-- Poems batch 41
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('d06ec3f5-8fe8-4089-a2ff-f361f14062ea','病中初聞復官二首 二','韓偓','唐','唐诗','tang','','[]','又挂朝衣一自驚，始知天意重推誠。',64,'全唐诗/poet.tang.37000.json','["又挂朝衣一自驚，始知天意重推誠。", "青雲有路通還去，白髮無私健亦生。", "曾避暖池將浴鳳，却同寒谷乍遷鶯。", "宦途巇嶮終難測，穩泊漁舟隱姓名。"]'),
('3bc28de6-3e5b-4059-a301-7e60b46c845f','早起五言三韻','韓偓','唐','唐诗','tang','','[]','萬樹綠楊垂，千般黃鳥語。',36,'全唐诗/poet.tang.37000.json','["萬樹綠楊垂，千般黃鳥語。", "庭花風雨餘，岑寂如村塢。", "依依官渡頭，晴陽照行旅。"]'),
('4b98edf8-48d2-482e-beef-c416b95cdd8e','家書後批二十八字','韓偓','唐','唐诗','tang','','[]','四序風光總是愁，鬢毛衰颯涕橫流。',32,'全唐诗/poet.tang.37000.json','["四序風光總是愁，鬢毛衰颯涕橫流。", "此書未到心先到，想在孤城海岸頭。"]'),
('db2b820b-c396-4ebb-b93f-489b28c58c26','湖南梅花一冬再發偶題於花援','韓偓','唐','唐诗','tang','','[]','湘浦梅花兩度開，直應天意別栽培。',64,'全唐诗/poet.tang.37000.json','["湘浦梅花兩度開，直應天意別栽培。", "玉爲通體依稀見，香號返魂容易迴。", "寒氣與君霜裏退，陽和爲爾臘前來。", "夭桃莫倚東風勢，調鼎何曾用不材。"]'),
('5ebac0b9-d39b-4d8c-a323-8e2b42cec505','即目二首 一','韓偓','唐','唐诗','tang','','[]','萬古離懷憎物色，幾生愁緒溺風光。',64,'全唐诗/poet.tang.37000.json','["萬古離懷憎物色，幾生愁緒溺風光。", "廢城沃土肥春草，野渡空船蕩夕陽。", "倚道向人多脈脈，爲情因酒易倀倀。", "宦途棄擲須甘分，迴避紅塵是所長。"]'),
('0f79b8b5-6f27-4542-98d7-89a2b4b10988','即目二首 二','韓偓','唐','唐诗','tang','','[]','動非求進靜非禪，咋舌吞聲過十年。',64,'全唐诗/poet.tang.37000.json','["動非求進靜非禪，咋舌吞聲過十年。", "溪漲浪花如積石，雨晴雲葉似連錢。", "干戈歲久諳戎事，枕簟秋涼減夜眠。", "攻苦慣來無不可，寸心如水但澄鮮。"]'),
('c67dd6f9-fb32-485c-8781-701254fc3631','淨興寺杜鵑一枝繁豔無比','韓偓','唐','唐诗','tang','','[]','一園紅豔醉坡陀，自地連梢簇蒨羅。',32,'全唐诗/poet.tang.37000.json','["一園紅豔醉坡陀，自地連梢簇蒨羅。", "蜀魄未歸長滴血，秪應偏滴此叢多。"]'),
('4e38a28c-13e1-4711-86f8-a3860c16e684','花時與錢尊師同醉因成二十字','韓偓','唐','唐诗','tang','','[]','橋下淺深水，竹間紅白花。',24,'全唐诗/poet.tang.37000.json','["橋下淺深水，竹間紅白花。", "酒仙同避世，何用厭長沙。"]'),
('1bf2b470-a30c-49a5-9d75-abf09cd3a42e','避地','韓偓','唐','唐诗','tang','','[]','西山爽氣生襟袖，南浦離愁入夢魂。',64,'全唐诗/poet.tang.37000.json','["西山爽氣生襟袖，南浦離愁入夢魂。", "人泊孤舟青草岸，鳥鳴高樹夕陽村。", "偷生亦似符天意，未死深疑負國恩。", "白面兒郎猶巧宦，不知誰與正乾坤。"]'),
('4f62bd66-5042-4571-9125-22da01330d31','息兵','韓偓','唐','唐诗','tang','','[]','漸覺人心望息兵，老儒希覬見澄清。',64,'全唐诗/poet.tang.37000.json','["漸覺人心望息兵，老儒希覬見澄清。", "正當困辱殊輕死，已過艱危却戀生。", "多難始應彰勁節，至公安肯爲虛名。", "暫時胯下何須恥，自有蒼蒼鑒赤誠。"]'),
('ddfbe663-408b-4b52-9daa-317560436361','翠碧鳥','韓偓','唐','唐诗','tang','','[]','天長水遠網羅稀，保得重重翠碧衣。',32,'全唐诗/poet.tang.37000.json','["天長水遠網羅稀，保得重重翠碧衣。", "挾彈小兒多害物，勸君莫近市朝飛。"]'),
('260aeaf1-d0e3-47f7-b449-cf1e5057e712','贈孫仁本尊師','韓偓','唐','唐诗','tang','','[]','齒如冰雪髮如黳，幾百年來醉似泥。',32,'全唐诗/poet.tang.37000.json','["齒如冰雪髮如黳，幾百年來醉似泥。", "不共世人爭得失，臥牀前有上天梯。"]'),
('584e5fa8-968e-457a-91e5-80241a8a3508','乙丑歲九月在蕭灘鎮駐泊兩月忽得商馬楊迢員外書賀余復除戎曹依舊承旨還緘後因書四十字','韓偓','唐','唐诗','tang','','[]','旅寓在江郊，秋風正寂寥。',48,'全唐诗/poet.tang.37000.json','["旅寓在江郊，秋風正寂寥。", "紫泥虛寵獎，白髮已漁樵。", "事往淒涼在，時危志氣銷。", "若爲將朽質，猶擬杖於朝。"]'),
('176971cd-5bec-4635-a60e-c892adfa164b','丙寅二月二十二日撫州如歸館雨中有懷諸朝客','韓偓','唐','唐诗','tang','','[]','悽悽惻惻又微嚬，欲話羇愁憶故人。',64,'全唐诗/poet.tang.38000.json','["悽悽惻惻又微嚬，欲話羇愁憶故人。", "薄酒旋醒寒徹夜，好花虛謝雨藏春。", "萍蓬已恨爲逋客，江嶺那知見侍臣。", "未必交情繫貧富，柴門自古少車塵。"]'),
('f18d3ce2-c550-4690-98d9-d784e805cd88','三月二十七日自撫州往南城縣舟行見拂水薔薇因有是作','韓偓','唐','唐诗','tang','','[]','江中春雨波浪肥，石上野花枝葉瘦。',64,'全唐诗/poet.tang.38000.json','["江中春雨波浪肥，石上野花枝葉瘦。", "枝低波高如有情，浪去枝留如力鬬。", "綠刺紅房戰褭時，吳娃越豔醺酣後。", "且將濁酒伴清吟，酒逸吟狂輕宇宙。"]'),
('f08d4d50-c82e-4dcc-a777-397ff768c1a2','茘枝三首 一','韓偓','唐','唐诗','tang','','[]','遐方不許貢珍奇，密詔唯教進茘枝。',32,'全唐诗/poet.tang.38000.json','["遐方不許貢珍奇，密詔唯教進茘枝。", "漢武碧桃爭比得，枉令方朔號偷兒。"]'),
('713f3f35-1318-4b7e-b18a-8c7b623f387b','茘枝三首 二','韓偓','唐','唐诗','tang','','[]','封開玉籠雞冠溼，葉襯金盤鶴頂鮮。',32,'全唐诗/poet.tang.38000.json','["封開玉籠雞冠溼，葉襯金盤鶴頂鮮。", "想得佳人微啓齒，翠釵先取一雙懸。"]'),
('346585f9-0ed0-4733-b088-471b183677df','茘枝三首 三','韓偓','唐','唐诗','tang','','[]','巧裁霞片裹神漿，崖蜜天然有異香。',32,'全唐诗/poet.tang.38000.json','["巧裁霞片裹神漿，崖蜜天然有異香。", "應是仙人金掌露，結成冰入蒨羅囊。"]'),
('4dabc174-0df3-4f81-9195-6e536e15ddac','寄上兄長','韓偓','唐','唐诗','tang','','[]','兩地支離路八千，襟懷悽愴鬢蒼然。',32,'全唐诗/poet.tang.38000.json','["兩地支離路八千，襟懷悽愴鬢蒼然。", "亂來未必長團會，其奈而今更長年。"]'),
('9abf25fa-e3e2-4cac-a45b-4c0277783815','寶劒','韓偓','唐','唐诗','tang','','[]','困極還應有甚通，難將糞壤掩神蹤。',32,'全唐诗/poet.tang.38000.json','["困極還應有甚通，難將糞壤掩神蹤。", "斗間紫氣分明後，擘地成川看化龍。"]'),
('082be90b-d771-420e-b6bf-dc07121e5bda','寶劒','韓偓','唐','唐诗','tang','','[]','困極還應有日通，難將糞土掩神蹤。',32,'全唐诗/poet.tang.38000.json','["困極還應有日通，難將糞土掩神蹤。", "但教出得豐城後，不是延津亦化龍。"]'),
('e576d21d-834d-40ad-aeb7-328d5c7a1f17','登南神光寺塔院','韓偓','唐','唐诗','tang','','[]','無奈離腸日九迴，強攄離抱立高臺。',64,'全唐诗/poet.tang.38000.json','["無奈離腸日九迴，強攄離抱立高臺。", "中華地向城邊盡，外國雲從島上來。", "四序有花長見雨，一冬無雪却聞雷。", "日宮紫氣生冠冕，試望扶桑病眼開。"]'),
('a0a417bb-5d92-4c7c-a830-554b1d8cb98d','兩賢','韓偓','唐','唐诗','tang','','[]','賣卜嚴將賣餅孫，兩賢高趣恐難倫。',32,'全唐诗/poet.tang.38000.json','["賣卜嚴將賣餅孫，兩賢高趣恐難倫。", "而今若有逃名者，應被品流呼差人。"]'),
('ad82e842-d1cc-443f-a4cf-6bcc7511f00d','再思','韓偓','唐','唐诗','tang','','[]','暴殄猶來是片時，無人向此略遲疑。',64,'全唐诗/poet.tang.38000.json','["暴殄猶來是片時，無人向此略遲疑。", "流金鑠石玉長潤，敗柳凋花松不知。", "但保行藏天是證，莫矜纖巧鬼難欺。", "近來更得窮經力，好事臨行亦再思。"]'),
('a80d1ec2-50b5-43b2-95fb-9d792053f79f','有矚','韓偓','唐','唐诗','tang','','[]','晚涼閑步向江亭，默默看書旋旋行。',64,'全唐诗/poet.tang.38000.json','["晚涼閑步向江亭，默默看書旋旋行。", "風轉滯帆狂得勢，潮來諸水寂無聲。", "誰將覆轍詢長策，願把棼絲屬老成。", "安石本懷經濟意，何妨一起爲蒼生。"]'),
('aba8f897-d6dc-4816-ba8f-4897726e4542','秋深閑興','韓偓','唐','唐诗','tang','','[]','此心兼笑野雲忙，甘得貧閑味甚長。',64,'全唐诗/poet.tang.38000.json','["此心兼笑野雲忙，甘得貧閑味甚長。", "病起乍嘗新橘柚，秋深初換舊衣裳。", "晴來喜鵲無窮語，雨後寒花特地香。", "把釣覆棊兼舉白，不離名教可顚狂。"]'),
('0ae7341e-7d0f-4c6c-9d98-bfe1b2445fe9','故都','韓偓','唐','唐诗','tang','','[]','故都遙想草萋萋，上帝深疑亦自迷。',64,'全唐诗/poet.tang.38000.json','["故都遙想草萋萋，上帝深疑亦自迷。", "塞雁已侵池籞宿，宮鴉猶戀女牆啼。", "天涯烈士空垂涕，地下強魂必噬臍。", "掩鼻計成終不覺，馮驩無路斅鳴雞。"]'),
('8e6fbc93-708e-4149-bd74-99bb56de6b5d','夢仙','韓偓','唐','唐诗','tang','','[]','紫霄宮闕五雲芝，九級壇前再拜時。',64,'全唐诗/poet.tang.38000.json','["紫霄宮闕五雲芝，九級壇前再拜時。", "鶴舞鹿眠春草遠，山高水闊夕陽遲。", "每嗟阮肇歸何速，深羨張騫去不疑。", "澡練純陽功力在，此心唯有玉皇知。"]'),
('7989cbbe-b32c-40ab-b648-da71f78730bd','贈吳顚尊師','韓偓','唐','唐诗','tang','','[]','飲酒經何代，休糧度此生。',168,'全唐诗/poet.tang.38000.json','["飲酒經何代，休糧度此生。", "跡應常自浼，顚亦強爲名。", "道若千釣重，身如一羽輕。", "毫釐分象緯，袒跣揖公卿。", "狗竇號光逸，漁陽裸禰衡。", "笑雷冬蟄震，巖電夜珠明。", "月魄侵簪冷，江光逼屐清。", "半酣思救世，一手擬扶傾。", "擊地嗟衰俗，看天貯不平。", "自緣懷氣義，可是計烹亨。", "議論通三教，年顏稱五更。", "老狂人不厭，密行鬼應驚。", "未識心相許，開襟語便誠。", "伊余常仗義，願拜十年兄。"]'),
('cd08aef7-5242-4d04-8bb9-09411a11a8d8','送人棄官入道','韓偓','唐','唐诗','tang','','[]','仙李濃陰潤，皇枝密葉敷。',120,'全唐诗/poet.tang.38000.json','["仙李濃陰潤，皇枝密葉敷。", "俊才輕折桂，捷徑取紆朱。", "斷紲三清路，揚鞭五達衢。", "側身期破的，縮手待呼盧。", "社稷俄如綴，雄豪詎守株。", "忸怩非壯志，擺脫是良圖。", "塵土留難住，纓緌棄若無。", "冥心歸大道，回首笑吾徒。", "酒律應難忘，詩魔未肯徂。", "他年如拔宅，爲我指清都。"]'),
('9f774d2c-5478-415d-9522-4ff467e5cd2d','感事三十四韻','韓偓','唐','唐诗','tang','','[]','紫殿承恩歲，金鑾入直年。',288,'全唐诗/poet.tang.38000.json','["紫殿承恩歲，金鑾入直年。", "人歸三島路，日過八花塼。", "鴛鷺皆迴席，臯夔亦慕羶。", "慶霄舒羽翼，塵世有神仙。", "雖遇河清聖，慙非岳降賢。", "皇慈容散拙，公議逼陶甄。", "江總參文會，陳暄侍狎筵。", "腐儒親帝座，太史認星躔。", "側弁聆神算，濡毫俟密宣。", "宮司持玉研，書省擘香箋。", "唯理心無黨，憐才膝屢前。", "焦勞皆實錄，宵旰豈虛傳。", "始議新堯曆，將期整舜弦。", "去梯言必盡，仄席意彌堅。", "上相思懲惡，中人詎省愆。", "鹿窮唯觝觸，兔急且㺦猭。", "本是謀賒死，因之致劫遷。", "氛霾言下合，日月暗中懸。", "恭顯誠甘罪，韋平亦恃權。", "畏聞巢幕險，寧寤積薪然。", "諒直尋鉗口，奸纖益比肩。", "晉讒終不解，魯瘠竟難痊。", "秪擬誅黃皓，何曾識霸先。", "嗾獒飜醜正，養虎欲求全。"]'),
('352da044-d964-434b-9a3d-778a9e3f558d','向隅','韓偓','唐','唐诗','tang','','[]','守道得途遲，中兼遇亂離。',48,'全唐诗/poet.tang.38000.json','["守道得途遲，中兼遇亂離。", "剛腸成繞指，玄髮轉垂絲。", "客路少安處，病牀無穩時。", "弟兄消息絕，獨斂向隅眉。"]'),
('10f9aacb-79cb-4cb9-b6d2-cc948daaf895','社後','韓偓','唐','唐诗','tang','','[]','社後重陽近，雲天澹薄間。',48,'全唐诗/poet.tang.38000.json','["社後重陽近，雲天澹薄間。", "目隨棊客靜，心共睡僧閑。", "歸鳥城銜日，殘虹雨在山。", "寂寥思晤語，何夕款柴關。"]'),
('6c4e7a6e-344c-44b8-a1fe-3fba8431b4ed','息慮','韓偓','唐','唐诗','tang','','[]','息慮狎羣鷗，行藏合自由。',48,'全唐诗/poet.tang.38000.json','["息慮狎羣鷗，行藏合自由。", "春寒宜酒病，夜雨入鄉愁。", "道向危時見，官因亂世休。", "外人相待淺，獨說濟川舟。"]'),
('4669f9a4-1be4-41f7-abd5-5d96705a5a27','早起探春','韓偓','唐','唐诗','tang','','[]','句芒一夜長精神，臘後風頭已見春。',64,'全唐诗/poet.tang.38000.json','["句芒一夜長精神，臘後風頭已見春。", "煙柳半眠藏利臉，雪梅含笑綻香脣。", "漸因閑暇思量酒，必怨顚狂泥摸人。", "若箇高情能似我，且應敧枕睡清晨。"]'),
('0f77d39d-9564-4c06-9f4c-b34263fd5680','味道','韓偓','唐','唐诗','tang','','[]','如含瓦礫竟何功，癡黠相兼似得中。',64,'全唐诗/poet.tang.38000.json','["如含瓦礫竟何功，癡黠相兼似得中。", "心繫是非徒悵望，事須光景旋虛空。", "升沈不定都如夢，毀譽無恆却要聾。", "弋者甚多應扼腕，任他閑處指冥鴻。"]'),
('53151f84-9412-4240-afa0-a669514c438a','秋郊閑望有感','韓偓','唐','唐诗','tang','','[]','楓葉微紅近有霜，碧雲秋色滿吳鄉。',64,'全唐诗/poet.tang.38000.json','["楓葉微紅近有霜，碧雲秋色滿吳鄉。", "魚衝駭浪雪鱗健，鴉閃夕陽金背光。", "心爲感恩長慘戚，鬢緣經亂早蒼浪。", "可憐廣武山前語，楚漢寧教作戰場。"]'),
('6b269705-816f-468e-a774-d3e589383568','李太舍池上玩紅薇醉題','韓偓','唐','唐诗','tang','','[]','花低池小水泙泙，花落池心片片輕。',64,'全唐诗/poet.tang.38000.json','["花低池小水泙泙，花落池心片片輕。", "酩酊不能羞白鬢，顚狂猶自睠紅英。", "乍爲旅客顏常厚，每見同人眼暫明。", "京洛園林歸未得，天涯相顧一含情。"]'),
('d8b2ea62-6639-49e6-a989-af906ace56ef','余寓汀州沙縣病中聞前鄭左丞璘隨外鎮舉薦赴洛兼云繼有急徵旋見脂轄因作七言四韻戲以贈之或冀其感悟也','韓偓','唐','唐诗','tang','','[]','莫恨當年入用遲，通材何處不逢知。',64,'全唐诗/poet.tang.38000.json','["莫恨當年入用遲，通材何處不逢知。", "桑田變後新舟檝，華表歸來舊路岐。", "公干寂寥甘坐廢，子牟歡抃促行期。", "移都已改侯王第，惆悵沙堤別築基。"]'),
('2623bbe7-d783-4230-a155-e3bf9aff9624','又一絕請爲申達京洛親交知余病廢','韓偓','唐','唐诗','tang','','[]','鬢惹新霜耳舊聾，眼昏腰曲四肢風。',32,'全唐诗/poet.tang.38000.json','["鬢惹新霜耳舊聾，眼昏腰曲四肢風。", "交親若要知形候，嵐嶂煙中折臂翁。"]'),
('77881f4e-00fa-4a3f-9074-4437679ac6db','夢中作','韓偓','唐','唐诗','tang','','[]','紫宸初啓列鴛鸞，直向龍墀對揖班。',64,'全唐诗/poet.tang.38000.json','["紫宸初啓列鴛鸞，直向龍墀對揖班。", "九曜再新環北極，萬方依舊祝南山。", "禮容肅睦纓緌外，和氣熏蒸劒履間。", "扇合却循黃道退，廟堂談笑百司閑。"]'),
('31a22c1d-950b-4b0b-9dd9-c4611c3ddf23','己巳年正月十二日自沙縣抵邵武軍將謀撫信之行到纔一夕爲閩相急脚相召却請赴沙縣郊外泊船偶成一篇','韓偓','唐','唐诗','tang','','[]','訪戴船迴郊外泊，故鄉何處望天涯。',48,'全唐诗/poet.tang.38000.json','["訪戴船迴郊外泊，故鄉何處望天涯。", "半明半暗山村日，自落自開江廟花。", "數醆綠醅桑落酒，一甌香沫火前茶。"]'),
('45079a57-8e31-4d91-aed1-f436dbeaf155','建谿灘波心目驚眩余平生溺奇境今則畏怯不暇因書二十八字','韓偓','唐','唐诗','tang','','[]','長貪山水羨漁樵，自笑揚鞭趁早朝。',32,'全唐诗/poet.tang.38000.json','["長貪山水羨漁樵，自笑揚鞭趁早朝。", "今日建谿驚恐後，李將軍畫也須燒。"]'),
('477dee88-46b6-46f9-b688-1da7cfdbde35','自沙縣抵龍溪縣值泉州軍過後村落皆空因有一絕','韓偓','唐','唐诗','tang','','[]','水自潺湲日自斜，盡無雞犬有鳴鴉。',32,'全唐诗/poet.tang.38000.json','["水自潺湲日自斜，盡無雞犬有鳴鴉。", "千村萬落如寒食，不見人煙空見花。"]'),
('cfe11ea1-7401-4c48-920e-36c990a4a383','此翁','韓偓','唐','唐诗','tang','','[]','高閣羣公莫忌儂，儂心不在宦名中。',64,'全唐诗/poet.tang.38000.json','["高閣羣公莫忌儂，儂心不在宦名中。", "嚴光一唾垂緌紫，何胤三遺大帶紅。", "金勁任從千口鑠，玉寒曾試幾爐烘。", "唯應鬼眼兼天眼，窺見行藏信此翁。"]'),
('93771ae9-e5b6-450b-9ff1-c16a90d175cb','失鶴','韓偓','唐','唐诗','tang','','[]','正憐標格出華亭，況是昂藏入相經。',64,'全唐诗/poet.tang.38000.json','["正憐標格出華亭，況是昂藏入相經。", "碧落順風初得志，故巢因雨却聞腥。", "幾時翔集來華表，每日沈吟看畫屏。", "爲報雞羣虛嫉妒，紅塵向上有青冥。"]'),
('8372f298-08f3-439b-9760-9f96dcae1aa0','卜隱','韓偓','唐','唐诗','tang','','[]','屏跡還應減是非，却憂藍玉又光輝。',64,'全唐诗/poet.tang.38000.json','["屏跡還應減是非，却憂藍玉又光輝。", "桑梢出舍蠶初老，柳絮蓋溪魚正肥。", "世亂豈容長愜意，景清還覺易忘機。", "世間華美無心問，藜藿充腸苧作衣。"]'),
('e68050c4-6a0c-49d0-8577-775ef25dd530','晨興','韓偓','唐','唐诗','tang','','[]','曉景山河爽，閑居巷陌清。',48,'全唐诗/poet.tang.38000.json','["曉景山河爽，閑居巷陌清。", "已能消滯念，兼得散餘酲。", "汲水人初起，迴燈燕暫驚。", "放懷殊未足，圓隙已塵生。"]'),
('ea5f3ed1-afa4-4d40-b4b8-216bafecc273','暴雨','韓偓','唐','唐诗','tang','','[]','電尾燒黑雲，雨脚飛銀線。',72,'全唐诗/poet.tang.38000.json','["電尾燒黑雲，雨脚飛銀線。", "急點濺池心，微煙昏水面。", "氣涼氛祲消，暑退松篁健。", "叢蓼亞赬茸，擎荷飜綠扇。", "風期誰與同，逸趣余探徧。", "欲去更遲留，胸中久交戰。"]'),
('615974f2-27b6-4e9a-a6ca-aa9d4dbbdbe2','山院避暑','韓偓','唐','唐诗','tang','','[]','行樂江郊外，追涼山寺中。',48,'全唐诗/poet.tang.38000.json','["行樂江郊外，追涼山寺中。", "靜陰生晚綠，寂慮延清風。", "運塞地維窄，氣蘇天宇空。", "何人識幽抱，目送冥冥鴻。"]'),
('edbb8e1b-c090-4d31-b417-25c9c9b83b24','閑興','韓偓','唐','唐诗','tang','','[]','景寂有玄味，韻高無俗情。',48,'全唐诗/poet.tang.38000.json','["景寂有玄味，韻高無俗情。", "他山冰雪解，此水波瀾生。", "影重驗花密，滴稀知酒清。", "忙人常擾擾，安得心和平。"]'),
('f46cba01-1204-4942-bdbf-8e2ff3760b03','漫作二首 一','韓偓','唐','唐诗','tang','','[]','暑雨灑和氣，香風吹日華。',48,'全唐诗/poet.tang.38000.json','["暑雨灑和氣，香風吹日華。", "瞬龍驚汗漫，翥鳳綷雲霞。", "懸圃珠爲樹，天池玉作砂。", "丹霄能幾級，何必待乘槎。"]'),
('dd798cf6-95ca-4be9-bdf1-216a4118e282','漫作二首 二','韓偓','唐','唐诗','tang','','[]','黍谷純陽入，鸞霄瑞彩生。',48,'全唐诗/poet.tang.38000.json','["黍谷純陽入，鸞霄瑞彩生。", "岳靈分正氣，仙衛借神兵。", "汚俗迎風變，虛懷遇物傾。", "千鈞將一羽，輕重在平衡。"]'),
('fe20ba41-3a18-45b7-95cb-3052c834b58c','騰騰','韓偓','唐','唐诗','tang','','[]','八年流落醉騰騰，點檢行藏喜不勝。',32,'全唐诗/poet.tang.38000.json','["八年流落醉騰騰，點檢行藏喜不勝。", "烏帽素餐兼施藥，前生多恐是醫僧。"]'),
('28494d7f-d062-4034-a506-0182cfd2d5f6','寄隱者','韓偓','唐','唐诗','tang','','[]','煙郭雲扃路不遙，懷賢猶恨太迢迢。',64,'全唐诗/poet.tang.38000.json','["煙郭雲扃路不遙，懷賢猶恨太迢迢。", "長松夜落釵千股，小港春添水半腰。", "已約病身拋印綬，不嫌門巷似漁樵。", "渭濱晦跡南陽臥，若比吾徒更寂寥。"]'),
('88e4fb5d-b969-4d62-b688-273e8db5b02d','閑居','韓偓','唐','唐诗','tang','','[]','厭聞趨競喜閑居，自種蕪菁亦自鋤。',64,'全唐诗/poet.tang.38000.json','["厭聞趨競喜閑居，自種蕪菁亦自鋤。", "麋鹿跳梁憂觸撥，鷹鸇搏擊恐麤疎。", "拙謀却爲多循理，所短深慙盡信書。", "刀尺不虧繩墨在，莫疑張翰戀鱸魚。"]'),
('4a426f3e-4f0c-4a36-a9ae-5cdbd8460286','僧影','韓偓','唐','唐诗','tang','','[]','山色依然僧已亡，竹間疎磬隔殘陽。',32,'全唐诗/poet.tang.38000.json','["山色依然僧已亡，竹間疎磬隔殘陽。", "智燈已滅餘空燼，猶自光明照十方。"]'),
('27803088-2a65-4ea7-9880-1d30c7ad2376','洞庭玩月','韓偓','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','洞庭湖上清秋月，月皎湖寬萬頃霜。',64,'全唐诗/poet.tang.38000.json','["洞庭湖上清秋月，月皎湖寬萬頃霜。", "玉椀深沈潭底白，金杯細碎浪頭光。", "寒驚烏鵲離巢噪，冷射蛟螭換窟藏。", "更憶瑤臺逢此夜，水晶宮殿挹瓊漿。"]'),
('f520fa35-0fd4-4a7b-ac61-aa94d5258fff','贈隱逸','韓偓','唐','唐诗','tang','','[]','靜景須教靜者尋，清狂何必在山陰。',64,'全唐诗/poet.tang.38000.json','["靜景須教靜者尋，清狂何必在山陰。", "蠭穿窗紙塵侵硯，鳥鬬庭花露滴琴。", "莫笑亂離方解印，猶勝顚蹶未抽簪。", "築金總得非名士，況是無人解築金。"]'),
('df6091c7-bfb2-4b21-bdd4-63d2c89bfe9f','南浦','韓偓','唐','唐诗','tang','','[]','月若半環雲若吐，高樓簾卷當南浦。',64,'全唐诗/poet.tang.38000.json','["月若半環雲若吐，高樓簾卷當南浦。", "應是石城艇子來，兩槳咿啞過花塢。", "正值連宵酒未醒，不宜此際兼微雨。", "直教筆底有文星，亦應難狀分明苦。"]'),
('b5c29b9b-2650-424f-be87-8b16dde36402','桃林場客舍之前有池半畝木槿櫛比閼水遮山因命僕夫運斤梳沐豁然清朗復覩太虛因作五言八韻','韓偓','唐','唐诗','tang','','[]','插槿作藩籬，叢生覆小池。',96,'全唐诗/poet.tang.38000.json','["插槿作藩籬，叢生覆小池。", "爲能妨遠目，因遣去閑枝。", "鄰叟偷來賞，棲禽欲下疑。", "虛空無障處，蒙閉有開時。", "葦鷺憐瀟灑，泥鰌畏日曦。", "稍寬春水面，盡見晚山眉。", "岸穩人偷釣，階明日上基。", "世間多弊事，事事要良醫。"]'),
('ee823576-5f33-4657-99f7-aea841e6e9c0','中秋寄楊學士','韓偓','唐','唐诗','tang','','[]','鱗差甲子漸衰遲，依舊年年困亂離。',32,'全唐诗/poet.tang.38000.json','["鱗差甲子漸衰遲，依舊年年困亂離。", "八月夜長鄉思切，鬢邊添得幾莖絲。"]'),
('fe85566d-acb2-4842-aeee-b1bee0e3d9e7','寄禪師','韓偓','唐','唐诗','tang','','[]','他心明與此心同，妙用忘言理暗通。',64,'全唐诗/poet.tang.38000.json','["他心明與此心同，妙用忘言理暗通。", "氣運陰陽成世界，水浮天地寄虛空。", "劫灰聚散銖錙黑，日御奔馳繭栗紅。", "萬物盡遭風鼓動，唯應禪室靜無風。"]'),
('6bebb844-7943-4531-a036-ad0c4b42d80d','清興','韓偓','唐','唐诗','tang','','[]','陰沈天氣連翩醉，摘索花枝料峭寒。',32,'全唐诗/poet.tang.38000.json','["陰沈天氣連翩醉，摘索花枝料峭寒。", "擁鼻繞廊吟看雨，不知遺却竹皮冠。"]'),
('aa6664b9-a90f-4406-9844-d4ab2b5a2b50','深院','韓偓','唐','唐诗','tang','','["\u548f\u7269\u8bd7", "\u5199\u666f", "\u548f\u7269"]','鵝兒唼啑梔黃觜，鳳子輕盈膩粉腰。',32,'全唐诗/poet.tang.38000.json','["鵝兒唼啑梔黃觜，鳳子輕盈膩粉腰。", "深院下簾人晝寢，紅薔薇架碧芭蕉。"]'),
('2bcbad58-8242-4895-be39-c58363d3426f','淒淒','韓偓','唐','唐诗','tang','','[]','深將寵辱齊，往往亦淒淒。',48,'全唐诗/poet.tang.38000.json','["深將寵辱齊，往往亦淒淒。", "白日知丹抱，青雲有舊蹊。", "嗜鹹凌魯濟，惡潔助涇泥。", "風雨今如晦，堪憐報曉雞。"]'),
('c236f109-5298-40ab-88da-011e534e3ee8','火蛾','韓偓','唐','唐诗','tang','','[]','陽光不照臨，積陰生此類。',48,'全唐诗/poet.tang.38000.json','["陽光不照臨，積陰生此類。", "非無惜死心，奈有滅明意。", "妝穿粉燄焦，翅撲蘭膏沸。", "爲爾一傷嗟，自棄非天棄。"]'),
('e168bdbb-7eb4-423e-ace3-49f7e61e57ac','信筆','韓偓','唐','唐诗','tang','','[]','春風狂似虎，春浪白於鵝。',48,'全唐诗/poet.tang.38000.json','["春風狂似虎，春浪白於鵝。", "柳密藏煙易，松長見日多。", "石崖采芝叟，鄉俗摘茶歌。", "道在無伊鬱，天將奈爾何。"]'),
('2466fb5b-bbaa-4e0d-bc00-f24a733562d3','雷公','韓偓','唐','唐诗','tang','','[]','閑人倚柱笑雷公，又向深山霹怪松。',32,'全唐诗/poet.tang.38000.json','["閑人倚柱笑雷公，又向深山霹怪松。", "必若有蘇天下意，何如驚起武侯龍。"]'),
('b84680ee-aee3-43ed-b120-68c3e6c71f91','船頭','韓偓','唐','唐诗','tang','','[]','兩岸綠蕪齊似翦，掩映雲山相向晚。',32,'全唐诗/poet.tang.38000.json','["兩岸綠蕪齊似翦，掩映雲山相向晚。", "船頭獨立望長空，日豔波光逼人眼。"]'),
('aef986d5-c829-4159-b811-d39ad0293858','喜涼','韓偓','唐','唐诗','tang','','[]','爐炭燒人百疾生，鳳狂龍躁減心情。',96,'全唐诗/poet.tang.38000.json','["爐炭燒人百疾生，鳳狂龍躁減心情。", "四山毒瘴乾坤濁，一簟涼風世界清。", "楚調忽驚淒玉柱，漢宮應已溼金莖。", "豪強頓息蛙脣吻，爽利重新鶻眼睛。", "穩想海槎朝犯斗，健思胡馬夜飜營。", "東南亦是中華分，蒸鬱相凌太不平。"]'),
('944d6c59-2ef8-4e05-b5f2-75b254bedff3','天鑒','韓偓','唐','唐诗','tang','','[]','何勞諂笑學趨時，務實清修勝用機。',64,'全唐诗/poet.tang.38000.json','["何勞諂笑學趨時，務實清修勝用機。", "猛虎十年搖尾立，蒼鷹一旦醒心飛。", "神依正道終潛衛，天鑒衷腸競不違。", "事歷艱難人始重，九層成後喜從微。"]'),
('4f4209b1-1864-4eae-99e6-55535141af7f','江岸閑步','韓偓','唐','唐诗','tang','','[]','一手攜書一杖筇，出門何處覓情通。',64,'全唐诗/poet.tang.38000.json','["一手攜書一杖筇，出門何處覓情通。", "立談禪客傳心印，坐睡漁師著背蓬。", "青布旗誇千日酒，白頭浪吼半江風。", "淮陰市裏人相見，盡道途窮未必窮。"]'),
('5930890b-7bcc-4e26-9216-62ac131bfdc3','野塘','韓偓','唐','唐诗','tang','','[]','侵曉乘涼偶獨來，不因魚躍見萍開。',32,'全唐诗/poet.tang.38000.json','["侵曉乘涼偶獨來，不因魚躍見萍開。", "卷荷忽被微風觸，瀉下清香露一杯。"]'),
('0fbe361c-0ea8-4564-80cc-aabf45d61fd5','余臥疾深村聞一二郎官今稱繼使閩越笑余迂古潛於異鄉聞之因成此篇','韓偓','唐','唐诗','tang','','[]','枕流方采北山薇，驛騎交迎市道兒。',64,'全唐诗/poet.tang.38000.json','["枕流方采北山薇，驛騎交迎市道兒。", "霧豹秪憂無石室，泥鰌唯要有洿池。", "不羞莽卓黃金印，却笑羲皇白接䍦。", "莫負美名書信史，清風埽地更無遺。"]'),
('14241332-5e0b-43d4-aac4-722924a897a1','安貧','韓偓','唐','唐诗','tang','','[]','手風慵展一行書，眼暗休尋九局圖。',64,'全唐诗/poet.tang.38000.json','["手風慵展一行書，眼暗休尋九局圖。", "窗裏日光飛野馬，案頭筠管長蒲廬。", "謀身拙爲安蛇足，報國危曾捋虎鬚。", "舉世可能無默識，未知誰擬試齊竽。"]'),
('b2d92dcc-a89a-4aeb-a60b-53949dd41eba','殘春旅舍','韓偓','唐','唐诗','tang','','["\u7231\u56fd", "\u957f\u5b89", "\u56de\u5fc6"]','旅舍殘春宿雨晴，恍然心地憶咸京。',64,'全唐诗/poet.tang.38000.json','["旅舍殘春宿雨晴，恍然心地憶咸京。", "樹頭蠭抱花鬚落，池面魚吹柳絮行。", "禪伏詩魔歸淨域，酒衝愁陣出奇兵。", "兩梁免被塵埃汚，拂拭朝簪待眼明。"]'),
('b29e2ffa-aa3f-41d0-8524-c235bc8fa56e','鵲','韓偓','唐','唐诗','tang','','[]','偏承雨露潤毛衣，黑白分明衆所知。',64,'全唐诗/poet.tang.38000.json','["偏承雨露潤毛衣，黑白分明衆所知。", "高處營巢親鳳闕，靜時閑語上龍墀。", "化爲金印新祥瑞，飛向銀河舊路岐。", "莫怪天涯棲不穩，託身須是萬年枝。"]'),
('7c84bcaa-f6d3-4607-b30b-3ef971feed6d','露','韓偓','唐','唐诗','tang','','[]','鶴非千歲飲猶難，鶯舌偷含豈自安。',64,'全唐诗/poet.tang.38000.json','["鶴非千歲飲猶難，鶯舌偷含豈自安。", "光溼最宜叢菊亞，蕩搖無奈綠荷乾。", "名因霈澤隨天睠，分與濃霜保歲寒。", "五色呈祥須得處，戛雲仙掌有金盤。"]'),
('bc43af5d-96db-4b0d-a309-dbd3f33ef970','贈僧','韓偓','唐','唐诗','tang','','[]','盡說歸山避戰塵，幾人終肯別囂氛。',64,'全唐诗/poet.tang.38000.json','["盡說歸山避戰塵，幾人終肯別囂氛。", "瓶添澗水盛將月，衲挂松枝惹得雲。", "三接舊承前席遇，一靈今用戒香熏。", "相逢莫話金鑾事，觸撥傷心不願聞。"]'),
('08ddae55-30cb-4033-8e9a-f37ceb5622dd','感舊','韓偓','唐','唐诗','tang','','[]','省趨弘閣待貂璫，指座深恩刻寸腸。',66,'全唐诗/poet.tang.38000.json','["省趨弘閣待貂璫，指座深恩刻寸腸。", "秦苑已荒空逝水，楚天無[限]更斜陽。", "時昏却笑朱弦直，事過方聞鎖骨香。", "入室故寮流落盡，路人惆悵見靈光。"]'),
('9665eaff-fd9a-4ab3-9df1-9268c00496c7','八月六日作四首 一','韓偓','唐','唐诗','tang','','[]','日離黃道十年昏，敏手重開造化門。',64,'全唐诗/poet.tang.38000.json','["日離黃道十年昏，敏手重開造化門。", "火帝動爐銷劒戟，風師吹雨洗乾坤。", "左牽犬馬誠難測，右袒簪纓最負恩。", "丹筆不知誰定罪，莫留遺跡怨神孫。"]'),
('e092b3ab-9c5f-455c-9040-0827fd236710','八月六日作四首 二','韓偓','唐','唐诗','tang','','[]','金虎挻災不復論，搆成狂猘犯車塵。',64,'全唐诗/poet.tang.38000.json','["金虎挻災不復論，搆成狂猘犯車塵。", "御衣空惜侍中血，國璽幾危皇后身。", "圖霸未能知盜道，飾非唯欲害仁人。", "黃旗紫氣今仍舊，免使老臣攀畫輪。"]'),
('6572231d-88eb-4839-9b65-d5225c277eb6','八月六日作四首 三','韓偓','唐','唐诗','tang','','[]','簪裾皆是漢公卿，盡作鋒鋩劒血醒。',64,'全唐诗/poet.tang.38000.json','["簪裾皆是漢公卿，盡作鋒鋩劒血醒。", "顯負舊恩歸亂主，難教新國用輕刑。", "穴中狡兔終須盡，井上嬰兒豈自寧。", "底事亦疑懲未了，更應書罪在泉扃。"]'),
('1c5f7b80-8443-4ee4-b41b-bac3a8a28c87','八月六日作四首 四','韓偓','唐','唐诗','tang','','[]','坐看包藏負國恩，無才不得預經綸。',64,'全唐诗/poet.tang.38000.json','["坐看包藏負國恩，無才不得預經綸。", "袁安墜睫尋憂漢，賈誼濡毫但過秦。", "威鳳鬼應遮矢射，靈犀天與隔埃塵。", "隄防瓜李能終始，免媿於心負此身。"]'),
('c3f362f5-bd40-4e71-87d3-2b19e638706d','驛步','韓偓','唐','唐诗','tang','','[]','暫息征車病眼開，況穿松竹入樓臺。',64,'全唐诗/poet.tang.38000.json','["暫息征車病眼開，況穿松竹入樓臺。", "江流燈影向東去，樹遞雨聲從北來。", "物近劉輿招垢膩，風經庾亮汚塵埃。", "高情自古多惆悵，賴有南華養不材。"]'),
('d8e27f72-e002-4b98-823d-43112d852046','訪隱者遇沈醉書其門而歸','韓偓','唐','唐诗','tang','','[]','曉入江村覓釣翁，釣翁沈醉酒缸空。',32,'全唐诗/poet.tang.38000.json','["曉入江村覓釣翁，釣翁沈醉酒缸空。", "夜來風起閑花落，狼藉柴門鳥徑中。"]'),
('1e2fd705-2cf2-403d-b686-972fd9ef7eff','疎雨','韓偓','唐','唐诗','tang','','[]','疎雨從東送疾雷，小庭涼氣淨莓苔。',64,'全唐诗/poet.tang.38000.json','["疎雨從東送疾雷，小庭涼氣淨莓苔。", "卷簾燕子穿人去，洗硯魚兒觸手來。", "但欲進賢求上賞，唯將拯溺作良媒。", "戎衣一挂清天下，傅野非無濟世才。"]'),
('e12b461b-6344-46ea-b3a5-9b27fd7ce8be','南安寓止','韓偓','唐','唐诗','tang','','[]','此地三年偶寄家，枳籬茅廠共桑麻。',64,'全唐诗/poet.tang.38000.json','["此地三年偶寄家，枳籬茅廠共桑麻。", "蝶矜翅暖徐窺草，蠭倚身輕凝看花。", "天近函關屯瑞氣，水侵吳甸浸晴霞。", "豈知卜肆嚴夫子，潛指星機認海槎。"]'),
('d80df0ff-95cb-4794-9d66-b1db8effa5e9','十月七日早起作時氣疾初愈','韓偓','唐','唐诗','tang','','[]','疾愈身輕覺數通，山無嵐瘴海無風。',32,'全唐诗/poet.tang.38000.json','["疾愈身輕覺數通，山無嵐瘴海無風。", "陽精欲出陰精落，天地包含紫氣中。"]'),
('18a199a7-91b3-4dc4-a215-d7c26126f043','有感','韓偓','唐','唐诗','tang','','[]','堅辭羽葆與吹鐃，飜向天涯困繫匏。',64,'全唐诗/poet.tang.38000.json','["堅辭羽葆與吹鐃，飜向天涯困繫匏。", "故老未曾忘炙背，何人終擬問苞茅。", "融風漸暖將迴雁，滫水猶腥近斬蛟。", "萬里關山如咫尺，女牀唯待鳳歸巢。"]'),
('c539bbf5-d804-43b7-a3e7-76cabc504914','觀鬬雞偶作','韓偓','唐','唐诗','tang','','[]','何曾解報稻粱恩，金距花冠氣遏雲。',32,'全唐诗/poet.tang.38000.json','["何曾解報稻粱恩，金距花冠氣遏雲。", "白日梟鳴無意問，唯將芥羽害同羣。"]'),
('e2de8d1d-89ea-4d3e-bd38-6fadd29a0ec7','蜻蜓','韓偓','唐','唐诗','tang','','[]','碧玉眼睛雲母翅，輕於粉蝶瘦於蠭。',32,'全唐诗/poet.tang.38000.json','["碧玉眼睛雲母翅，輕於粉蝶瘦於蠭。", "坐來迎拂波光久，豈是殷勤爲蓼叢。"]'),
('9ef6dd4c-945b-4b71-9a6f-59b71aa5def3','即目','韓偓','唐','唐诗','tang','','[]','書牆暗記移花日，洗甕先知醞酒期。',32,'全唐诗/poet.tang.38000.json','["書牆暗記移花日，洗甕先知醞酒期。", "須信閑人有忙事，早來衝雨覓漁師。"]'),
('0ab90d8b-3022-4df6-a828-606b1db22cef','寄鄰莊道侶','韓偓','唐','唐诗','tang','','[]','聞說經旬不啓關，藥窗誰伴醉開顏。',32,'全唐诗/poet.tang.38000.json','["聞說經旬不啓關，藥窗誰伴醉開顏。", "夜來雪壓村前竹，賸見溪南幾尺山。"]'),
('a20e04bc-aecb-4f81-be02-4bfbaff64fc4','初赴期集','韓偓','唐','唐诗','tang','','[]','輕寒著背雨淒淒，九陌無塵未有泥。',32,'全唐诗/poet.tang.38000.json','["輕寒著背雨淒淒，九陌無塵未有泥。", "還是平時舊滋味，慢垂鞭袖過街西。"]'),
('60a89be4-fba8-42f7-998b-a89a348f442c','惜花','韓偓','唐','唐诗','tang','','[]','皺白離情高處切，膩香愁態靜中深。',64,'全唐诗/poet.tang.38000.json','["皺白離情高處切，膩香愁態靜中深。", "眼隨片片沿流去，恨滿枝枝被雨淋。", "總得苔遮猶慰意，若教泥汚更傷心。", "臨軒一醆悲春酒，明日池塘是綠陰。"]'),
('48b58c0b-224d-49a5-9dc8-4490dc8fcbcb','半醉','韓偓','唐','唐诗','tang','','[]','水向東流竟不迴，紅顏白髮遞相催。',64,'全唐诗/poet.tang.38000.json','["水向東流竟不迴，紅顏白髮遞相催。", "壯心暗逐高歌盡，往事空因半醉來。", "雲護雁霜籠澹月，雨連鶯曉落殘梅。", "西樓悵望芳菲節，處處斜陽草似苔。"]'),
('7b4a18e5-e406-4855-a0c0-c180c8f4e69f','春盡','韓偓','唐','唐诗','tang','','[]','惜春連日醉昏昏，醒後衣裳見酒痕。',64,'全唐诗/poet.tang.38000.json','["惜春連日醉昏昏，醒後衣裳見酒痕。", "細水浮花歸別澗，斷雲含雨入孤村。", "人閑易有芳時恨，地勝難招自古魂。", "慙媿流鶯相厚意，清晨猶爲到西園。"]'),
('eb5f3dc9-ee39-46b9-90de-423164914b30','睡起','韓偓','唐','唐诗','tang','','[]','睡起牆陰下藥闌，瓦松花白閉柴關。',64,'全唐诗/poet.tang.38000.json','["睡起牆陰下藥闌，瓦松花白閉柴關。", "斷年不出僧嫌癖，逐日無機鶴伴閑。", "塵土莫尋行止處，煙波長在夢魂間。", "終撐舴艋稱漁叟，賒買湖心一崦山。"]'),
('a9525c7f-4b83-4b6b-b21b-b667b76aec86','寄友人','韓偓','唐','唐诗','tang','','[]','傷時惜別心交加，搘頤一向千咨嗟。',64,'全唐诗/poet.tang.38000.json','["傷時惜別心交加，搘頤一向千咨嗟。", "曠野風吹寒食月，廣庭煙著黃昏花。", "長擬醺酣遺世事，若爲局促問生涯。", "夫君亦是多情者，幾處將愁殢酒家。"]'),
('22e8cc7d-77bc-4b71-bea9-bb57c174a982','見別離者因贈之','韓偓','唐','唐诗','tang','','[]','征人草草盡戎裝，征馬蕭蕭立路傍。',64,'全唐诗/poet.tang.38000.json','["征人草草盡戎裝，征馬蕭蕭立路傍。", "尊酒闌珊將遠別，秋山迤邐更斜陽。", "白髭兄弟中年後，瘴海程途萬里長。", "曾向天涯懷此恨，見君嗚咽更淒涼。"]'),
('514c0d63-4676-45c3-9827-d57ffe01f3ef','傷亂','韓偓','唐','唐诗','tang','','[]','岸上花根總倒垂，水中花影幾千枝。',64,'全唐诗/poet.tang.38000.json','["岸上花根總倒垂，水中花影幾千枝。", "一枝一影寒山裏，野水野花清露時。", "故國幾年猶戰鬬，異鄉終日見旌旗。", "交親流落身羸病，誰在誰亡兩不知。"]'),
('246eaaa9-538f-476a-8681-d970eea0798c','南亭','韓偓','唐','唐诗','tang','','[]','每日在南亭，南亭似僧院。',72,'全唐诗/poet.tang.38000.json','["每日在南亭，南亭似僧院。", "人語靜先聞，鳥啼深不見。", "松瘦石稜稜，山光溪澱澱。", "塹蔓墜長茸，島花垂小蒨。", "行簪隱士冠，臥讀先賢傳。", "更有興來時，取琴彈一徧。"]'),
('edc2f675-9de4-41ce-8aa7-d76cbf78e85c','太平谷中玩水上花','韓偓','唐','唐诗','tang','','[]','山頭水從雲外落，水面花自山中來。',64,'全唐诗/poet.tang.38000.json','["山頭水從雲外落，水面花自山中來。", "一溪紅點我獨惜，幾樹蜜房誰見開。", "應有妖魂隨暮雨，豈無香跡在蒼苔。", "凝眸不覺斜陽盡，忘逐樵人躡石回。"]'),
('129534f5-d6db-4d09-be4c-bb409b96dec1','雨','韓偓','唐','唐诗','tang','','[]','坐來簌簌山風急，山雨隨風暗原隰。',64,'全唐诗/poet.tang.38000.json','["坐來簌簌山風急，山雨隨風暗原隰。", "樹帶繁聲出竹聞，溪將大點穿籬入。", "餉婦寥翹布領寒，牧童擁腫蓑衣溼。", "此時高味共誰論，擁鼻吟詩空佇立。"]'),
('c1e7ee44-f029-45c1-b1da-3483701c3994','幽獨','韓偓','唐','唐诗','tang','','[]','幽獨起侵晨，山鶯啼更早。',48,'全唐诗/poet.tang.38000.json','["幽獨起侵晨，山鶯啼更早。", "門巷掩蕭條，落花滿芳草。", "煙和魂共遠，春與人同老。", "默默又依依，淒然此懷抱。"]'),
('b3fa69f4-c337-48a4-b216-e906f33b99ed','江行','韓偓','唐','唐诗','tang','','[]','浪蹙青山江北岸，雲含黑雨日西邊。',48,'全唐诗/poet.tang.38000.json','["浪蹙青山江北岸，雲含黑雨日西邊。", "舟人偶語憂風色，行客無聊罷晝眠。", "爭似槐花九衢裏，馬蹄安穩慢垂鞭。"]'),
('ce2667fd-1055-4575-bc3c-a6f8c1f098d6','漢江行次','韓偓','唐','唐诗','tang','','[]','村寺雖深已暗知，幡竿殘日迥依依。',64,'全唐诗/poet.tang.38000.json','["村寺雖深已暗知，幡竿殘日迥依依。", "沙頭有廟青林合，驛步無人白鳥飛。", "牧笛自由隨草遠，漁歌得意扣舷歸。", "竹園相接春波暖，痛憶家鄉舊釣磯。"]'),
('479dc55f-e5c9-49fb-9966-2a90ab8d8574','偶題','韓偓','唐','唐诗','tang','','[]','俟時輕進固相妨，實行丹心仗彼蒼。',32,'全唐诗/poet.tang.38000.json','["俟時輕進固相妨，實行丹心仗彼蒼。", "蕭艾轉肥蘭蕙瘦，可能天亦妬馨香。"]'),
('9e7a30bf-9fd6-4a88-aa59-e05170fe09e6','湖南絕少含桃偶有人以新摘者見惠感事傷懷因成四韻','韓偓','唐','唐诗','tang','','[]','時節雖同氣候殊，不知堪薦寢園無。',64,'全唐诗/poet.tang.38000.json','["時節雖同氣候殊，不知堪薦寢園無。", "合充鳳食留三島，誰許鶯偷過五湖。", "苦筍恐難同象匕，酪漿無復瑩蠙珠。", "金鑾歲歲長宣賜，忍淚看天憶帝都。"]'),
('088f1c54-e5d0-4956-9c05-f9b5720c7e43','隰州新驛','韓偓','唐','唐诗','tang','','[]','盛德已圖形，胡爲忽搆兵。',96,'全唐诗/poet.tang.38000.json','["盛德已圖形，胡爲忽搆兵。", "燎原雖自及，誅亂不無名。", "擲鼠須防誤，連雞莫憚驚。", "本期將係虜，末策但嬰城。", "肘腋人情變，朝廷物論生。", "果聞荒谷縊，旋覩藁街烹。", "帝怒今方息，時危喜暫清。", "始終俱以此，天意甚分明。"]'),
('86aec3f1-ade0-4b82-8897-a8a95f154abe','亂後春日途經野塘','韓偓','唐','唐诗','tang','','[]','世亂他鄉見落梅，野塘晴暖獨裴回。',64,'全唐诗/poet.tang.38000.json','["世亂他鄉見落梅，野塘晴暖獨裴回。", "船衝水鳥飛還住，袖拂楊花去却來。", "季重舊遊多喪逝，子山新賦極悲哀。", "眼看朝市成陵谷，始信昆明是劫灰。"]'),
('1ca7cb47-958e-4335-be8b-e6595fbf1ecd','贈易卜崔江處士','韓偓','唐','唐诗','tang','','[]','白首窮經通祕義，青山養老度危時。',64,'全唐诗/poet.tang.38000.json','["白首窮經通祕義，青山養老度危時。", "門傳組綬身能退，家學漁樵跡更奇。", "四海盡聞龜策妙，九霄堪歎鶴書遲。", "壺中日月將何用，借與閑人試一窺。"]'),
('06b81855-29db-4824-a249-fc894f44b443','過臨淮故里','韓偓','唐','唐诗','tang','','[]','交遊昔歲已凋零，第宅今來亦變更。',64,'全唐诗/poet.tang.38000.json','["交遊昔歲已凋零，第宅今來亦變更。", "舊廟荒涼時饗絕，諸孫飢凍一官成。", "五湖竟負他年志，百戰空垂異代名。", "榮盛幾何流落久，遣人襟抱薄浮生。"]'),
('8085273c-5ae5-4a78-9271-b7510d82a188','贈湖南李思齊處士','韓偓','唐','唐诗','tang','','[]','兩板船頭濁酒壺，七絲琴畔白髭鬚。',64,'全唐诗/poet.tang.38000.json','["兩板船頭濁酒壺，七絲琴畔白髭鬚。", "三春日日黃梅雨，孤客年年青草湖。", "燕俠冰霜難狎近，楚狂鋒刃觸凡愚。", "知余絕粒窺仙事，許到名山看藥鑪。"]'),
('2cff3a83-5bb0-4ea3-9af3-ff0d6e5b4960','亂後却至近甸有感','韓偓','唐','唐诗','tang','','[]','狂童容易犯金門，比屋齊人作旅魂。',64,'全唐诗/poet.tang.38000.json','["狂童容易犯金門，比屋齊人作旅魂。", "夜戶不扃生茂草，春渠自溢浸荒園。", "關中忽見屯邊卒，塞外飜聞有漢村。", "堪恨無情清渭水，渺茫依舊繞秦原。"]'),
('faa7317d-d867-44b7-9a5e-6348bec254fa','同年前虞部李郎中自長沙赴行在余以紫石硯贈之賦詩代書','韓偓','唐','唐诗','tang','','[]','斧柯新樣勝珠璣，堪贊星郎染翰時。',64,'全唐诗/poet.tang.38000.json','["斧柯新樣勝珠璣，堪贊星郎染翰時。", "不向東垣修直疏，即須西掖草妍詞。", "紫光稱近丹青筆，聲韻宜裁錦繡詩。", "蓬島侍臣今放逐，羨君迴去逼龍墀。"]'),
('043e5d61-b57f-4e03-801f-8f7cfd7e2d2d','甲子歲夏五月自長沙抵醴陵貴就深僻以便疎慵由道林之南步步勝絕去綠口分東入南小江山水益秀村籬之次忽見紫薇花因思玉堂及西掖廳前皆植是花遂賦詩四韻聊寄知心','韓偓','唐','唐诗','tang','','[]','職在內庭宮闕下，廳前皆種紫薇花。',64,'全唐诗/poet.tang.38000.json','["職在內庭宮闕下，廳前皆種紫薇花。", "眼明忽傍漁家見，魂斷方驚魏闕賒。", "淺色暈成宮裏錦，濃香染著洞中霞。", "此行若遇支機石，又被君平驗海槎。"]'),
('d2ee7153-04ce-43f0-9078-47fa99358049','和王舍人撫州飲席贈韋司空','韓偓','唐','唐诗','tang','','[]','樓臺掩映入春寒，絲竹錚鏦向夜闌。',64,'全唐诗/poet.tang.38000.json','["樓臺掩映入春寒，絲竹錚鏦向夜闌。", "席上弟兄皆杞梓，花前賓客盡鴛鸞。", "孫弘莫惜頻開閤，韓信終期別築壇。", "削玉風姿官水土，黑頭公自古來難。"]'),
('118df6cd-cbc0-459f-b155-e7b2c98ed451','避地寒食','韓偓','唐','唐诗','tang','','[]','避地淹留已自悲，況逢寒食欲霑衣。',64,'全唐诗/poet.tang.38000.json','["避地淹留已自悲，況逢寒食欲霑衣。", "濃春孤館人愁坐，斜日空園花亂飛。", "路遠漸憂知己少，時危又與賞心違。", "一名所繫無窮事，爭敢當年便息機。"]'),
('cf42591e-6945-4ed6-a7c2-c98f90c248e8','山驛','韓偓','唐','唐诗','tang','','[]','參差西北數行雁，寥落東方幾片雲。',64,'全唐诗/poet.tang.38000.json','["參差西北數行雁，寥落東方幾片雲。", "疊石小松張水部，暗山寒雨李將軍。", "秋花粉黛宜無味，獨鳥笙簧稱靜聞。", "瀟灑襟懷遺世慮，驛樓紅葉自紛紛。"]'),
('568001ac-a5d5-44ef-9eaa-62a8e7a76b40','早發藍關','韓偓','唐','唐诗','tang','','[]','關門愁立候雞鳴，搜景馳魂入杳冥。',64,'全唐诗/poet.tang.38000.json','["關門愁立候雞鳴，搜景馳魂入杳冥。", "雲外日隨千里雁，山根霜共一潭星。", "路盤暫見樵人火，棧轉時聞驛使鈴。", "自問辛勤緣底事，半年驅馬傍長亭。"]'),
('8c1ae28a-a279-4207-8c5b-d5dcd5e51fd2','深村','韓偓','唐','唐诗','tang','','[]','甘向深村固不材，猶勝摧折傍塵埃。',64,'全唐诗/poet.tang.38000.json','["甘向深村固不材，猶勝摧折傍塵埃。", "清宵翫月唯紅葉，永日關門但綠苔。", "幽院菊荒同寂寞，野橋僧去獨裴回。", "隔籬農叟遙相賀，□□□□膏雨來。"]'),
('4d4ca5c0-aad6-4c92-bf9e-fbda6813f57d','重遊曲江','韓偓','唐','唐诗','tang','','[]','追尋前事立江汀，漁者應聞太息聲。',64,'全唐诗/poet.tang.38000.json','["追尋前事立江汀，漁者應聞太息聲。", "避客野鷗如有感，損花微雪似無情。", "疎林自覺長堤在，春水空連古岸平。", "惆悵引人還到夜，鞭鞘風冷柳煙輕。"]'),
('511fd322-e75b-452e-a4a8-17b833aa932b','三月','韓偓','唐','唐诗','tang','','[]','辛夷纔謝小桃發，蹋青過後寒食前。',64,'全唐诗/poet.tang.38000.json','["辛夷纔謝小桃發，蹋青過後寒食前。", "四時最好是三月，一去不迴唯少年。", "吳國地遙江接海，漢陵魂斷草連天。", "新愁舊恨真無奈，須就鄰家甕底眠。"]'),
('e68c54db-98e7-4696-a8c5-d39ca0c75904','秋村','韓偓','唐','唐诗','tang','','[]','稻壟蓼紅溝水清，荻園葉白秋日明。',64,'全唐诗/poet.tang.38000.json','["稻壟蓼紅溝水清，荻園葉白秋日明。", "空坡路細見騎過，遠田人靜聞水行。", "柴門狼藉牛羊氣，竹塢幽深雞犬聲。", "絕粒看經香一炷，心知無事即長生。"]'),
('f984fbe1-6bab-4cb7-b9c6-801f9dac6b24','殘花','韓偓','唐','唐诗','tang','','[]','餘霞殘雪幾多在，蔫香冶態猶無窮。',64,'全唐诗/poet.tang.38000.json','["餘霞殘雪幾多在，蔫香冶態猶無窮。", "黃昏月下惆悵白，清明雨後寥𤞚紅。", "樹底草齊千片淨，牆頭風急數枝空。", "西園此日傷心處，一曲高歌水向東。"]'),
('95eed0ec-1579-4c8c-8f16-925e130f6345','夜船','韓偓','唐','唐诗','tang','','[]','野雲低迷煙蒼蒼，平波揮目如凝霜。',64,'全唐诗/poet.tang.38000.json','["野雲低迷煙蒼蒼，平波揮目如凝霜。", "月明船上簾幕卷，露重岸頭花木香。", "村遠夜深無火燭，江寒坐久換衣裳。", "誠知不覺天將曙，幾簇青山雁一行。"]'),
('8fd5f89d-4394-4f52-aadc-6a20825c83ae','傷春','韓偓','唐','唐诗','tang','','[]','三月光景不忍看，五陵春色何摧殘。',64,'全唐诗/poet.tang.38000.json','["三月光景不忍看，五陵春色何摧殘。", "窮途得志反惆悵，飲席話舊多闌珊。", "中酒向陽成美睡，惜花衝雨覺傷寒。", "野棠飛盡蒲根暖，寂寞南溪倚釣竿。"]'),
('626f2e03-f11a-46b0-8c68-4c7dac25c7c4','歸紫閣下','韓偓','唐','唐诗','tang','','[]','一笈攜歸紫閣峰，馬蹄閑慢水溶溶。',67,'全唐诗/poet.tang.38000.json','["一笈攜歸紫閣峰，馬蹄閑慢水溶溶。", "黃昏後見山田火，朧{月悤}時聞縣郭鐘。", "瘦竹迸生僧坐石，野藤纏殺鶴翹松。", "釣磯自別經秋雨，長得莓苔更幾重。"]'),
('94204506-4c6e-4cc8-8f8f-1ea3f34902d1','夜坐','韓偓','唐','唐诗','tang','','[]','天似空江星似波，時時珠露滴圓荷。',64,'全唐诗/poet.tang.38000.json','["天似空江星似波，時時珠露滴圓荷。", "平生蹤跡慕真隱，此夕襟懷深自多。", "格是厭厭饒酒病，終須的的學漁歌。", "無名無位堪休去，猶擬朝衣換釣蓑。"]'),
('611f950a-0743-40bb-a620-f5b11bbb5735','午寢夢江外兄弟','韓偓','唐','唐诗','tang','','[]','長夏居閑門不開，繞門青草絕塵埃。',64,'全唐诗/poet.tang.38000.json','["長夏居閑門不開，繞門青草絕塵埃。", "空庭日午獨眠覺，旅夢天涯相見迴。", "鬢向此時應有雪，心從別處即成灰。", "如何水陸三千里，幾月書郵始一來。"]'),
('66372a6c-64ab-418a-a9f7-040b6f53f3bb','曲江夜思','韓偓','唐','唐诗','tang','','[]','鼓聲將絕月斜痕，園外閑坊半掩門。',64,'全唐诗/poet.tang.38000.json','["鼓聲將絕月斜痕，園外閑坊半掩門。", "池裏紅蓮凝白露，苑中青草伴黃昏。", "林塘闃寂偏宜夜，煙火稀疎便似村。", "大抵世間幽獨景，最關詩思與離魂。"]'),
('f5c6cadd-7683-455a-bccd-8a64807ac9d4','過漢口','韓偓','唐','唐诗','tang','','[]','濁世清名一概休，古今飜覆賸堪愁。',64,'全唐诗/poet.tang.38000.json','["濁世清名一概休，古今飜覆賸堪愁。", "年年春浪來巫峽，日日殘陽過沔州。", "居雜商徒偏富庶，地多詞客自風流。", "聯翩半世騰騰過，不在漁船即酒樓。"]'),
('8827a8a3-2164-47cd-8c47-211345dd707b','惜春','韓偓','唐','唐诗','tang','','[]','願言未偶非高臥，多病無憀選勝遊。',64,'全唐诗/poet.tang.38000.json','["願言未偶非高臥，多病無憀選勝遊。", "一夜雨聲三月盡，萬般人事五更頭。", "年踰弱冠即爲老，節過清明却似秋。", "應是西園花已落，滿溪紅片向東流。"]'),
('47a9ffc7-61fe-4dab-b5ef-6c92119b9a18','及第過堂日作','韓偓','唐','唐诗','tang','','[]','早隨真侶集蓬瀛，閶闔門開尚見星。',64,'全唐诗/poet.tang.38000.json','["早隨真侶集蓬瀛，閶闔門開尚見星。", "龍尾樓臺迎曉日，鼇頭宮殿入青冥。", "暗驚凡骨升仙籍，忽訝麻衣謁相庭。", "百辟斂容開路看，片時輝赫勝圖形。"]'),
('3ceaeb8c-4bcd-4d8c-a49a-01e1efdd3ec6','夏課成感懷','韓偓','唐','唐诗','tang','','[]','別離終日心忉忉，五湖煙波歸夢勞。',64,'全唐诗/poet.tang.38000.json','["別離終日心忉忉，五湖煙波歸夢勞。", "淒涼身事夏課畢，濩落生涯秋風高。", "居世無媒多困躓，昔賢因此亦號咷。", "誰憐愁苦多衰改，未到潘年有二毛。"]'),
('2da7b2be-0ad0-4344-8c95-65bb529ae7e5','離家第二日却寄諸兄弟','韓偓','唐','唐诗','tang','','[]','睡起褰簾日出時，今辰初恨間容輝。',64,'全唐诗/poet.tang.38000.json','["睡起褰簾日出時，今辰初恨間容輝。", "千行淚激傍人感，一點心隨健步歸。", "却望山川空黯黯，迴看僮僕亦依依。", "定知兄弟高樓上，遙指征途羨鳥飛。"]'),
('a07628a0-7d96-4f37-9b7f-6e0f81056f8f','遊江南水陸院','韓偓','唐','唐诗','tang','','[]','早於喧雜是深讎，猶恐行藏墜俗流。',64,'全唐诗/poet.tang.38000.json','["早於喧雜是深讎，猶恐行藏墜俗流。", "高寺嬾爲攜酒去，名山長恨送人遊。", "關河見月空垂淚，風雨看花欲白頭。", "除却祖師心法外，浮生何處不堪愁。"]'),
('b429a614-b5cb-44ca-89f2-d253f196bd00','江南送別','韓偓','唐','唐诗','tang','','[]','江南行止忽相逢，江館棠棃葉正紅。',64,'全唐诗/poet.tang.38000.json','["江南行止忽相逢，江館棠棃葉正紅。", "一笑共嗟成往事，半酣相顧似衰翁。", "關山月皎清風起，送別人歸野渡空。", "大抵多情應易老，不堪岐路數西東。"]'),
('64884e6b-1886-4394-9869-95cc8a7d9c6c','格卑','韓偓','唐','唐诗','tang','','[]','格卑嘗恨足牽仍，欲學忘情似不能。',64,'全唐诗/poet.tang.38000.json','["格卑嘗恨足牽仍，欲學忘情似不能。", "入意雲山輸畫匠，動人風月羨琴僧。", "南朝峻潔推弘景，東晉清狂數季鷹。", "惆悵後塵流落盡，自拋懷抱醉懵騰。"]'),
('9d6aaf6c-ce45-4ecf-9c2d-3a5c438979ee','冬日','韓偓','唐','唐诗','tang','','[]','蕭條古木銜斜日，戚瀝晴寒滯早梅。',64,'全唐诗/poet.tang.38000.json','["蕭條古木銜斜日，戚瀝晴寒滯早梅。", "愁處雪煙連野起，靜時風竹過牆來。", "故人每憶心先見，新酒偷嘗手自開。", "景狀入詩兼入畫，言情不盡恨無才。"]'),
('88e5d589-8f23-4c1e-b053-8f3ae70745e8','再止廟居','韓偓','唐','唐诗','tang','','[]','去值秋風來值春，前時今日共銷魂。',64,'全唐诗/poet.tang.38000.json','["去值秋風來值春，前時今日共銷魂。", "頹坦古柏疑山關，高柳鳴鴉似水村。", "菜甲未齊初出葉，樹陰方合掩重門。", "幽深凍餒皆推分，靜者還應爲討論。"]'),
('0aceab09-f9a5-41f7-bfb0-0d727392d6c1','老將','韓偓','唐','唐诗','tang','','[]','折槍黃馬倦塵埃，掩耳凶徒怕疾雷。',64,'全唐诗/poet.tang.38000.json','["折槍黃馬倦塵埃，掩耳凶徒怕疾雷。", "雪密酒酣偷號去，月明衣冷斫營回。", "行驅貔虎披金甲，立聽笙歌擲玉杯。", "坐久不須輕矍鑠，至今雙擘硬弓開。"]'),
('943034f5-322e-496f-8839-4cf8d435348d','邊上看獵贈元戎','韓偓','唐','唐诗','tang','','[]','繡簾臨曉覺新霜，便遣移廚較獵場。',96,'全唐诗/poet.tang.38000.json','["繡簾臨曉覺新霜，便遣移廚較獵場。", "燕卒鐵衣圍漢相，魯儒戎服從梁王。", "搜山閃閃旗頭遠，出樹斑斑豹尾長。", "贊獲一聲連朔漠，賀杯環騎舞優倡。", "軍迴野靜秋天白，角怨城遙晚照黃。", "紅袖擁門持燭炬，解勞今夜宴華堂。"]'),
('3029a767-6580-4537-84b9-f9bcb65fafa3','余自刑部員外郎爲權所擠值盤石出鎮藩屏朝選賓佐以余充職掌記鬱鬱不樂因成長句寄所知','韓偓','唐','唐诗','tang','','[]','正叨清級忽從戎，況與燕臺事不同。',48,'全唐诗/poet.tang.38000.json','["正叨清級忽從戎，況與燕臺事不同。", "開口謾勞矜道在，撫膺唯合哭途窮。", "操心未省趨浮俗，點額尤慙自至公。"]'),
('4a50c02d-d4a4-421f-bae1-19505d448482','北齊二首 一','韓偓','唐','唐诗','tang','','[]','任道驕奢必敗亡，且將繁盛悅嬪嬙。',64,'全唐诗/poet.tang.38000.json','["任道驕奢必敗亡，且將繁盛悅嬪嬙。", "幾千籢鏡成樓柱，六十間雲號殿廊。", "後主獵迴初按樂，胡姬酒醒更新妝。", "綺羅堆裏春風畔，年少多情一帝王。"]'),
('ce88cb23-d73d-429b-b8fc-59955666596f','北齊二首 二','韓偓','唐','唐诗','tang','','[]','神器傳時異至公，敗亡安可怨悤悤。',64,'全唐诗/poet.tang.38000.json','["神器傳時異至公，敗亡安可怨悤悤。", "犯寒獵士朝頻戮，告急軍書夜不通。", "幷部義旗遮日暗，鄴城飛燄照天紅。", "周朝將相還無體，寧死何須入鐵籠。"]'),
('2221d898-d539-4a0f-839b-eb96aa5946b0','寄京城親友二首 一','韓偓','唐','唐诗','tang','','[]','苦吟看墜葉，寥落共天涯。',48,'全唐诗/poet.tang.38000.json','["苦吟看墜葉，寥落共天涯。", "壯歲空爲客，初寒更憶家。", "雨牆經月蘚，山菊向陽花。", "因味碧雲句，傷哉後會賒。"]'),
('7011a550-3042-435b-95f5-9870f142907c','寄京城親友二首 二','韓偓','唐','唐诗','tang','','[]','相思凡幾日，日欲詠離衿。',48,'全唐诗/poet.tang.38000.json','["相思凡幾日，日欲詠離衿。", "直得吟成病，終難狀此心。", "解衣悲緩帶，搔首悶遺簪。", "西嶺斜陽外，潛疑是故林。"]'),
('a085662a-fc0c-4923-9bf1-96dac2648e26','野寺','韓偓','唐','唐诗','tang','','[]','野寺看紅葉，縣城聞擣衣。',48,'全唐诗/poet.tang.38000.json','["野寺看紅葉，縣城聞擣衣。", "自憐癡病苦，猶共賞心違。", "高閣正臨夜，前山應落暉。", "離情在煙鳥，遙入故關飛。"]'),
('266820f7-248a-4bf5-b601-8d54165d5ef2','吳郡懷古','韓偓','唐','唐诗','tang','','[]','主暗臣忠枉就刑，遂教強國醉中傾。',64,'全唐诗/poet.tang.38000.json','["主暗臣忠枉就刑，遂教強國醉中傾。", "人亡建業空城在，花落西江春水平。", "萬古壯夫猶抱恨，至今詞客盡傷情。", "徒勞鐵鎖長千尺，不覺樓船下晉兵。"]'),
('9de0b12c-2cab-403b-9242-4ae9a79fae11','守愚','韓偓','唐','唐诗','tang','','[]','深院寥寥竹蔭廊，披衣欹枕過年芳。',64,'全唐诗/poet.tang.38000.json','["深院寥寥竹蔭廊，披衣欹枕過年芳。", "守愚不覺世途險，無事始知春日長。", "一畝落花圍隙地，半竿濃日界空牆。", "今來自責趨時嬾，飜恨松軒書滿牀。"]'),
('936d2ab6-9f39-48f8-8993-27faba27d037','村居','韓偓','唐','唐诗','tang','','[]','二月三月雨晴初，舍南舍北唯平蕪。',64,'全唐诗/poet.tang.38000.json','["二月三月雨晴初，舍南舍北唯平蕪。", "前懽入望盈千恨，勝景牽心非一途。", "日照神堂聞啄木，風含社樹叫提壺。", "行看旦夕棃霜發，猶有山寒傷酒壚。"]'),
('c925083f-e765-45b4-a395-ae31d5f5be88','離家','韓偓','唐','唐诗','tang','','[]','八月初長夜，千山第一程。',48,'全唐诗/poet.tang.38000.json','["八月初長夜，千山第一程。", "款顏唯有夢，怨泣却無聲。", "祖席諸賓散，空郊匹馬行。", "自憐非達識，局促爲浮名。"]'),
('3bd063b7-6d59-4aba-8b68-06ea57031935','秋雨內宴','韓偓','唐','唐诗','tang','','[]','一帶清風入畫堂，撼真珠箔碎玎璫。',32,'全唐诗/poet.tang.38000.json','["一帶清風入畫堂，撼真珠箔碎玎璫。", "更看檻外霏霏雨，似勸須教醉玉觴。"]'),
('5fc6879b-525f-45df-8790-4075dbe27ab2','寒食日沙縣雨中看薔薇','韓偓','唐','唐诗','tang','','[]','何處遇薔薇，殊鄉冷節時。',72,'全唐诗/poet.tang.38000.json','["何處遇薔薇，殊鄉冷節時。", "雨聲籠錦帳，風勢偃羅幃。", "通體全無力，酡顏不自持。", "綠疎微露刺，紅密欲藏枝。", "愜意凭闌久，貪吟放醆遲。", "旁人應見訝，自醉自題詩。"]'),
('361e7cd1-0717-4284-b0ba-21e027f2a97e','地爐','韓偓','唐','唐诗','tang','','[]','兩星殘火地爐畔，夢斷背燈重擁衾。',64,'全唐诗/poet.tang.38000.json','["兩星殘火地爐畔，夢斷背燈重擁衾。", "側聽空堂聞靜響，似敲疎磬褭清音。", "風燈有影隨籠轉，臘雪無聲逐夜深。", "禪客釣翁徒自好，那知此際湛然心。"]'),
('c7054287-c59b-484e-8fe5-3d6196d52b57','隰州新驛贈刺史','韓偓','唐','唐诗','tang','','[]','賢侯新換古長亭，先定心機指顧成。',64,'全唐诗/poet.tang.38000.json','["賢侯新換古長亭，先定心機指顧成。", "高義盡招秦逐客，曠懷偏接魯諸生。", "萍蓬到此銷離恨，燕雀飛來帶喜聲。", "却笑昔賢交易極，一開東閤便垂名。"]'),
('e2068b0e-af40-46d6-9c30-7371f4ba32ab','草書屏風','韓偓','唐','唐诗','tang','','[]','何處一屏風，分明懷素蹤。',48,'全唐诗/poet.tang.38000.json','["何處一屏風，分明懷素蹤。", "雖多塵色染，猶見墨痕濃。", "怪石奔秋澗，寒藤挂古松。", "若教臨水畔，字字恐成龍。"]'),
('bdd9c9cf-31b1-4a97-9fce-525d3b7a643c','永明禪師房','韓偓','唐','唐诗','tang','','[]','景色方妍媚，尋真出近郊。',48,'全唐诗/poet.tang.38000.json','["景色方妍媚，尋真出近郊。", "寶香爐上爇，金磬佛前敲。", "蔓草稜山徑，晴雲拂樹梢。", "支公禪寂處，時有鶴來巢。"]'),
('f696b6ad-5546-4b3e-9f4e-128669e5e5d8','登樓有題','韓偓','唐','唐诗','tang','','[]','暑氣檐前過，蟬聲樹杪交。',48,'全唐诗/poet.tang.38000.json','["暑氣檐前過，蟬聲樹杪交。", "待潮生浦口，看雨過山坳。", "才見蘭舟動，仍聞桂檝敲。", "窣雲朱檻好，終覩鳳來巢。"]'),
('0532fb36-14b8-485d-b1d7-28e610073650','朝退書懷','韓偓','唐','唐诗','tang','','[]','鶴帔星冠羽客裝，寢樓西畔坐書堂。',64,'全唐诗/poet.tang.38000.json','["鶴帔星冠羽客裝，寢樓西畔坐書堂。", "山禽養久知人喚，窗竹芟多漏月光。", "粉壁不題新拙惡，小屏唯錄古篇章。", "孜孜莫患勞心力，富國安民理道長。"]'),
('1994c0bf-2857-436e-9013-3cbd7b15b39c','元夜即席','韓偓','唐','唐诗','tang','','[]','元宵清景亞元正，絲雨霏霏向晚傾。',64,'全唐诗/poet.tang.38000.json','["元宵清景亞元正，絲雨霏霏向晚傾。", "桂兔韜光雲葉重，燭龍銜耀月輪明。", "煙空但仰如膏潤，綺席都忘滴砌聲。", "更待今宵開霽後，九衢車馬未妨行。"]'),
('5d344565-86ef-4819-bbb2-8b851597bd70','大慶堂賜宴元璫而有詩呈吳越王','韓偓','唐','唐诗','tang','','[]','非爲親賢展綺筵，恆常寧敢恣遊盤。',64,'全唐诗/poet.tang.38000.json','["非爲親賢展綺筵，恆常寧敢恣遊盤。", "綠搓楊柳緜初輭，紅暈櫻桃粉未乾。", "谷鳥乍啼聲似澀，甘霖方霽景猶寒。", "笙歌風緊人酣醉，却繞珍叢爛熳看。"]'),
('c825b83c-8680-48bc-9180-94208572aeb8','又和大慶堂賜宴元璫而有詩呈吳越王','韓偓','唐','唐诗','tang','','[]','櫻桃花下會親賢，風遠銅烏轉露盤。',64,'全唐诗/poet.tang.38000.json','["櫻桃花下會親賢，風遠銅烏轉露盤。", "蝶下粉牆梅乍坼，蟻浮金斝酒難乾。", "雲和緩奏泉聲咽，珠箔低垂水影寒。", "狂簡斐然吟詠足，却邀羣彥重吟看。"]'),
('42e18cf9-2f1a-4600-b502-67fe4aa53f55','再和大慶堂賜宴元璫而有詩呈吳越王','韓偓','唐','唐诗','tang','','[]','我有嘉賓宴乍歡，畫簾紋細鳳雙盤。',64,'全唐诗/poet.tang.38000.json','["我有嘉賓宴乍歡，畫簾紋細鳳雙盤。", "影籠沼沚修篁密，聲透笙歌羯鼓乾。", "散後便依書篋寐，渴來潛想玉壺寒。", "櫻桃零落紅桃媚，更俟旬餘共醉看。"]'),
('ea410d34-6364-406b-b508-f100622440fa','重和大慶堂賜宴元璫而有詩呈吳越王','韓偓','唐','唐诗','tang','','[]','冷宴殷勤展小園，舞鞇柔輭綵虯盤。',64,'全唐诗/poet.tang.38000.json','["冷宴殷勤展小園，舞鞇柔輭綵虯盤。", "篸花盡日疑頭重，病酒經宵覺口乾。", "嘉樹倚樓青瑣暗，晚雲藏雨碧山寒。", "文章天子文章別，八米盧郎未可看。"]'),
('e0b46888-2a9d-494b-8063-283b6e18bdef','余作探使以繚綾手帛子寄賀因而有詩','韓偓','唐','唐诗','tang','','[]','解寄繚綾小字封，探花筵上映春叢。',64,'全唐诗/poet.tang.38000.json','["解寄繚綾小字封，探花筵上映春叢。", "黛眉印在微微綠，檀口消來薄薄紅。", "緶處直應心共緊，砑時兼恐汗先融。", "帝臺春盡還東去，却繫帬腰伴雪胷。"]'),
('26a81572-7480-4250-9b49-3a4d89133fa9','別錦兒','韓偓','唐','唐诗','tang','','[]','一尺紅綃一首詩，贈君相別兩相思。',64,'全唐诗/poet.tang.38000.json','["一尺紅綃一首詩，贈君相別兩相思。", "畫眉今日空留語，解佩他年更可期。", "臨去莫論交頸意，清歌休著斷腸詞。", "出門何事休惆悵，曾夢良人折桂枝。"]'),
('021d9666-1711-4b18-970b-4ed31eb2b178','閑步','韓偓','唐','唐诗','tang','','[]','莊南縱步遊荒野，獨鳥寒煙輕惹惹。',64,'全唐诗/poet.tang.38000.json','["莊南縱步遊荒野，獨鳥寒煙輕惹惹。", "傍山疎雨溼秋花，僻路淺泉浮敗果。", "樵人相見指驚麏，牧童四散收嘶馬。", "一壺傾盡未能歸，黃昏更望諸峰火。"]'),
('7b5c4cc2-f903-46d8-be20-5eb2b098d68b','乾寧三年丙辰在奉天重圍作','韓偓','唐','唐诗','tang','','[]','仗劒夜巡城，衣襟滿霜霰。',48,'全唐诗/poet.tang.38000.json','["仗劒夜巡城，衣襟滿霜霰。", "賊火徧郊坰，飛燄侵星漢。", "積雪似空江，長林如斷岸。", "獨凭女牆頭，思家起長歎。"]'),
('dde60786-075b-4447-ae3a-2c398241e9bf','雨中','韓偓','唐','唐诗','tang','','[]','青桐承雨聲，聲聲何重疊。',48,'全唐诗/poet.tang.38000.json','["青桐承雨聲，聲聲何重疊。", "疎滴下高枝，次打敧低葉。", "鳥溼更梳翎，人愁方拄頰。", "獨自上西樓，風襟寒帖帖。"]'),
('577e12b2-9f7e-4815-8bb6-e91a02690d57','與僧','韓偓','唐','唐诗','tang','','[]','江海扁舟客，雲山一衲僧。',24,'全唐诗/poet.tang.38000.json','["江海扁舟客，雲山一衲僧。", "相逢兩無語，若箇是南能。"]'),
('c9ab5b79-1b3d-405e-a261-71de1236f091','晚岸','韓偓','唐','唐诗','tang','','[]','揭起青𦪪上岸頭，野花和雨冷脩脩。',32,'全唐诗/poet.tang.38000.json','["揭起青𦪪上岸頭，野花和雨冷脩脩。", "春江一夜無波浪，校得行人分外愁。"]'),
('557c3fa3-04ee-46d0-92af-e059d3d0427d','仙山','韓偓','唐','唐诗','tang','','[]','一炷心香洞府開，偃松皺澀半莓苔。',32,'全唐诗/poet.tang.38000.json','["一炷心香洞府開，偃松皺澀半莓苔。", "水清無底山如削，始有仙人騎鶴來。"]'),
('5eae55d1-8f2b-498e-8b32-8282f487e976','過茂陵','韓偓','唐','唐诗','tang','','[]','不悲霜露但傷春，孝理何因感兆民。',32,'全唐诗/poet.tang.38000.json','["不悲霜露但傷春，孝理何因感兆民。", "景帝龍髯消息斷，異香空見李夫人。"]'),
('eb694f00-4f8e-47fc-82f0-16d9726ef918','曲江秋日','韓偓','唐','唐诗','tang','','[]','斜煙縷縷鷺鷥棲，藕葉枯香折野泥。',32,'全唐诗/poet.tang.38000.json','["斜煙縷縷鷺鷥棲，藕葉枯香折野泥。", "有箇高僧入圖畫，把經吟立水塘西。"]'),
('e5035184-1a66-4c43-b1b4-737110270921','流年','韓偓','唐','唐诗','tang','','[]','三月傷心仍晦日，一春多病更陰天。',32,'全唐诗/poet.tang.38000.json','["三月傷心仍晦日，一春多病更陰天。", "雄豪亦有流年恨，況是離魂易黯然。"]'),
('df9936ec-3cf6-4f5a-892f-4e4292df4612','商山道中','韓偓','唐','唐诗','tang','','[]','雲橫峭壁水平鋪，渡口人家日欲晡。',32,'全唐诗/poet.tang.38000.json','["雲橫峭壁水平鋪，渡口人家日欲晡。", "却憶往年看粉本，始知名畫有工夫。"]'),
('b6de5623-7f11-4b4c-8643-e5b0bfc9cffe','招隱','韓偓','唐','唐诗','tang','','[]','立意忘機機已生，可能朝市汙高情。',32,'全唐诗/poet.tang.38000.json','["立意忘機機已生，可能朝市汙高情。", "時人未會嚴陵志，不釣鱸魚只釣名。"]'),
('85b808ec-f148-4031-872a-71d89d0b03cd','雨村','韓偓','唐','唐诗','tang','','[]','雁行斜拂雨村樓，簾下三重幕一鉤。',32,'全唐诗/poet.tang.38000.json','["雁行斜拂雨村樓，簾下三重幕一鉤。", "倚柱不知身半溼，黃昏獨自未迴頭。"]'),
('0500d26b-4376-45a9-a8f1-148edec200df','使風','韓偓','唐','唐诗','tang','','[]','茶煙睡覺心無事，一卷黃庭在手中。',32,'全唐诗/poet.tang.38000.json','["茶煙睡覺心無事，一卷黃庭在手中。", "敧枕卷簾江萬里，舟人不語滿帆風。"]'),
('e2f72fc7-f762-4e24-a1de-301239569d50','阻風','韓偓','唐','唐诗','tang','','[]','平生情趣羨漁師，此日煙江愜所思。',32,'全唐诗/poet.tang.38000.json','["平生情趣羨漁師，此日煙江愜所思。", "肥鱖香秔小艛艓，斷腸滋味阻風時。"]'),
('b823e0cf-13d4-49c6-9553-2b8459d168a6','幷州','韓偓','唐','唐诗','tang','','[]','戍旗青草接榆關，雨裏幷州四月寒。',32,'全唐诗/poet.tang.38000.json','["戍旗青草接榆關，雨裏幷州四月寒。", "誰會凭闌潛忍淚，不勝天際似江干。"]'),
('fb9caef8-ee28-4d7b-92ab-53d7371aff26','夏夜','韓偓','唐','唐诗','tang','','[]','猛風飄電黑雲生，霎霎高林簇雨聲。',32,'全唐诗/poet.tang.38000.json','["猛風飄電黑雲生，霎霎高林簇雨聲。", "夜久雨休風又定，斷雲流月却斜明。"]'),
('cd976142-6f60-418b-b9c0-fe1fbc3bfdad','闌干','韓偓','唐','唐诗','tang','','[]','埽花雖恨夜來雨，把酒却憐晴後寒。',32,'全唐诗/poet.tang.38000.json','["埽花雖恨夜來雨，把酒却憐晴後寒。", "吳質謾言愁得病，當時猶不凭闌干。"]'),
('6ae4c769-82dd-48a8-a391-48a4c4804b75','以庭前海棠棃花一枝寄李十九員外','韓偓','唐','唐诗','tang','','[]','二月春風澹蕩時，旅人虛對海棠棃。',32,'全唐诗/poet.tang.38000.json','["二月春風澹蕩時，旅人虛對海棠棃。", "不如寄與星郎去，想得朝回正畫眉。"]'),
('c1383e53-6ff9-4ada-ac7b-98098025637d','驛樓','韓偓','唐','唐诗','tang','','[]','流雲溶溶水悠悠，故鄉千里空迴頭。',32,'全唐诗/poet.tang.38000.json','["流雲溶溶水悠悠，故鄉千里空迴頭。", "三更猶凭闌干月，淚滿關山孤驛樓。"]'),
('cdc5cd0e-1d3f-475b-a3a6-aeef9765a896','頻訪盧秀才','韓偓','唐','唐诗','tang','','[]','藥訣棊經思致論，柳腰蓮臉本忘情。',32,'全唐诗/poet.tang.38000.json','["藥訣棊經思致論，柳腰蓮臉本忘情。", "頻頻強入風流坐，酒肆應疑阮步兵。"]'),
('b447cd88-87d9-445e-ab03-76b3b998821a','荅友人見寄酒','韓偓','唐','唐诗','tang','','[]','雖可忘憂矣，其如作病何。',24,'全唐诗/poet.tang.38000.json','["雖可忘憂矣，其如作病何。", "淋漓滿襟袖，更發楚狂歌。"]'),
('4afdf208-2b80-4665-a3e2-23a8bbd4e955','野釣','韓偓','唐','唐诗','tang','','[]','細雨桃花水，輕鷗逆浪飛。',24,'全唐诗/poet.tang.38000.json','["細雨桃花水，輕鷗逆浪飛。", "風頭阻歸櫂，坐睡倚蓑衣。"]'),
('c86f9f2e-ddf0-4d1f-beaa-56fe2fef9a87','曲江晚思','韓偓','唐','唐诗','tang','','[]','雲物陰寂歷，竹木寒青蒼。',24,'全唐诗/poet.tang.38000.json','["雲物陰寂歷，竹木寒青蒼。", "水冷鷺鷥立，煙月愁昏黃。"]'),
('8ffe24e6-8eb5-44c0-be0a-c26de43cf5f4','贈友人','韓偓','唐','唐诗','tang','','[]','莫嫌談笑與經過，却恐閑多病亦多。',32,'全唐诗/poet.tang.38000.json','["莫嫌談笑與經過，却恐閑多病亦多。", "若遣心中無一事，不知爭奈日長何。"]'),
('e6529d0f-9b9a-46dd-9d96-867ddd5e565c','半睡','韓偓','唐','唐诗','tang','','[]','眉山暗澹向殘燈，一半雲鬟墜枕稜。',32,'全唐诗/poet.tang.38000.json','["眉山暗澹向殘燈，一半雲鬟墜枕稜。", "四體著人嬌欲泣，自家揉損砑繚綾。"]'),
('73ad083b-da5b-4d0b-8af6-d2c1ece6cc76','已涼','韓偓','唐','唐诗','tang','','[]','愁多却訝天涼早，思倦飜嫌夜漏遲。',32,'全唐诗/poet.tang.38000.json','["愁多却訝天涼早，思倦飜嫌夜漏遲。", "何處山川孤館裏，向燈彎盡一雙眉。"]'),
('c204ce3c-21ce-43ad-9537-703e4c26fa6a','寄禪師','韓偓','唐','唐诗','tang','','[]','從無入有雲峰聚，已有還無電火銷。',32,'全唐诗/poet.tang.38000.json','["從無入有雲峰聚，已有還無電火銷。", "銷聚本來皆是幻，世間閑口漫囂囂。"]'),
('16506161-f82b-493d-a0d0-1c324d14e9ef','訪明公大德','韓偓','唐','唐诗','tang','','[]','寸髮如霜袒右肩，倚肩筇竹貌怡然。',64,'全唐诗/poet.tang.38000.json','["寸髮如霜袒右肩，倚肩筇竹貌怡然。", "懸燈深屋夜分坐，移榻向陽齋後眠。", "刮膜且揚三毒論，攝心徐指二宗禪。", "清涼藥分能知味，各自胷中有醴泉。"]'),
('c551b53f-7d06-4acc-9859-97040190e81b','大酺樂','韓偓','唐','唐诗','tang','','[]','晚日催弦管，春風入綺羅。',24,'全唐诗/poet.tang.38000.json','["晚日催弦管，春風入綺羅。", "杏花如有意，偏落舞衫多。"]'),
('6d96149c-b4b2-4ebe-942e-108e2fabec03','思歸樂','韓偓','唐','唐诗','tang','','[]','淚滴珠難盡，容殊玉易銷。',24,'全唐诗/poet.tang.38000.json','["淚滴珠難盡，容殊玉易銷。", "儻隨明月去，莫道夢魂遙。"]'),
('51280f0b-5a60-4865-80b1-557a1e6d008e','御製春遊長句','韓偓','唐','唐诗','tang','','[]','天意分明道已光，春遊嘉景勝仙鄉。',128,'全唐诗/poet.tang.38000.json','["天意分明道已光，春遊嘉景勝仙鄉。", "玉爐煙直風初靜，銀漢雲消日正長。", "柳帶似眉全展綠，杏苞如臉半開香。", "黃鶯歷歷啼紅樹，紫燕關關語畫梁。", "低檻晚晴籠翡翠，小池波暖浴鴛鴦。", "馬嘶廣陌貪新草，人醉花堤怕夕陽。", "比屋管弦呈妙曲，連營羅綺鬬時妝。", "全吳霸越千年後，獨此升平顯萬方。"]'),
('73ba6059-c8e0-4dec-81ad-534398fae2da','幽窗','韓偓','唐','唐诗','tang','','[]','刺繡非無暇，幽窗自尟歡。',48,'全唐诗/poet.tang.38000.json','["刺繡非無暇，幽窗自尟歡。", "手香江橘嫩，齒輭越梅酸。", "密約臨行怯，私書欲報難。", "無憑諳鵲語，猶得暫心寬。"]'),
('4034153b-4490-4b55-81d8-d1129753f56b','江樓二首 一','韓偓','唐','唐诗','tang','','[]','夢啼嗚咽覺無語，杳杳微微望煙浦。',32,'全唐诗/poet.tang.38000.json','["夢啼嗚咽覺無語，杳杳微微望煙浦。", "樓空客散燕交飛，江靜帆飛日亭午。"]'),
('9d3f7f00-9c7c-48c1-a0cd-46150bf4ef84','江樓二首 二','韓偓','唐','唐诗','tang','','[]','鳀魚苦筍香味新，楊柳酒旗三月春。',32,'全唐诗/poet.tang.38000.json','["鳀魚苦筍香味新，楊柳酒旗三月春。", "風光百計牽人老，爭奈多情是病身。"]'),
('735d0f6c-1338-4d36-a741-3cb60712902b','春盡日','韓偓','唐','唐诗','tang','','[]','樹頭初日照西檐，樹底蔫花夜雨霑。',64,'全唐诗/poet.tang.38000.json','["樹頭初日照西檐，樹底蔫花夜雨霑。", "外院池亭聞動鎖，後堂闌檻見垂簾。", "柳腰入戶風斜倚，榆莢堆牆水半淹。", "把酒送春惆悵在，年年三月病厭厭。"]'),
('5a57acaf-59f9-403f-a6c8-7039461a139b','詠燈','韓偓','唐','唐诗','tang','','[]','高在酒樓明錦幕，遠隨漁艇泊煙江。',32,'全唐诗/poet.tang.38000.json','["高在酒樓明錦幕，遠隨漁艇泊煙江。", "古來幽怨皆銷骨，休向長門背雨窗。"]'),
('6a564a6e-d8aa-49c5-8478-39a7697724c4','別緒','韓偓','唐','唐诗','tang','','[]','別緒靜愔愔，牽愁暗入心。',72,'全唐诗/poet.tang.38000.json','["別緒靜愔愔，牽愁暗入心。", "已回花渚櫂，悔聽酒壚琴。", "菊露淒羅幕，棃霜惻錦衾。", "此生終獨宿，到死誓相尋。", "月好知何計，歌闌歎不禁。", "山巔更高處，憶上上頭吟。"]'),
('b9964314-a0ea-4f2c-87a4-aa87f44080fe','見花','韓偓','唐','唐诗','tang','','[]','褰裳擁鼻正吟詩，日午牆頭獨見時。',64,'全唐诗/poet.tang.38000.json','["褰裳擁鼻正吟詩，日午牆頭獨見時。", "血染蜀羅山躑躅，肉紅宮錦海棠棃。", "因狂得病真閑事，欲詠無才是所悲。", "看却東風歸去也，爭教判得最繁枝。"]'),
('ec668690-153b-4beb-8668-5013b5e28820','馬上見','韓偓','唐','唐诗','tang','','[]','驕馬錦連錢，乘騎是謫仙。',48,'全唐诗/poet.tang.38000.json','["驕馬錦連錢，乘騎是謫仙。", "和帬穿玉鐙，隔袖把金鞭。", "去帶懵騰醉，歸成困頓眠。", "自憐輸廐吏，餘煖在香韉。"]'),
('d71ed4d1-7e07-4c4f-ba21-a1075caeb95d','繞廊','韓偓','唐','唐诗','tang','','[]','濃煙隔簾香漏泄，斜燈映竹光參差。',32,'全唐诗/poet.tang.38000.json','["濃煙隔簾香漏泄，斜燈映竹光參差。", "繞廊倚柱堪惆悵，細雨輕寒花落時。"]'),
('55663383-5899-4e2d-9ce2-eaefb0c48874','屐子','韓偓','唐','唐诗','tang','','[]','方寸膚圓光緻緻，白羅繡屧紅托裏。',32,'全唐诗/poet.tang.38000.json','["方寸膚圓光緻緻，白羅繡屧紅托裏。", "南朝天子欠風流，却重金蓮輕綠齒。"]'),
('081fcc0d-3551-4ec2-939d-943b5fcf698f','青春','韓偓','唐','唐诗','tang','','[]','眼意心期卒未休，暗中終擬約秦樓。',64,'全唐诗/poet.tang.38000.json','["眼意心期卒未休，暗中終擬約秦樓。", "光陰負我難相遇，情緒牽人不自由。", "遙夜定嫌香蔽膝，悶時應弄玉搔頭。", "櫻桃花謝棃花發，腸斷青春兩處愁。"]'),
('de845f8f-03ae-49f8-8007-716b8ef5ba5d','聞雨','韓偓','唐','唐诗','tang','','[]','香侵蔽膝夜寒輕，聞雨傷春夢不成。',32,'全唐诗/poet.tang.38000.json','["香侵蔽膝夜寒輕，聞雨傷春夢不成。", "羅帳四垂紅燭背，玉釵敲著枕函聲。"]'),
('6c08fb29-5cab-4eb5-93d2-d62677c066ed','嬾起','韓偓','唐','唐诗','tang','','[]','百舌喚朝眠，春心動幾般。',72,'全唐诗/poet.tang.38000.json','["百舌喚朝眠，春心動幾般。", "枕痕霞黯澹，淚粉玉闌珊。", "籠繡香煙歇，屏山燭燄殘。", "煖嫌羅韤窄，瘦覺錦衣寬。", "昨夜三更雨，今朝一陣寒。", "海棠花在否，側臥卷簾看。"]'),
('1deac6d5-6da0-4d9f-a182-2f0697cbb932','已涼','韓偓','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u4e03\u8a00\u7edd\u53e5", "\u7231\u60c5", "\u5199\u666f", "\u5a49\u7ea6"]','碧闌干外繡簾垂，猩血屏風畫折枝。',32,'全唐诗/poet.tang.38000.json','["碧闌干外繡簾垂，猩血屏風畫折枝。", "八尺龍鬚方錦褥，已涼天氣未寒時。"]'),
('600b055c-cffb-48d7-bf63-36d4b8ef6071','欲去','韓偓','唐','唐诗','tang','','[]','紛紜隔窗語，重約蹋青期。',48,'全唐诗/poet.tang.38000.json','["紛紜隔窗語，重約蹋青期。", "總得相逢處，無非欲去時。", "恨深書不盡，寵極意多疑。", "惆悵桃源路，惟教夢寐知。"]'),
('c3f84d62-65f3-47ed-b2a7-2454f354276b','橫塘','韓偓','唐','唐诗','tang','','[]','秋寒灑背入簾霜，鳳脛燈清照洞房。',64,'全唐诗/poet.tang.38000.json','["秋寒灑背入簾霜，鳳脛燈清照洞房。", "蜀紙麝煤沾筆興，越甌犀液發茶香。", "風飄亂點更籌轉，拍送繁弦曲破長。", "散客出門斜月在，兩眉愁思問橫塘。"]'),
('d3b2b69e-ed01-4a03-9cd8-b9ecbb2bc2b9','五更','韓偓','唐','唐诗','tang','','[]','往年曾約鬱金牀，半夜潛身入洞房。',64,'全唐诗/poet.tang.38000.json','["往年曾約鬱金牀，半夜潛身入洞房。", "懷裏不知金鈿落，暗中唯覺繡鞵香。", "此時欲別魂俱斷，自後相逢眼更狂。", "光景旋消惆悵在，一生贏得是淒涼。"]'),
('c27aaf29-a365-46ae-93dd-3e855dedc02e','聯綴體','韓偓','唐','唐诗','tang','','[]','院宇秋明日日長，社前一雁到遼陽。',32,'全唐诗/poet.tang.38000.json','["院宇秋明日日長，社前一雁到遼陽。", "隴頭鍼線年年事，不喜寒碪擣斷腸。"]'),
('8a37da24-6ff6-491a-bd2c-ead3df126e94','半睡','韓偓','唐','唐诗','tang','','[]','擡鏡仍嫌重，更衣又怕寒。',24,'全唐诗/poet.tang.38000.json','["擡鏡仍嫌重，更衣又怕寒。", "宵分未歸帳，半睡待郎看。"]'),
('b0589a3e-6f1a-447d-9792-994c4af9398b','寒食夜','韓偓','唐','唐诗','tang','','[]','清江碧草兩悠悠，各自風流一種愁。',32,'全唐诗/poet.tang.38000.json','["清江碧草兩悠悠，各自風流一種愁。", "正是落花寒食夜，夜深無伴倚南樓。"]'),
('4462bb65-2600-4ffe-bca1-6f11899de712','哭花','韓偓','唐','唐诗','tang','','[]','曾愁香結破顏遲，今見妖紅委地時。',32,'全唐诗/poet.tang.38000.json','["曾愁香結破顏遲，今見妖紅委地時。", "若是有情爭不哭，夜來風雨葬西施。"]'),
('2165cce4-3a7d-484a-9bd4-ec6e8ee925d9','重遊曲江','韓偓','唐','唐诗','tang','','[]','鞭梢亂拂暗傷情，蹤跡難尋露草青。',32,'全唐诗/poet.tang.38000.json','["鞭梢亂拂暗傷情，蹤跡難尋露草青。", "猶是玉輪曾輾處，一泓秋水漲浮萍。"]'),
('f5b0b440-9222-441c-a22a-969c6c5f89a8','遙見','韓偓','唐','唐诗','tang','','[]','悲歌淚溼澹胭脂，閑立風吹金縷衣。',32,'全唐诗/poet.tang.38000.json','["悲歌淚溼澹胭脂，閑立風吹金縷衣。", "白玉堂東遙見後，令人斗薄畫楊妃。"]'),
('b89ddfab-befa-4387-b120-9aea264180ec','新秋','韓偓','唐','唐诗','tang','','[]','一夜清風動扇愁，背時容色入新秋。',32,'全唐诗/poet.tang.38000.json','["一夜清風動扇愁，背時容色入新秋。", "桃花臉裏汪汪淚，忍到更深枕上流。"]'),
('12bb090c-7e30-4acb-bd88-276e8d45a049','宮詞','韓偓','唐','唐诗','tang','','[]','繡帬斜立正銷魂，侍女移燈掩殿門。',32,'全唐诗/poet.tang.38000.json','["繡帬斜立正銷魂，侍女移燈掩殿門。", "燕子不來花著雨，春風應自怨黃昏。"]'),
('35e57b71-e2fc-4559-adcc-3db1fc5b7640','蹋青','韓偓','唐','唐诗','tang','','[]','蹋青會散欲歸時，金車久立頻催上。',32,'全唐诗/poet.tang.38000.json','["蹋青會散欲歸時，金車久立頻催上。", "收帬整髻故遲遲，兩點深心各惆悵。"]'),
('36563b54-2b56-4ffa-8e64-5d65e9ce715e','夜深','韓偓','唐','唐诗','tang','','["\u79cb\u5343", "\u5bd2\u98df\u8282", "\u5199\u666f"]','惻惻輕寒翦翦風，小梅飄雪杏花紅。',32,'全唐诗/poet.tang.38000.json','["惻惻輕寒翦翦風，小梅飄雪杏花紅。", "夜深斜搭鞦韆索，樓閣朦朧煙雨中。"]'),
('0606d2ab-617e-4b59-880c-0e11b2ebed03','夏日','韓偓','唐','唐诗','tang','','[]','庭樹新陰葉未成，玉階人靜一蟬聲。',32,'全唐诗/poet.tang.38000.json','["庭樹新陰葉未成，玉階人靜一蟬聲。", "相風不動烏龍睡，時有嬌鶯自喚名。"]'),
('9e232d5c-325f-4119-a85b-9f6fcd1da1a5','新上頭','韓偓','唐','唐诗','tang','','[]','學梳鬆鬢試新帬，消息佳期在此春。',32,'全唐诗/poet.tang.38000.json','["學梳鬆鬢試新帬，消息佳期在此春。", "爲要好多心轉惑，徧將宜稱問傍人。"]'),
('f7f33651-e5e9-4edd-bb59-25aad8fcdc16','中庭','韓偓','唐','唐诗','tang','','[]','夜短睡遲慵早起，日高方始出紗窗。',32,'全唐诗/poet.tang.38000.json','["夜短睡遲慵早起，日高方始出紗窗。", "中庭自摘青梅子，先向釵頭戴一雙。"]'),
('ef0fa306-1791-4d0e-935a-2338705f4adf','詠浴','韓偓','唐','唐诗','tang','','[]','再整魚犀攏翠簪，解衣先覺冷森森。',64,'全唐诗/poet.tang.38000.json','["再整魚犀攏翠簪，解衣先覺冷森森。", "教移蘭燭頻羞影，自試香湯更怕深。", "初似洗花難抑按，終憂沃雪不勝任。", "豈知侍女簾帷外，賸取君王幾餅金。"]'),
('b05ebac5-df81-4347-8a06-0cbf6e773c24','席上有贈','韓偓','唐','唐诗','tang','','[]','矜嚴標格絕嫌猜，嗔怒雖逢笑靨開。',64,'全唐诗/poet.tang.38000.json','["矜嚴標格絕嫌猜，嗔怒雖逢笑靨開。", "小雁斜侵眉柳去，媚霞橫接眼波來。", "鬢垂香頸雲遮藕，粉著蘭胷雪壓梅。", "莫道風流無宋玉，好將心力事妝臺。"]'),
('539d9067-ddd4-42a0-a236-dd768b39a3fb','早歸','韓偓','唐','唐诗','tang','','[]','去是黃昏後，歸當朧{月悤}時。',27,'全唐诗/poet.tang.38000.json','["去是黃昏後，歸當朧{月悤}時。", "扠衣吟宿醉，風露動相思。"]'),
('ae28e94c-11f4-4147-833e-7978d1e8993c','玉合','韓偓','唐','唐诗','tang','','[]','羅囊繡兩鳳皇，玉合雕雙鸂鶒。',62,'全唐诗/poet.tang.38000.json','["羅囊繡兩鳳皇，玉合雕雙鸂鶒。", "中有蘭膏漬紅豆，每回拈著長相憶。", "長相憶，經幾春。", "人悵望，香氤氳。", "開緘不見新書迹，帶粉猶殘舊淚痕。"]'),
('5c598957-e484-4b95-aa04-06def69cce7b','金陵','韓偓','唐','唐诗','tang','','[]','風雨蕭蕭，石頭城下木蘭橈。',58,'全唐诗/poet.tang.38000.json','["風雨蕭蕭，石頭城下木蘭橈。", "煙月迢迢，金陵渡口去來潮。", "自古風流皆暗銷，才魂妖魂誰與招。", "彩牋麗句今已矣，羅韈金蓮何寂寥。"]'),
('c8f64e35-bd8d-4fa9-b362-b1ff9532d952','嬾卸頭','韓偓','唐','唐诗','tang','','[]','侍女動妝籢，故故驚人睡。',48,'全唐诗/poet.tang.38000.json','["侍女動妝籢，故故驚人睡。", "那知本未眠，背面偷垂淚。", "嬾卸鳳皇釵，羞入鴛鴦被。", "時復見殘燈，和煙墜金穗。"]'),
('86fd59f2-c97f-4cac-a057-2e0b5681c1f8','倚醉','韓偓','唐','唐诗','tang','','[]','倚醉無端尋舊約，却憐惆悵轉難勝。',64,'全唐诗/poet.tang.38000.json','["倚醉無端尋舊約，却憐惆悵轉難勝。", "靜中樓閣深春雨，遠處簾櫳半夜燈。", "抱柱立時風細細，繞廊行處思騰騰。", "分明窗下聞裁翦，敲徧闌干喚不譍。"]'),
('f005b5d4-37c5-4509-a474-4f33a06caca0','詠手','韓偓','唐','唐诗','tang','','[]','腕白膚紅玉筍芽，調琴抽線露尖斜。',64,'全唐诗/poet.tang.38000.json','["腕白膚紅玉筍芽，調琴抽線露尖斜。", "背人細撚垂臙鬢，向鏡輕勻襯臉霞。", "悵望昔逢褰繡幔，依稀曾見托金車。", "後園笑向同行道，摘得蘼蕪又折花。"]'),
('cbb41e14-8b16-4286-93c4-cf0feb0cf7d1','荷花','韓偓','唐','唐诗','tang','','[]','紈扇相敧綠，香囊獨立紅。',48,'全唐诗/poet.tang.38000.json','["紈扇相敧綠，香囊獨立紅。", "浸淫因重露，狂暴是秋風。", "逸調無人唱，秋塘每夜空。", "何繇見周昉，移入畫屏中。"]'),
('f5e38966-817e-4666-90c5-636d400dcbb6','鬆髻','韓偓','唐','唐诗','tang','','[]','髻根鬆慢玉釵垂，指點花枝又過時。',32,'全唐诗/poet.tang.38000.json','["髻根鬆慢玉釵垂，指點花枝又過時。", "坐久暗生惆悵事，背人勻却淚臙脂。"]'),
('c4a9f6cf-afe7-4bd4-a36f-0cef0ee09c79','寄遠','韓偓','唐','唐诗','tang','','[]','眉如半月雲如鬟，梧桐葉落敲井闌。',64,'全唐诗/poet.tang.38000.json','["眉如半月雲如鬟，梧桐葉落敲井闌。", "孤燈亭亭公署寒，微霜淒淒客衣單。", "想美人兮雲一端，夢魂悠悠關山難。", "空房展轉懷悲酸，銅壺漏盡聞金鸞。"]'),
('2d188e5a-252b-4ee2-9312-963c738f36d4','蹤跡','韓偓','唐','唐诗','tang','','[]','東烏西兔似車輪，劫火桑田不復論。',32,'全唐诗/poet.tang.38000.json','["東烏西兔似車輪，劫火桑田不復論。", "唯有風光與蹤跡，思量長是暗銷魂。"]'),
('d0bda067-2b0f-4350-91b5-263fef49d679','病憶','韓偓','唐','唐诗','tang','','[]','信知尤物必牽情，一顧難酬覺命輕。',32,'全唐诗/poet.tang.38000.json','["信知尤物必牽情，一顧難酬覺命輕。", "曾把禪機銷此病，破除纔盡又重生。"]'),
('1d36430f-6c79-46c4-a32f-356e82cc17d7','妬媒','韓偓','唐','唐诗','tang','','[]','洞房深閉不曾開，橫臥烏龍作妬媒。',96,'全唐诗/poet.tang.38000.json','["洞房深閉不曾開，橫臥烏龍作妬媒。", "好鳥豈勞兼比翼，異華何必更重臺。", "難留旋逐驚飆去，暫見如隨急電來。", "多爲過防成後悔，偶因翻語得深猜。", "已嫌刻蠟春宵短，最恨鳴珂曉鼓催。", "應笑楚囊仙分薄，日中長是獨裴回。"]'),
('3275afa6-909d-4ff3-8013-95deb60e6370','不見','韓偓','唐','唐诗','tang','','[]','動靜防閑又怕疑，佯佯脈脈是深機。',32,'全唐诗/poet.tang.38000.json','["動靜防閑又怕疑，佯佯脈脈是深機。", "此身願作君家燕，秋社歸時也不歸。"]'),
('d425875b-b6a9-4e2a-922d-212a0ab2b181','晝寢','韓偓','唐','唐诗','tang','','[]','碧桐陰盡隔簾櫳，扇拂金鵝玉簟烘。',64,'全唐诗/poet.tang.38000.json','["碧桐陰盡隔簾櫳，扇拂金鵝玉簟烘。", "撲粉更添香體滑，解衣唯見下裳紅。", "煩襟乍觸冰壺冷，倦枕徐敧寶髻鬆。", "何必苦勞魂與夢，王昌只在此牆東。"]'),
('039e9918-e8b2-4172-95f1-2feab66a64c8','意緒','韓偓','唐','唐诗','tang','','[]','絕代佳人何寂寞，棃花未發梅花落。',64,'全唐诗/poet.tang.38000.json','["絕代佳人何寂寞，棃花未發梅花落。", "東風吹雨入西園，銀綫千條度虛閣。", "臉粉難勻蜀酒濃，口脂易印吳綾薄。", "嬌饒意態不勝羞，願倚郎肩永相著。"]'),
('d861b947-eb7a-4782-8202-7b52616fa213','惆悵','韓偓','唐','唐诗','tang','','[]','身情長在暗相隨，生魄隨君君豈知。',64,'全唐诗/poet.tang.38000.json','["身情長在暗相隨，生魄隨君君豈知。", "被頭不煖空霑淚，釵股欲分猶半疑。", "朗月清風難愜意，詞人絕色多傷離。", "何如飲酒連千醉，席地幕天無所知。"]'),
('6d136e35-ed32-44ae-85a3-7ef902fa66de','忍笑','韓偓','唐','唐诗','tang','','[]','宮樣衣裳淺畫眉，晚來梳洗更相宜。',32,'全唐诗/poet.tang.38000.json','["宮樣衣裳淺畫眉，晚來梳洗更相宜。", "水精鸚鵡釵頭顫，舉袂佯羞忍笑時。"]'),
('c82d653f-2323-4d90-9685-c55a15ee3df6','詠柳','韓偓','唐','唐诗','tang','','[]','褭雨拖風不自持，全身無力向人垂。',32,'全唐诗/poet.tang.38000.json','["褭雨拖風不自持，全身無力向人垂。", "玉纖折得遙相贈，便似觀音手裏時。"]'),
('8b1c63db-d120-4679-acd0-ac49def44b62','密意','韓偓','唐','唐诗','tang','','[]','呵花貼鬢黏寒髮，凝酥光透猩猩血。',32,'全唐诗/poet.tang.38000.json','["呵花貼鬢黏寒髮，凝酥光透猩猩血。", "經過洛水幾多人，唯有陳王見羅韈。"]'),
('24adc1f8-2221-45ff-a8b8-c760bcb0c17f','偶見','韓偓','唐','唐诗','tang','','[]','鞦韆打困解羅帬，指點醍醐索一尊。',32,'全唐诗/poet.tang.38000.json','["鞦韆打困解羅帬，指點醍醐索一尊。", "見客入來和笑走，手搓梅子映中門。"]'),
('9442cf34-ce1b-47c7-8779-dccb11de4373','寒食夜有寄','韓偓','唐','唐诗','tang','','[]','風流大抵是倀倀，此際相思必斷腸。',32,'全唐诗/poet.tang.38000.json','["風流大抵是倀倀，此際相思必斷腸。", "雲薄月昏寒食夜，隔簾微雨杏花香。"]'),
('8ebd1227-9a94-4f30-bc83-8aa364549f2c','寒食夜有寄','韓偓','唐','唐诗','tang','','[]','風流大抵是倀倀，一度相思一斷腸。',32,'全唐诗/poet.tang.38000.json','["風流大抵是倀倀，一度相思一斷腸。", "雲薄月昏寒食夜，隔簾微雨杏花香。"]'),
('e78b2a65-7582-4a33-aeca-030091c8c3a8','效崔國輔體四首 一','韓偓','唐','唐诗','tang','','[]','澹月照中庭，海棠花自落。',24,'全唐诗/poet.tang.38000.json','["澹月照中庭，海棠花自落。", "獨立俯閑階，風動鞦韆索。"]'),
('abb8de6b-83f2-4e33-8c2f-2e2c9b2bc601','效崔國輔體四首 二','韓偓','唐','唐诗','tang','','[]','雨後碧苔院，霜來紅葉樓。',24,'全唐诗/poet.tang.38000.json','["雨後碧苔院，霜來紅葉樓。", "閑階上斜日，鸚鵡伴人愁。"]'),
('c5e10aeb-d2ff-445c-ade1-96d5483b03a5','效崔國輔體四首 三','韓偓','唐','唐诗','tang','','[]','酒力滋睡眸，鹵莽聞街鼓。',24,'全唐诗/poet.tang.38000.json','["酒力滋睡眸，鹵莽聞街鼓。", "欲明天更寒，東風打窗雨。"]'),
('44f24a1d-1aa5-483e-a4e6-29e56869c13b','效崔國輔體四首 四','韓偓','唐','唐诗','tang','','[]','羅幕生春寒，繡窗愁未眠。',24,'全唐诗/poet.tang.38000.json','["羅幕生春寒，繡窗愁未眠。", "南湖一夜雨，應溼采蓮船。"]'),
('cec27cbe-ddaf-4788-979e-09a358c922d3','後魏時相州人作李波小妹歌疑其未備因補之','韓偓','唐','唐诗','tang','','[]','李波小妹字雍容，窄衣短袖蠻錦紅。',64,'全唐诗/poet.tang.38000.json','["李波小妹字雍容，窄衣短袖蠻錦紅。", "未解有情夢梁殿，何曾自媚妒吳宮。", "難教牽引知酒味，因令悵望成春慵。", "海棠花下鞦韆畔，背人撩鬢道怱怱。"]'),
('cbc92492-14f6-4380-b450-205ce7361af1','春晝','韓偓','唐','唐诗','tang','','[]','春融豔豔，大醉陶陶。',82,'全唐诗/poet.tang.38000.json','["春融豔豔，大醉陶陶。", "漏添遲日，箭減良宵。", "藤垂戟戶，柳拂河橋。", "簾幕燕子，池塘[伯]勞。", "膚清臂瘦，衫薄香銷。", "楚殿衣窄，南朝髻高。", "河陽縣遠，清波地遙。", "絲纏露泣，各自無憀。"]'),
('6a22f497-6057-4278-9bed-6d1e2a1d625b','三憶 一','韓偓','唐','唐诗','tang','','[]','憶眠時，春夢困騰騰。',22,'全唐诗/poet.tang.38000.json','["憶眠時，春夢困騰騰。", "展轉不能起，玉釵垂枕稜。"]'),
('3cc59edb-ddc2-483d-a3aa-75fd9550c807','三憶 二','韓偓','唐','唐诗','tang','','[]','憶行時，背手挼金雀。',22,'全唐诗/poet.tang.38000.json','["憶行時，背手挼金雀。", "斂笑慢回頭，步轉闌干角。"]'),
('78591d34-88de-41de-a9ec-a27bd0524dfe','三憶 三','韓偓','唐','唐诗','tang','','[]','憶去時，向月遲遲行。',22,'全唐诗/poet.tang.38000.json','["憶去時，向月遲遲行。", "強語戲同伴，圖郎聞笑聲。"]'),
('fd41af99-b592-4d19-9526-9b98759f3dfd','六言三首 一','韓偓','唐','唐诗','tang','','[]','春樓處子傾城，金陵狎客多情。',56,'全唐诗/poet.tang.38000.json','["春樓處子傾城，金陵狎客多情。", "朝雲暮雨會合，羅韤繡被逢迎。", "華山梧桐相覆，蠻江荳蔻連生。", "幽歡不盡告別，秋河悵望平明。"]'),
('fe6db001-85fa-4642-b150-7d0ee66cc9e5','六言三首 二','韓偓','唐','唐诗','tang','','[]','一燈前雨落夜，三月盡草青時。',56,'全唐诗/poet.tang.38000.json','["一燈前雨落夜，三月盡草青時。", "半寒半暖正好，花開花謝相思。", "惆悵空教夢見，懊惱多成酒悲。", "紅袖不乾誰會，揉損聯娟澹眉。"]'),
('8b7595c3-a611-4ed9-8ba9-576380e239b6','六言三首 三','韓偓','唐','唐诗','tang','','[]','此間青草更遠，不唯空繞汀洲。',56,'全唐诗/poet.tang.38000.json','["此間青草更遠，不唯空繞汀洲。", "那裏朝日才出，還應先照西樓。", "憶淚因成恨淚，夢遊常續心遊。", "桃源洞口來否，絳節霓旌久留。"]'),
('d17588cc-0e34-4bfc-8c20-a16a939b31b4','寒食日重遊李氏園亭有懷','韓偓','唐','唐诗','tang','','["\u5bd2\u98df\u8282", "\u611f\u4f24", "\u6000\u5ff5"]','往年同在鸞橋上，見倚朱闌詠柳緜。',64,'全唐诗/poet.tang.38000.json','["往年同在鸞橋上，見倚朱闌詠柳緜。", "今日獨來香徑裏，更無人跡有苔錢。", "傷心闊別三千里，屈指思量四五年。", "料得他鄉遇佳節，亦應懷抱暗淒然。"]'),
('0cbaa67b-97f3-473e-8438-9976693e1dcc','思錄舊詩於卷上淒然有感因成一章','韓偓','唐','唐诗','tang','','[]','緝綴小詩鈔卷裏，尋思閑事到心頭。',32,'全唐诗/poet.tang.38000.json','["緝綴小詩鈔卷裏，尋思閑事到心頭。", "自吟自泣無人會，腸斷蓬山第一流。"]'),
('ac439702-7c98-48c0-a087-8b2f8674e025','春閨二首 一','韓偓','唐','唐诗','tang','','[]','願結交加夢，因傾瀲灩尊。',24,'全唐诗/poet.tang.38000.json','["願結交加夢，因傾瀲灩尊。", "醒來情緒惡，簾外正黃昏。"]'),
('1c161fe9-2cd6-4b7e-94b2-4b38d878c8ac','春閨二首 二','韓偓','唐','唐诗','tang','','[]','氤氳帳裏香，薄薄睡時妝。',24,'全唐诗/poet.tang.38000.json','["氤氳帳裏香，薄薄睡時妝。", "長吁解羅帶，怯見上空牀。"]'),
('f267a052-49bf-4ba5-8357-92f6bceb82c0','代小玉家爲蕃騎所虜後寄故集賢裴公相國','韓偓','唐','唐诗','tang','','[]','動天金鼓逼神州，惜別無心學墜樓。',64,'全唐诗/poet.tang.38000.json','["動天金鼓逼神州，惜別無心學墜樓。", "不得回眸辭傅粉，便須含淚對殘秋。", "折釵伴妾埋青冢，半鏡隨郎葬杜郵。", "唯有此宵魂夢裏，殷勤見覓鳳池頭。"]'),
('695d97de-86e8-48be-8e43-3b4fbace1630','薦福寺講筵偶見又別','韓偓','唐','唐诗','tang','','[]','見時濃日午，別處暮鐘殘。',48,'全唐诗/poet.tang.38000.json','["見時濃日午，別處暮鐘殘。", "景色疑春盡，襟懷似酒闌。", "兩情含眷戀，一餉致辛酸。", "夜靜長廊下，難尋屐齒看。"]'),
('3168a5c2-50fd-46d1-808f-d911988d0807','復偶見三絕 一','韓偓','唐','唐诗','tang','','[]','霧爲襟袖玉爲冠，半似羞人半忍寒。',32,'全唐诗/poet.tang.38000.json','["霧爲襟袖玉爲冠，半似羞人半忍寒。", "別易會難長自歎，轉身應把淚珠彈。"]'),
('9a204f0e-638b-40ca-8cc0-3ea291f7867b','復偶見三絕 二','韓偓','唐','唐诗','tang','','[]','桃花臉薄難藏淚，柳葉眉長易覺愁。',32,'全唐诗/poet.tang.38000.json','["桃花臉薄難藏淚，柳葉眉長易覺愁。", "密跡未成當面笑，幾迴擡眼又低頭。"]'),
('4acbcf98-a9a7-4137-8f1f-3ec2a7beb87e','復偶見三絕 三','韓偓','唐','唐诗','tang','','[]','半身映竹輕聞語，一手揭簾微轉頭。',32,'全唐诗/poet.tang.38000.json','["半身映竹輕聞語，一手揭簾微轉頭。", "此意別人應未覺，不勝情緒兩風流。"]'),
('9e4ef9fc-781f-453d-9000-933feada38f7','厭花落','韓偓','唐','唐诗','tang','','[]','厭花落，人寂寞。',152,'全唐诗/poet.tang.38000.json','["厭花落，人寂寞。", "果樹陰成燕翅齊，西園永日閑高閣。", "後堂夾簾愁不卷，低頭悶把衣襟撚。", "忽然事到心中來，四肢嬌入茸茸眼。", "也曾同在華堂宴，佯佯攏鬢偷迴面。", "半醉狂心忍不禁，分明一任傍人見。", "書中說却平生事，猶疑未滿情郎意。", "錦囊封了又重開，夜深窗下燒紅紙。", "紅紙千張言不盡，至誠無語傳心印。", "但得鴛鴦枕臂眠，也任時光都一瞬。"]'),
('acaf1a0e-3669-4c2d-9859-6fd956d40a34','春悶偶成十二韻','韓偓','唐','唐诗','tang','','[]','阡陌懸雲壤，闌畦隔艾芝。',144,'全唐诗/poet.tang.38000.json','["阡陌懸雲壤，闌畦隔艾芝。", "路遙行雨嬾，河闊過橋遲。", "雁足應難達，狐蹤浪得疑。", "謝鯤吟未廢，張碩夢堪思。", "有意通情處，無言攏鬢時。", "格高歸斂笑，歌怨在顰眉。", "醉後金蟬重，歡餘玉燕敧。", "素姿凌白柰，圓頰誚紅棃。", "粉字題花筆，香牋詠柳詩。", "繡窗攜手約，芳草蹋青期。", "別淚開泉脈，春愁罥藕絲。", "相思不相信，幽恨更誰知。"]'),
('e070241f-b094-48b6-8d5c-345d58557ae8','想得','韓偓','唐','唐诗','tang','','[]','兩重門裏玉堂前，寒食花枝月午天。',32,'全唐诗/poet.tang.38000.json','["兩重門裏玉堂前，寒食花枝月午天。", "想得那人垂手立，嬌羞不肯上鞦韆。"]'),
('c4173c8c-49d2-410d-aad3-bdff981c3761','偶見背面是夕兼夢','韓偓','唐','唐诗','tang','','[]','酥凝背胛玉搓肩，輕薄紅綃覆白蓮。',64,'全唐诗/poet.tang.38000.json','["酥凝背胛玉搓肩，輕薄紅綃覆白蓮。", "此夜分明來入夢，當時惆悵不成眠。", "眼波向我無端豔，心火因君特地然。", "莫道人生難際會，秦樓鸞鳳有神仙。"]'),
('22a9e4cc-407e-4a0e-8cfb-1869fce730a8','五更','韓偓','唐','唐诗','tang','','[]','秋雨五更頭，桐竹鳴騷屑。',48,'全唐诗/poet.tang.38000.json','["秋雨五更頭，桐竹鳴騷屑。", "却似殘春間，斷送花時節。", "空樓雁一聲，遠屏燈半滅。", "繡被擁嬌寒，眉山正愁絕。"]'),
('3bbac938-fd13-48f8-9c47-10ba7682a05d','有憶','韓偓','唐','唐诗','tang','','[]','晝漏迢迢夜漏遲，傾城消息杳無期。',64,'全唐诗/poet.tang.38000.json','["晝漏迢迢夜漏遲，傾城消息杳無期。", "愁腸泥酒人千里，淚眼倚樓天四垂。", "自笑計狂多獨語，誰憐夢好轉相思。", "何時斗帳濃香裏，分付東風與玉兒。"]'),
('949f69b6-e482-4ae9-9c8d-6530878a7532','半夜','韓偓','唐','唐诗','tang','','[]','板閤數尊後，至今猶酒悲。',36,'全唐诗/poet.tang.38000.json','["板閤數尊後，至今猶酒悲。", "一宵相見事，半夜獨眠時。", "明朝窗下照，應有鬢如絲。"]'),
('0f36a631-8f9f-41a3-ab1f-216495a297c3','信筆','韓偓','唐','唐诗','tang','','[]','睡髻休頻攏，春眉忍更長。',48,'全唐诗/poet.tang.38000.json','["睡髻休頻攏，春眉忍更長。", "整釵梔子重，泛酒菊花香。", "繡疊昏金色，羅揉損砑光。", "有時閑弄筆，亦畫兩鴛鴦。"]'),
('5f992854-6df6-4949-885d-9b7cbc6261b1','寄恨','韓偓','唐','唐诗','tang','','[]','秦釵枉斷長條玉，蜀紙虛留小字紅。',32,'全唐诗/poet.tang.38000.json','["秦釵枉斷長條玉，蜀紙虛留小字紅。", "死恨物情難會處，蓮花不肯嫁春風。"]'),
('ada57845-f348-4b9f-91e8-48d39b24c58a','兩處','韓偓','唐','唐诗','tang','','[]','樓上澹山橫，樓前溝水清。',24,'全唐诗/poet.tang.38000.json','["樓上澹山橫，樓前溝水清。", "憐山又憐水，兩處總牽情。"]'),
('101e0115-192c-496d-b282-92d31bfe8b12','擁鼻','韓偓','唐','唐诗','tang','','[]','擁鼻悲吟一向愁，寒更轉盡未回頭。',64,'全唐诗/poet.tang.38000.json','["擁鼻悲吟一向愁，寒更轉盡未回頭。", "綠屏無睡秋分簟，紅葉傷心月午樓。", "却要因循添逸興，若爲趨競愴離憂。", "殷勤憑仗官渠水，爲到西溪動釣舟。"]'),
('377deb10-3359-4928-8ac7-8a5880e85af7','閨怨','韓偓','唐','唐诗','tang','','[]','時光潛去暗淒涼，嬾對菱花暈曉妝。',32,'全唐诗/poet.tang.38000.json','["時光潛去暗淒涼，嬾對菱花暈曉妝。", "初坼鞦韆人寂寞，後園青草任他長。"]'),
('9703d0c3-0c3c-469d-9595-082674fb8582','褭娜','韓偓','唐','唐诗','tang','','[]','褭娜腰肢澹薄妝，六朝宮樣窄衣裳。',64,'全唐诗/poet.tang.38000.json','["褭娜腰肢澹薄妝，六朝宮樣窄衣裳。", "著詞暫見櫻桃破，飛醆遙聞荳蔻香。", "春惱情懷身覺瘦，酒添顏色粉生光。", "此時不敢分明道，風月應知暗斷腸。"]'),
('8ff2b7e7-15e5-4de6-8f26-9dab2900b1a9','多情','韓偓','唐','唐诗','tang','','[]','天遣多情不自持，多情兼與病相宜。',64,'全唐诗/poet.tang.38000.json','["天遣多情不自持，多情兼與病相宜。", "蠭偷野蜜初嘗處，鶯啄含桃欲咽時。", "酒蕩襟懷微駊騀，春牽情緒更融怡。", "水香賸置金盆裏，瓊樹長須浸一枝。"]'),
('236dbeb0-604a-43a4-a8cb-d5733d7b60fa','偶見','韓偓','唐','唐诗','tang','','[]','千金莫惜旱蓮生，一笑從教下蔡傾。',64,'全唐诗/poet.tang.38000.json','["千金莫惜旱蓮生，一笑從教下蔡傾。", "仙樹有花難問種，御香聞氣不知名。", "愁來自覺歌喉咽，瘦去誰憐舞掌輕。", "小疊紅箋書恨字，與奴方便寄卿卿。"]'),
('3f3f1766-c952-4b95-adfc-59b2df129a7c','箇儂','韓偓','唐','唐诗','tang','','[]','甚感殷勤意，其如阻礙何。',48,'全唐诗/poet.tang.38000.json','["甚感殷勤意，其如阻礙何。", "隔簾窺綠齒，映柱送橫波。", "老大逢知少，襟懷暗喜多。", "因傾一尊酒，聊以慰蹉跎。"]'),
('5b4229ef-dfa0-4d4b-b619-58db1756edc3','無題 一','韓偓','唐','唐诗','tang','','[]','小檻移燈灺，空房鎖隙塵。',168,'全唐诗/poet.tang.38000.json','["小檻移燈灺，空房鎖隙塵。", "額波風盡日，簾影月侵晨。", "香辣更衣後，釵梁攏鬢新。", "吉音聞詭計，醉語近天真。", "妝好方長歎，歡餘却淺顰。", "繡屏金作屋，絲幰玉爲輪。", "致意通緜竹，精誠託錦鱗。", "歌凝眉際恨，酒發臉邊春。", "溪紵殊傾越，樓簫豈羨秦。", "柳虛禳沴氣，梅實引芳津。", "樂府降清唱，宮廚減食珍。", "防閑襟幷斂，忍妬淚休勻。", "宿飲愁縈夢，春寒瘦著人。", "手持雙荳蔻，的的爲東鄰。"]'),
('9c402fa0-548f-41a8-b2c1-3070e34684f6','無題 二','韓偓','唐','唐诗','tang','','[]','碧瓦偏光日，紅簾不受塵。',168,'全唐诗/poet.tang.38000.json','["碧瓦偏光日，紅簾不受塵。", "柳昏連綠野，花爛爍清晨。", "書密偷看數，情通破體新。", "明言終未實，暗祝始應真。", "枉道嫌偷藥，推誠鄙效顰。", "合成雲五色，宜作日中輪。", "照獸金塗爪，釵魚玉鏤鱗。", "渺瀰三島浪，平遠一樓春。", "墮髻還名壽，修蛾本姓秦。", "櫂尋聞犬洞，槎入飲牛津。", "麟脯隨重釀，霜華間八珍。", "錦囊霞彩爛，羅韤砑光勻。", "羞澀佯牽伴，嬌饒欲泥人。", "偷兒難捉搦，慎莫共比鄰。"]'),
('bf4b5060-7a74-4650-8720-872efc10c7c2','無題 三','韓偓','唐','唐诗','tang','','[]','紫蠟融花蔕，紅緜拭鏡塵。',36,'全唐诗/poet.tang.38000.json','["紫蠟融花蔕，紅緜拭鏡塵。", "夢狂飜惜夜，妝嬾厭凌晨。", "茜袖啼痕數，香牋墨色新。"]'),
('0b15810f-cc50-4a01-91e3-eb5f62610d4b','倒押前韻','韓偓','唐','唐诗','tang','','[]','白下同歸路，烏衣枉作鄰。',168,'全唐诗/poet.tang.38000.json','["白下同歸路，烏衣枉作鄰。", "珮聲猶隔箔，香氣已迎人。", "酒勸杯須滿，書羞字不勻。", "歌憐黃竹怨，味實碧桃珍。", "翦燭非良策，當關是要津。", "東阿初度洛，楊惲舊家秦。", "粉化橫波溢，衫輕曉霧春。", "鵶黃雙鳳翅，麝月半魚鱗。", "別袂飜如浪，迴腸轉似輪。", "後期纔注脚，前事又含顰。", "縱有才難詠，寧無畫逼真。", "天香聞更有，瓊樹見長新。", "鬬草常更僕，迷鬮誤達晨。", "齅花判不得，檀注惹風塵。"]'),
('66f8e23c-67cc-468f-98a9-86a5eed3459d','閨情','韓偓','唐','唐诗','tang','','[]','輕風滴礫動簾鉤，宿酒猶酣嬾卸頭。',64,'全唐诗/poet.tang.38000.json','["輕風滴礫動簾鉤，宿酒猶酣嬾卸頭。", "但覺夜深花有露，不知人靜月當樓。", "何郎燭暗誰能詠，韓壽香焦亦任偷。", "敲折玉釵歌轉咽，一聲聲作兩眉愁。"]'),
('4dff6fe7-1993-4b4a-b014-d0d89d468211','自負','韓偓','唐','唐诗','tang','','[]','人許風流自負才，偷桃三度到瑤臺。',32,'全唐诗/poet.tang.38000.json','["人許風流自負才，偷桃三度到瑤臺。", "至今衣領胭脂在，曾被謫仙痛齩來。"]'),
('b76dae97-2b6c-47da-a501-76cc85c6b578','天涼','韓偓','唐','唐诗','tang','','[]','愁來却訝天涼早，思倦飜嫌夜漏遲。',32,'全唐诗/poet.tang.38000.json','["愁來却訝天涼早，思倦飜嫌夜漏遲。", "何處山川孤館裏，向燈彎盡一雙眉。"]'),
('1db700bc-5cef-4497-8fff-f1a63e72c745','日高','韓偓','唐','唐诗','tang','','[]','朦朧猶記管弦聲，噤[㾕]餘寒酒半醒。',34,'全唐诗/poet.tang.38000.json','["朦朧猶記管弦聲，噤[㾕]餘寒酒半醒。", "春暮日高簾半卷，落花和雨滿中庭。"]'),
('0c300f82-c5a0-40f9-bd88-6ea11aa99ffe','夕陽','韓偓','唐','唐诗','tang','','[]','花前灑淚臨寒食，醉裏回頭問夕陽。',32,'全唐诗/poet.tang.38000.json','["花前灑淚臨寒食，醉裏回頭問夕陽。", "不管相思人老盡，朝朝容易下西牆。"]'),
('7efa311b-821f-47c4-8244-0cb5bf5710aa','舊館','韓偓','唐','唐诗','tang','','[]','前歡往恨分明在，酒興詩情大半亡。',32,'全唐诗/poet.tang.38000.json','["前歡往恨分明在，酒興詩情大半亡。", "還似牆西紫荆樹，殘花摘索映高塘。"]'),
('d20df6b0-f1f4-4373-b3d2-3309406cd35d','中春憶贈','韓偓','唐','唐诗','tang','','[]','年年長是阻佳期，萬種恩情只自知。',32,'全唐诗/poet.tang.38000.json','["年年長是阻佳期，萬種恩情只自知。", "春色轉添惆悵事，似君花發兩三枝。"]'),
('1f9711cb-f271-4e07-bd57-1affa5902970','春恨','韓偓','唐','唐诗','tang','','[]','殘夢依依酒力餘，城頭畫角伴啼烏。',32,'全唐诗/poet.tang.38000.json','["殘夢依依酒力餘，城頭畫角伴啼烏。", "平明未卷西樓幕，院靜時聞響轆轤。"]'),
('61f553c6-52f6-45d5-b43e-8fd81a5370ff','鞦韆','韓偓','唐','唐诗','tang','','[]','池塘夜歇清明雨，繞院無塵近花塢。',64,'全唐诗/poet.tang.38000.json','["池塘夜歇清明雨，繞院無塵近花塢。", "五絲繩繫出牆遲，力盡纔瞵見鄰圃。", "下來嬌喘未能調，斜倚朱闌久無語。", "無語兼動所思愁，轉眼看天一長吐。"]'),
('da151296-2dd9-4980-b27c-d672c92fe922','長信宮二首 一','韓偓','唐','唐诗','tang','','[]','天上夢魂何杳杳，宮中消息太沈沈。',32,'全唐诗/poet.tang.38000.json','["天上夢魂何杳杳，宮中消息太沈沈。", "君恩不似黃金井，一處團圓萬丈深。"]'),
('c74c58df-6df8-4399-b5d2-a92b4bb2729d','長信宮二首 二','韓偓','唐','唐诗','tang','','[]','天上鳳皇休寄夢，人間鸚鵡舊堪悲。',32,'全唐诗/poet.tang.38000.json','["天上鳳皇休寄夢，人間鸚鵡舊堪悲。", "平生心緒無人識，一隻金梭萬丈絲。"]'),
('66b4d94f-7506-4350-a0e9-327f954acffa','句','韓偓','唐','唐诗','tang','','[]','豈獨鴟夷解歸去，五湖漁艇且餔糟。',16,'全唐诗/poet.tang.38000.json','["豈獨鴟夷解歸去，五湖漁艇且餔糟。"]'),
('b3d5593d-f7f3-40cc-a401-2c28eb612983','奉和御製','吳融','唐','唐诗','tang','','[]','嶽寺清秋霽，宸遊永日閑。',48,'全唐诗/poet.tang.38000.json','["嶽寺清秋霽，宸遊永日閑。", "霓旌森物外，鳳吹落人間。", "玉漱穿城水，屏開對闕山。", "皆知聖情悅，麗藻灑芳蘭。"]'),
('ad10e9c0-e632-4d90-be31-71113f75a3b3','和集賢相公西溪侍宴觀競渡','吳融','唐','唐诗','tang','','[]','片水聳層橋，祥煙靄慶霄。',48,'全唐诗/poet.tang.38000.json','["片水聳層橋，祥煙靄慶霄。", "晝花鋪廣宴，晴電閃飛橈。", "浪疊搖仙仗，風微定彩標。", "都人同盛觀，不覺在行朝。"]'),
('8e31332a-d1cd-4109-9b80-cf5e40c7f4e7','山居即事四首 一','吳融','唐','唐诗','tang','','[]','桂樹秋來風滿枝，碧巖歸日免乖期。',32,'全唐诗/poet.tang.38000.json','["桂樹秋來風滿枝，碧巖歸日免乖期。", "故人盡向蟾宮折，獨我攀條欲寄誰。"]'),
('561e0d19-381b-4b91-a283-4dcc5eaccb07','山居即事四首 二','吳融','唐','唐诗','tang','','[]','不傲南窗且採樵，乾松每帶溼雲燒。',32,'全唐诗/poet.tang.38000.json','["不傲南窗且採樵，乾松每帶溼雲燒。", "庖廚却得長兼味，三秀芝根五朮苗。"]'),
('971034f6-5ef7-4f17-b48a-999f5e3a8a96','山居即事四首 三','吳融','唐','唐诗','tang','','[]','萬事翛然只有棊，小軒高淨簟涼時。',32,'全唐诗/poet.tang.38000.json','["萬事翛然只有棊，小軒高淨簟涼時。", "闌珊半局和微醉，花落中庭樹影移。"]'),
('7f796c0c-a070-47e4-8aff-edb01d7e9495','山居即事四首 四','吳融','唐','唐诗','tang','','[]','無鄰無里不成村，水曲雲重掩石門。',32,'全唐诗/poet.tang.38000.json','["無鄰無里不成村，水曲雲重掩石門。", "何用深求避秦客，吾家便是武陵源。"]'),
('7933ada7-3c20-4dbe-be3c-b51f791b5c2e','紅白牡丹','吳融','唐','唐诗','tang','','[]','不必繁弦不必歌，靜中相對更情多。',64,'全唐诗/poet.tang.38000.json','["不必繁弦不必歌，靜中相對更情多。", "殷鮮一半霞分綺，潔澈旁邊月颭波。", "看久願成莊叟夢，惜留須倩魯陽戈。", "重來應共今來別，風墮香殘襯綠莎。"]'),
('980c7227-ba31-4795-b27f-f6c61265fe18','中秋陪熙用學士禁中翫月','吳融','唐','唐诗','tang','','[]','月圓年十二，秋半每多陰。',72,'全唐诗/poet.tang.38000.json','["月圓年十二，秋半每多陰。", "此夕無纖靄，同君宿禁林。", "未高知海闊，當午見宮深。", "衣似繁霜透，身疑積水沈。", "遭逢陪侍輦，歸去憶抽簪。", "太液池南岸，相期到曉吟。"]'),
('7ad7a0d5-22ed-4333-813b-22843bd3d9b1','題豪家故池','吳融','唐','唐诗','tang','','[]','歲久無泉引，春來仰雨流。',48,'全唐诗/poet.tang.38000.json','["歲久無泉引，春來仰雨流。", "萍枯黏朽檻，沙淺露沈舟。", "照影人何在，持竿客寄遊。", "翛然興廢外，回首謝眠鷗。"]'),
('d8ca9c81-6ddb-473d-b6f0-f6d55dc06abd','偶題','吳融','唐','唐诗','tang','','[]','賤子曾塵國士知，登門倒屣憶當時。',64,'全唐诗/poet.tang.38000.json','["賤子曾塵國士知，登門倒屣憶當時。", "西州酌盡看花酒，東閣編成詠雪詩。", "莫道精靈無伯有，尋聞任俠報爰絲。", "烏衣舊宅猶能認，粉竹金松一兩枝。"]'),
('2ef680f8-51df-4f6e-a6bd-7445a9e096ac','渚宮立春書懷','吳融','唐','唐诗','tang','','[]','春候侵殘臘，江蕪綠已齊。',48,'全唐诗/poet.tang.38000.json','["春候侵殘臘，江蕪綠已齊。", "風高鶯囀澁，雨密鴈飛低。", "向日心須在，歸朝路欲迷。", "近聞驚御火，猶及灞陵西。"]'),
('fc255ba0-86d7-4a2e-99c8-6bc598f4d785','聞李翰林遊池上有寄','吳融','唐','唐诗','tang','','[]','花飛絮落水和流，玉署詞臣奉詔遊。',64,'全唐诗/poet.tang.38000.json','["花飛絮落水和流，玉署詞臣奉詔遊。", "四面看人隨畫鷁，中流合樂起眠鷗。", "皇恩自抱丹心報，清頌誰將白雪酬。", "不爲禁鐘催入宿，前峰月上未回舟。"]'),
('c193e382-ac66-4672-a3a3-e5ef1da08cb5','谷口寓居偶題','吳融','唐','唐诗','tang','','[]','涔涔病骨怯朝天，谷口歸來取性眠。',48,'全唐诗/poet.tang.38000.json','["涔涔病骨怯朝天，谷口歸來取性眠。", "峭壁削成開畫障，急溪飛下咽繁弦。", "不能塵土爭閑事，且放形神學散仙。"]'),
('f9e722d0-0e22-4b14-972c-dafd77af8fbc','無題','吳融','唐','唐诗','tang','','[]','萬態千端一瞬中，沁園蕪沒佇秋風。',64,'全唐诗/poet.tang.38000.json','["萬態千端一瞬中，沁園蕪沒佇秋風。", "鵁鶄夜警池塘冷，蝙蝠晝飛樓閣空。", "粉貌早聞殘洛市，簫聲猶自傍秦宮。", "今朝陌上相非者，曾此歌鐘幾醉同。"]'),
('1e01a0f3-87f9-421a-b1bc-dd75a971d7dc','賦雪','吳融','唐','唐诗','tang','','[]','一夜陰風度，平明顥氣交。',120,'全唐诗/poet.tang.38000.json','["一夜陰風度，平明顥氣交。", "未知融結判，唯見混茫包。", "路莫藏行跡，林難出樹梢。", "氣應封獸穴，險必墮禽巢。", "影密燈回照，聲繁竹送敲。", "翫宜蘇讓點，飡稱蜜勻抄。", "結凍防魚躍，黏沙費馬跑。", "爐寒資爇荻，屋暖賴編茅。", "遠不分山疊，低宜失地坳。", "闌干高百尺，新霽若爲拋。"]'),
('1094f9b0-2b58-4678-ab6d-32f19fb2d589','寄僧','吳融','唐','唐诗','tang','','[]','柳拂池光一點清，紫方袍袖杖藜行。',64,'全唐诗/poet.tang.38000.json','["柳拂池光一點清，紫方袍袖杖藜行。", "偶傳新句來中禁，誰把閑書寄上卿。", "錫倚山根重蘚破，棊敲石面碎雲生。", "應憐正視淮王詔，不識東林物外情。"]'),
('a135efcf-8182-437f-9f34-c836901fc2cf','酬僧','吳融','唐','唐诗','tang','','[]','吾師既續惠休才，況值高秋萬象開。',64,'全唐诗/poet.tang.38000.json','["吾師既續惠休才，況值高秋萬象開。", "吟處遠峰橫落照，定中黃葉下青苔。", "雙林不見金蘭久，丹楚空翻組繡來。", "聞說近郊寒尚綠，登臨應待一追陪。"]'),
('69942c0b-dc1c-4037-b04e-99ddecf0b2b1','題延壽坊東南角古池','吳融','唐','唐诗','tang','','[]','蔓草蕭森曲岸摧，水籠沙淺露莓苔。',64,'全唐诗/poet.tang.38000.json','["蔓草蕭森曲岸摧，水籠沙淺露莓苔。", "更無蔟蔟紅妝點，猶有雙雙翠羽來。", "雨細幾逢耕犢去，日斜時見釣人回。", "繁華自古皆相似，金谷荒園土一堆。"]'),
('5befb939-b7d2-4293-b6d7-24877158917f','登鸛雀樓','吳融','唐','唐诗','tang','','[]','鳥在林梢脚底看，夕陽無際戍煙殘。',64,'全唐诗/poet.tang.38000.json','["鳥在林梢脚底看，夕陽無際戍煙殘。", "凍開河水奔渾急，雪洗條山錯落寒。", "始爲一名拋故國，近因多難怕長安。", "祖鞭掉折徒爲爾，贏得雲溪負釣竿。"]'),
('8fe0f461-7959-431c-8539-0562e39ab405','和峽州馮使君題所居','吳融','唐','唐诗','tang','','[]','三年拔薤成仁政，一日誅茅葺所居。',64,'全唐诗/poet.tang.38000.json','["三年拔薤成仁政，一日誅茅葺所居。", "曉岫近排吟閣冷，夜江遙響寢堂虛。", "唯懷避地逃多難，不羨朝天臥直廬。", "記得街西鄰舍否，投荒南去五千餘。"]'),
('2197313b-579a-4222-bf58-cf82dfc3673d','秋日感事','吳融','唐','唐诗','tang','','[]','一葉飄然夕照沈，世間何事不經心。',64,'全唐诗/poet.tang.38000.json','["一葉飄然夕照沈，世間何事不經心。", "幾人欲話雲臺峻，獨我方探禹穴深。", "雞檄固應無下策，鶴書還要問中林。", "自憐情爲多憂動，不爲西風白露吟。"]'),
('85215aad-a839-48d7-a8cc-1c06fd0f4c4d','鶯','吳融','唐','唐诗','tang','','[]','日落林西鳥未知，自先飛上最高枝。',64,'全唐诗/poet.tang.38000.json','["日落林西鳥未知，自先飛上最高枝。", "千啼萬語不離恨，已去又來如有期。", "慣識江南春早處，長驚薊北夢回時。", "謝家園裏成吟久，只欠池塘一句詩。"]'),
('4976cdbf-ffa4-44f1-9a43-4662518cafc3','次韻和王員外雜遊四韻','吳融','唐','唐诗','tang','','[]','一分難減亦難加，得似溪頭浣越紗。',64,'全唐诗/poet.tang.38000.json','["一分難減亦難加，得似溪頭浣越紗。", "兩槳慣邀催去艇，七香曾占取來車。", "黃昏忽墮當樓月，清曉休開滿鏡花。", "誰見玉郎腸斷處，露牀風簟半欹斜。"]'),
('edefb7be-8264-4ee2-a193-c94710f34e6d','秋事','吳融','唐','唐诗','tang','','[]','江天暑氣自涼清，物候須知一雨成。',64,'全唐诗/poet.tang.38000.json','["江天暑氣自涼清，物候須知一雨成。", "松竹健來唯欠語，蕙蘭衰去始多情。", "他年擬獻書空在，此日知機意盡平。", "更欲輕橈放煙浪，葦花深處睡秋聲。"]'),
('7662f254-11c8-460a-8afc-8f9f7fec66c6','和陸拾遺題諫院松','吳融','唐','唐诗','tang','','[]','落落孤松何處尋，月華西畔結根深。',64,'全唐诗/poet.tang.38000.json','["落落孤松何處尋，月華西畔結根深。", "曉含仙掌三清露，晚上宮牆百雉陰。", "野鶴不歸應有怨，白雲高去太無心。", "碧巖秋澗休相望，捧日元須在禁林。"]'),
('9cc8843a-e2c2-4983-83d6-a890c3600e32','題楊子津亭','吳融','唐','唐诗','tang','','[]','楊子江津十四經，紀行文字徧長亭。',64,'全唐诗/poet.tang.38000.json','["楊子江津十四經，紀行文字徧長亭。", "驚人旅鬢斬新白，無事海門依舊青。", "前路莫知霜凜凜，故鄉何處鴈冥冥。", "可憐不識生離者，數點漁帆落暮汀。"]'),
('102adf2f-8824-48fa-9cf9-0197e54fb1e8','閑望','吳融','唐','唐诗','tang','','[]','三點五點映山雨，一枝兩枝臨水花。',64,'全唐诗/poet.tang.38000.json','["三點五點映山雨，一枝兩枝臨水花。", "蛺蝶狂飛掠芳草，鴛鴦穩睡翹暖沙。", "闕下新居成別業，江南舊隱是誰家。", "東遷西去俱無計，却羨暝歸林上鴉。"]'),
('b8214e95-b4bb-4b94-ad52-0e8545196a9d','雪後過昭應','吳融','唐','唐诗','tang','','[]','路過章臺氣象寬，九重城闕在雲端。',64,'全唐诗/poet.tang.38000.json','["路過章臺氣象寬，九重城闕在雲端。", "煙含上苑沈沈紫，雪露南山悚悚寒。", "綺陌已堪騎寶馬，綠蕪行即彈金丸。", "灞川南北真圖畫，更待殘陽一望看。"]'),
('f3e783d1-64fe-4073-bb0e-03788183e8a1','商人','吳融','唐','唐诗','tang','','[]','百尺竿頭五兩斜，此生何處不爲家。',64,'全唐诗/poet.tang.38000.json','["百尺竿頭五兩斜，此生何處不爲家。", "北拋衡嶽南過鴈，朝發襄陽暮看花。", "蹭蹬也應無陸地，團圓應覺有天涯。", "隨風逐浪年年別，却笑如期八月槎。"]'),
('155181d2-f174-4e92-8e43-a09df28e9bf4','岐下聞杜鵑','吳融','唐','唐诗','tang','','[]','化去蠻鄉北，飛來渭水西。',72,'全唐诗/poet.tang.38000.json','["化去蠻鄉北，飛來渭水西。", "爲多亡國恨，不忍故山啼。", "怨已驚秦鳳，靈應識漢雞。", "數聲煙漠漠，餘思草萋萋。", "樓迥波無際，林昏日又低。", "如何不腸斷，家近五雲溪。"]'),
('28492d3c-f800-44f9-95c9-8962835d4f5e','雨後聞思歸樂二首 一','吳融','唐','唐诗','tang','','[]','山禽連夜叫，兼雨未嘗休。',48,'全唐诗/poet.tang.38000.json','["山禽連夜叫，兼雨未嘗休。", "儘道思歸樂，應多離別愁。", "我家方旅食，故國在滄洲。", "聞此不能寐，青燈茆屋幽。"]'),
('a9dc5713-5c0a-4c18-8cd7-236d7ca1f446','雨後聞思歸樂二首 二','吳融','唐','唐诗','tang','','[]','一夜鳥飛鳴，關關徹五更。',48,'全唐诗/poet.tang.38000.json','["一夜鳥飛鳴，關關徹五更。", "似因歸路隔，長使別魂驚。", "未省愁雨暗，就中傷月明。", "須知越吟客，欹枕不勝情。"]'),
('c36636be-e8b1-4495-8b08-2be3957f9468','中夜聞啼禽','吳融','唐','唐诗','tang','','[]','漠漠蒼蒼未五更，宿禽何處兩三聲。',64,'全唐诗/poet.tang.38000.json','["漠漠蒼蒼未五更，宿禽何處兩三聲。", "若非西澗回波觸，即是南塘急雨驚。", "金屋獨眠堪寄恨，商陵永訣更牽情。", "此時歸夢隨腸斷，半壁殘燈閃閃明。"]'),
('1f85220c-3b3a-4472-ad7b-cfea8c8f85cb','靈池縣見早梅','吳融','唐','唐诗','tang','','[]','小園晴日見寒梅，一寸鄉心萬里回。',64,'全唐诗/poet.tang.38000.json','["小園晴日見寒梅，一寸鄉心萬里回。", "春日暖時拋笠澤，戰塵飛處上琴臺。", "棲身未識登龍地，落筆元非倚馬才。", "待勒燕然歸未得，雪枝南畔少徘徊。"]'),
('71cf61e0-9d16-45f2-bb7f-d79f552965fd','野廟','吳融','唐','唐诗','tang','','[]','古原荒廟揜莓苔，何處喧喧鼓笛來。',32,'全唐诗/poet.tang.38000.json','["古原荒廟揜莓苔，何處喧喧鼓笛來。", "日暮鳥歸人散盡，野風吹起紙錢灰。"]'),
('78afbe5d-8ae9-4570-9466-db4c37cc8404','閑書','吳融','唐','唐诗','tang','','[]','接鷺陪鸞漫得羣，未如高臥紫溪雲。',64,'全唐诗/poet.tang.38000.json','["接鷺陪鸞漫得羣，未如高臥紫溪雲。", "晉陽起義尋常見，湖口屯營取次聞。", "大底鷦鵬須自適，何嘗玉石不同焚。", "回看帶礪山河者，濟得危時沒舊勳。"]'),
('140a427c-d1f3-4a0d-893a-0b26ef4aabfe','寄貫休上人','吳融','唐','唐诗','tang','','[]','別來如夢亦如雲，八字微言不復聞。',64,'全唐诗/poet.tang.38000.json','["別來如夢亦如雲，八字微言不復聞。", "世上浮沈應念我，筆端飛動只降君。", "幾同江步吟秋霽，更憶山房語夜分。", "見擬沃州尋舊約，且教丹頂許爲鄰。"]'),
('e6ad117c-a510-405e-aadf-8ae1fd000eb1','書懷','吳融','唐','唐诗','tang','','[]','傍巖依樹結簷楹，夏物蕭疎景更清。',64,'全唐诗/poet.tang.38000.json','["傍巖依樹結簷楹，夏物蕭疎景更清。", "灘響忽高何處雨，松陰自轉遠山晴。", "見多鄰犬遙相認，來慣幽禽近不驚。", "爭得便誇饒勝事，九衢塵裏免勞生。"]'),
('0dd1543b-b99d-4a07-b0f8-7dad85cc26a4','重陽日荆州作','吳融','唐','唐诗','tang','','[]','萬里投荒已自哀，高秋寓目更徘徊。',64,'全唐诗/poet.tang.38000.json','["萬里投荒已自哀，高秋寓目更徘徊。", "濁醪任冷難辭醉，黃菊因暄却未開。", "上國莫歸戎馬亂，故人何在塞鴻來。", "驚時感事俱無奈，不待殘陽下楚臺。"]'),
('432a0cf8-f143-4731-9bce-5f62304b8e5d','寄貫休','吳融','唐','唐诗','tang','','[]','休公何處在，知我宦情無。',48,'全唐诗/poet.tang.38000.json','["休公何處在，知我宦情無。", "已似馮唐老，方知武子愚。", "一身仍更病，雙闕又須趨。", "若得重相見，冥心學半銖。"]'),
('47d88d4b-45cd-484f-a39a-986c49e73a04','秋日渚宮即事','吳融','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','漠漠澹雲煙，秋歸澤國天。',48,'全唐诗/poet.tang.38000.json','["漠漠澹雲煙，秋歸澤國天。", "風高還促燕，雨細未妨蟬。", "靜引荒城望，涼驚旅枕眠。", "更堪憔悴裏，欲泛洞庭船。"]'),
('49fcfb7b-783e-4c1e-afdc-b20dd736468b','荆州寓居書懷','吳融','唐','唐诗','tang','','[]','一室四無鄰，荒郊接古津。',48,'全唐诗/poet.tang.38000.json','["一室四無鄰，荒郊接古津。", "幽閑消俗態，搖落露家貧。", "絕跡思浮海，修書嬾寄秦。", "東西不復問，翻笑泣岐人。"]'),
('30ed2ebd-c708-427e-af4f-52773ed704b1','和嚴諫議蕭山廟十韻','吳融','唐','唐诗','tang','','[]','澤國瞻遺廟，雲韶仰舊名。',120,'全唐诗/poet.tang.38000.json','["澤國瞻遺廟，雲韶仰舊名。", "一隅連障影，千仞落泉聲。", "老狖尋危棟，秋蛇束畫楹。", "路長資稅駕，歲儉絕豐盛。", "默默雖難測，昭昭本至平。", "豈知遷去客，自有復來兵。", "美舜歌徒作，欺堯犬正獰。", "近兼聞順動，敢復怨徂征。", "日出天須霽，風休海自清。", "肺腸無處說，一爲啓聰明。"]'),
('1806da88-cfad-40b2-9113-04d952bfc7cc','松江晚泊','吳融','唐','唐诗','tang','','[]','樹遠天疑盡，江奔地欲隨。',48,'全唐诗/poet.tang.38000.json','["樹遠天疑盡，江奔地欲隨。", "孤帆落何處，殘日更新離。", "客是淒涼本，情爲繫滯枝。", "寸腸無計免，應只楚猿知。"]'),
('2e338036-ab5b-4aa5-ae1f-61d0ba657aad','湖州溪樓書獻鄭員外','吳融','唐','唐诗','tang','','[]','危檻等飛檣，閑追晚際涼。',48,'全唐诗/poet.tang.38000.json','["危檻等飛檣，閑追晚際涼。", "青林上雨色，白鳥破溪光。", "目以高須極，心因靜更傷。", "唯公舊相許，早晚侍長楊。"]'),
('5c4bcd42-346f-4c65-b7a9-9e3fbeb67fc0','秋興','吳融','唐','唐诗','tang','','[]','微雨過菰葦，野居生早涼。',48,'全唐诗/poet.tang.38000.json','["微雨過菰葦，野居生早涼。", "襟期漸蕭灑，精爽欲飛揚。", "魚買罾頭活，酒沽船上香。", "不緣人不用，始道靜勝忙。"]'),
('d84844a8-3590-4fee-ae0f-595f965e9592','端居','吳融','唐','唐诗','tang','','[]','片雨過前汀，端居枕簟清。',48,'全唐诗/poet.tang.38000.json','["片雨過前汀，端居枕簟清。", "病魔隨暑退，詩思傍涼生。", "別燕殷勤語，殘蟬彷彿鳴。", "古來悲不盡，況我本多情。"]'),
('04a51f95-bc69-4ec3-b005-a7bb587a2e68','途中','吳融','唐','唐诗','tang','','[]','一棹歸何處，蒼茫落照昏。',48,'全唐诗/poet.tang.38000.json','["一棹歸何處，蒼茫落照昏。", "無人應失路，有樹始知春。", "湖岸春耕廢，江城戰鼓喧。", "儒冠解相悞，學劒盡乘軒。"]'),
('0b67941f-14f0-4f05-af82-65fb7b0d7117','西陵夜居','吳融','唐','唐诗','tang','','[]','寒潮落遠汀，暝色入柴扃。',48,'全唐诗/poet.tang.38000.json','["寒潮落遠汀，暝色入柴扃。", "漏永沈沈靜，燈孤的的清。", "林風移宿鳥，池雨定流螢。", "盡夜成愁絕，啼蛩莫近庭。"]'),
('3a8cf389-4d62-4d9f-8e16-f58fd310aa69','燕雛','吳融','唐','唐诗','tang','','[]','掠水身猶重，偎風力尚微。',48,'全唐诗/poet.tang.38000.json','["掠水身猶重，偎風力尚微。", "瓦苔難定立，簷雨忽喧歸。", "未識重溟遠，先愁一葉飛。", "銜泥在他日，兩兩占春暉。"]'),
('4e9353b6-0b23-4ef4-aaa1-5e05ba9965e9','新秋','吳融','唐','唐诗','tang','','[]','白髮又經秋，端居海上洲。',48,'全唐诗/poet.tang.38000.json','["白髮又經秋，端居海上洲。", "無機因事發，有涕爲時流。", "新酒乘涼壓，殘碁隔夜收。", "公車無路入，同拜老閑侯。"]'),
('920b6e26-923b-48ac-a994-0de9506eba9e','題越州法華寺','吳融','唐','唐诗','tang','','[]','寺在五峰陰，穿緣一徑尋。',48,'全唐诗/poet.tang.38000.json','["寺在五峰陰，穿緣一徑尋。", "雲藏古殿暗，石護小房深。", "宿鳥連僧定，寒猨應客吟。", "上方應見海，月出試登臨。"]'),
('bb743dbf-45dd-4eca-8051-8bb0bbb75348','寒食洛陽道','吳融','唐','唐诗','tang','','[]','路岐無樂處，時節倍思家。',48,'全唐诗/poet.tang.38000.json','["路岐無樂處，時節倍思家。", "綵索颺輕吹，黃鸝啼落花。", "連乹馳寶馬，歷祿鬬香車。", "行客勝回首，看看春日斜。"]'),
('6a353ed2-9ece-4023-8c05-ad76712839c8','憶事','吳融','唐','唐诗','tang','','[]','去年花下把金巵，曾賦楊花數句詩。',32,'全唐诗/poet.tang.38000.json','["去年花下把金巵，曾賦楊花數句詩。", "回首朱門閉荒草，如今愁到牡丹時。"]'),
('2b152319-c7f2-4993-8220-f606c6311d1e','金陵遇悟空上人','吳融','唐','唐诗','tang','','[]','東閣無人事渺茫，老僧持鉢過丹陽。',32,'全唐诗/poet.tang.38000.json','["東閣無人事渺茫，老僧持鉢過丹陽。", "十年栖止如何報，好與南譙剩炷香。"]'),
('38e9ed07-47ae-4d50-acb6-93bc2963783f','途中','吳融','唐','唐诗','tang','','[]','柳弱風長在，雲輕雨易休。',36,'全唐诗/poet.tang.38000.json','["柳弱風長在，雲輕雨易休。", "不勞芳草色，更惹夕陽愁。", "萬里獨歸去，五陵無與遊。"]'),
('c75b80a4-ff93-45ad-9098-52befa707174','秋園','吳融','唐','唐诗','tang','','[]','始憐春草細霏霏，不覺秋來綠漸稀。',32,'全唐诗/poet.tang.38000.json','["始憐春草細霏霏，不覺秋來綠漸稀。", "惆悵擷芳人散盡，滿園煙露蝶高飛。"]'),
('731da7dc-efe6-497e-a900-5e2a049c21c3','富春','吳融','唐','唐诗','tang','','[]','天下有水亦有山，富春山水非人寰。',32,'全唐诗/poet.tang.38000.json','["天下有水亦有山，富春山水非人寰。", "長川不是春來綠，千峰倒影落其間。"]'),
('75b2a1c1-5825-4e5e-b43b-487e4ce3ec60','山居即事','吳融','唐','唐诗','tang','','[]','小亭前面接青崖，白石交加襯綠苔。',32,'全唐诗/poet.tang.38000.json','["小亭前面接青崖，白石交加襯綠苔。", "日暮松聲滿階砌，不關風雨鶴歸來。"]'),
('8f88d4c6-9121-4cd4-b245-2bdc0d433522','寓言','吳融','唐','唐诗','tang','','[]','非明非暗朦朦月，不暖不寒慢慢風。',32,'全唐诗/poet.tang.38000.json','["非明非暗朦朦月，不暖不寒慢慢風。", "獨臥空牀好天氣，平生閑事到心中。"]'),
('699cb47c-9f13-4f5b-b43a-b0e7445bca50','華清宮二首 一','吳融','唐','唐诗','tang','','[]','四郊飛雪暗雲端，唯此宮中落旋乾。',32,'全唐诗/poet.tang.38000.json','["四郊飛雪暗雲端，唯此宮中落旋乾。", "綠樹碧簷相掩映，無人知道外邊寒。"]'),
('3f9bb1d5-eff7-4bfc-bc2e-9644b6190ff9','華清宮二首 二','吳融','唐','唐诗','tang','','[]','長生祕殿倚青蒼，擬敵金庭不死鄉。',32,'全唐诗/poet.tang.38000.json','["長生祕殿倚青蒼，擬敵金庭不死鄉。", "無奈逝川東去急，秦陵松柏滿殘陽。"]'),
('32a70ddb-ef27-4241-a6e5-7ca2612f7cfd','過九成宮','吳融','唐','唐诗','tang','','[]','鳳輦東歸二百年，九成宮殿半荒阡。',64,'全唐诗/poet.tang.38000.json','["鳳輦東歸二百年，九成宮殿半荒阡。", "魏公碑字封蒼蘚，文帝泉聲落野田。", "碧草斷霑仙掌露，綠楊猶憶御爐煙。", "昇平舊事無人說，萬疊青山但一川。"]'),
('5b01c696-0d47-4af5-9ed3-23d9a39b8fbc','出潼關','吳融','唐','唐诗','tang','','["\u534e\u5c71", "\u9ec4\u6cb3"]','重門隨地險，一徑入天開。',48,'全唐诗/poet.tang.38000.json','["重門隨地險，一徑入天開。", "華嶽眼前盡，黃河腳底來。", "飛軒何滿路，丹陛正求才。", "獨我疎慵質，飄然又此回。"]'),
('9493c2c0-8064-4199-9b05-8d3a6b0847da','過丹陽','吳融','唐','唐诗','tang','','[]','雲陽縣郭半郊坰，風雨蕭條萬古情。',64,'全唐诗/poet.tang.38000.json','["雲陽縣郭半郊坰，風雨蕭條萬古情。", "山帶梁朝陵路斷，水連劉尹宅基平。", "桂枝自折思前代，藻鑑難逢恥後生。", "遺事滿懷兼滿目，不堪孤棹艤荒城。"]'),
('308dfc63-7280-49c3-b9bb-fd99c5603fb9','和人題武城寺','吳融','唐','唐诗','tang','','[]','神清已覺三清近，目斷仍勞萬象牽。',64,'全唐诗/poet.tang.38000.json','["神清已覺三清近，目斷仍勞萬象牽。", "渭水遠含秋草渡，漢陵高枕夕陽天。", "半巖雲粉千竿竹，滿寺風雷百尺泉。", "別有闌干壓行路，看人塵土竟流年。"]'),
('bca9a51f-6a28-4503-861c-4e9ccc95d71d','長安里中聞猨','吳融','唐','唐诗','tang','','[]','夾巷重門似海深，楚猨爭得此中吟。',64,'全唐诗/poet.tang.38000.json','["夾巷重門似海深，楚猨爭得此中吟。", "一聲紫陌纔回首，萬里青山已到心。", "慣倚客船和雨聽，可堪侯第見塵侵。", "無因永夜聞清嘯，禁路人歸月自沈。"]'),
('43d34ba5-e506-443d-92f7-de044fdf2b9b','岐下聞子規','吳融','唐','唐诗','tang','','[]','劒閣西南遠鳳臺，蜀魂何事此飛來。',64,'全唐诗/poet.tang.38000.json','["劒閣西南遠鳳臺，蜀魂何事此飛來。", "偶因隴樹相迷至，唯恐邊風却送回。", "只有花知啼血處，更無猨替斷腸哀。", "誰憐越客曾聞處，月落江平曉霧開。"]'),
('8621f331-846e-41e2-a6d9-ec0f2e2517c3','敷水有丐者云是馬侍中諸孫憫而有贈','吳融','唐','唐诗','tang','','[]','天地塵昏九鼎危，大貂曾出武侯師。',64,'全唐诗/poet.tang.38000.json','["天地塵昏九鼎危，大貂曾出武侯師。", "一心忠赤山河見，百戰功名日月知。", "舊宅已聞栽禁樹，諸孫仍見丐征岐。", "而今不要教人識，正藉將軍死鬬時。"]'),
('b12ce4af-eeb1-4d5b-960f-f6a6f1fd891f','還俗尼','吳融','唐','唐诗','tang','','[]','柳眉梅額倩妝新，笑脫袈裟得舊身。',64,'全唐诗/poet.tang.38000.json','["柳眉梅額倩妝新，笑脫袈裟得舊身。", "三峽却爲行雨客，九天曾是散花人。", "空門付與悠悠夢，寶帳迎回暗暗春。", "寄語江南徐孝克，一生長短託清塵。"]'),
('4bdc6347-e805-4b89-b386-abbb796b1cfe','彭門用兵後經汴路三首 一','吳融','唐','唐诗','tang','','[]','長亭一望一徘徊，千里關河百戰來。',68,'全唐诗/poet.tang.38000.json','["長亭一望一徘徊，千里關河百戰來。", "細柳舊營猶鏁月，[祁]連新塚已封苔。", "霜凋綠野愁無際，燒接黃雲慘不開。", "若比江南更牢落，子山詞賦莫興[哀]。"]'),
('0b305db2-e155-4f70-993f-81084e4cc89a','彭門用兵後經汴路三首 二','吳融','唐','唐诗','tang','','[]','隋堤風物已淒涼，堤下仍多舊戰塲。',64,'全唐诗/poet.tang.38000.json','["隋堤風物已淒涼，堤下仍多舊戰塲。", "金鏃有苔人拾得，蘆花無主鳥銜將。", "秋聲暗促河聲急，野色遙連日色黃。", "獨上寒城正愁絕，戍鼙驚起鴈行行。"]'),
('e62efb3c-8e7c-47d1-93fe-9544f271107b','彭門用兵後經汴路三首 三','吳融','唐','唐诗','tang','','[]','鐵馬雲旗夢渺茫，東來無處不堪傷。',64,'全唐诗/poet.tang.38000.json','["鐵馬雲旗夢渺茫，東來無處不堪傷。", "風吹白草人行少，月落空城鬼嘯長。", "一自紛爭驚宇宙，可憐蕭索絕煙光。", "曾爲塞北閑遊客，遼水天山未斷腸。"]'),
('b7f04079-d6f1-441a-ba93-7f08da7c52ad','寄殿院高侍御','吳融','唐','唐诗','tang','','[]','黃梅雨細羃長洲，柳密花疎水慢流。',64,'全唐诗/poet.tang.38000.json','["黃梅雨細羃長洲，柳密花疎水慢流。", "釣艇正尋逋客去，繡衣方結少年遊。", "風前不肯看垂手，燈下還應惜裹頭。", "一夜自憐無羽翼，獨當何遜滴階愁。"]'),
('da73c615-65f3-4bd3-b486-979f19e20d3c','新安道中翫流水','吳融','唐','唐诗','tang','','[]','一渠春碧弄潺潺，密竹繁花掩映間。',64,'全唐诗/poet.tang.38000.json','["一渠春碧弄潺潺，密竹繁花掩映間。", "看處便須終日住，算來爭得此身閑。", "縈紆似接迷春洞，清冷應連有雪山。", "上却征車再回首，了然塵土不相關。"]'),
('0571ed01-a9b3-415e-9d4f-a3310f49272f','憶釣舟','吳融','唐','唐诗','tang','','[]','青山小隱枕潺湲，一葉垂綸幾泝沿。',64,'全唐诗/poet.tang.38000.json','["青山小隱枕潺湲，一葉垂綸幾泝沿。", "後浦春風隨興去，南塘秋雨有時眠。", "慣衝曉霧驚羣鴈，愛颭殘陽入亂煙。", "迴首無人寄惆悵，九衢塵土困揚鞭。"]'),
('c251522a-952a-4039-a4c6-16f8d50c8a96','靈寶縣西側津','吳融','唐','唐诗','tang','','[]','碧溪瀲瀲流殘陽，晴沙兩兩眠鴛鴦。',64,'全唐诗/poet.tang.38000.json','["碧溪瀲瀲流殘陽，晴沙兩兩眠鴛鴦。", "柳花無賴苦多暇，蛺蝶有情長自忙。", "千里宦遊成底事，每年風景是他鄉。", "高歌一曲垂鞭去，盡日無人識楚狂。"]'),
('39bdb2f4-6ce9-4873-ae3f-586600fd1b40','即席','吳融','唐','唐诗','tang','','[]','家住叢臺舊，名參絳圃新。',48,'全唐诗/poet.tang.38000.json','["家住叢臺舊，名參絳圃新。", "醉波疑奪燭，嬌態欲沈春。", "伴雨聊過楚，歸雲定占秦。", "桃花正濃暖，爭不浪迷人。"]'),
('e1f94995-cc31-466b-a87b-720371b4292c','出遲','吳融','唐','唐诗','tang','','[]','園密花藏易，樓深月到難。',48,'全唐诗/poet.tang.38000.json','["園密花藏易，樓深月到難。", "酒虛留客盡，燈暗遠更殘。", "麝想眉間印，鴉知頂上盤。", "文王之囿小，莫惜借人看。"]'),
('1413143a-3de1-4ebe-8ef2-ff510f9a2d6a','送僧歸日本國','吳融','唐','唐诗','tang','','[]','滄溟分故國，渺渺泛杯歸。',48,'全唐诗/poet.tang.38000.json','["滄溟分故國，渺渺泛杯歸。", "天盡終期到，人生此別稀。", "無風亦駭浪，未午已斜暉。", "繫帛何須鴈，金烏日日飛。"]'),
('ee6b36a3-3dfb-466c-b991-062409637b3c','送僧歸破山寺','吳融','唐','唐诗','tang','','[]','萬里指吳山，高秋杖錫還。',48,'全唐诗/poet.tang.38000.json','["萬里指吳山，高秋杖錫還。", "別來雙闕老，歸去片雲閑。", "師在有無外，我嬰塵土間。", "居然本相別，不要慘離顏。"]'),
('d59f9d54-5ea5-4712-abbe-53561449d069','夏夜有寄','吳融','唐','唐诗','tang','','[]','月上簟如水，軒高簾在鉤。',48,'全唐诗/poet.tang.38000.json','["月上簟如水，軒高簾在鉤。", "竹聲寒不夏，蛩思靜先秋。", "偶得清宵興，方知白日愁。", "所思何處遠，斜漢欲低流。"]'),
('60d50092-8ac3-4b56-8f56-58d00812d7ad','春詞','吳融','唐','唐诗','tang','','[]','鸞鏡長侵夜，鴛衾不識寒。',48,'全唐诗/poet.tang.38000.json','["鸞鏡長侵夜，鴛衾不識寒。", "羞多轉面語，妬極定睛看。", "金市舊居近，鈿車新造寬。", "春期莫相悞，一日百花殘。"]'),
('6896816c-ec5d-4cdc-a45d-bc26b9a77921','汴上晚泊','吳融','唐','唐诗','tang','','[]','亭上風猶急，橋邊月已斜。',48,'全唐诗/poet.tang.38000.json','["亭上風猶急，橋邊月已斜。", "柳寒難吐絮，浪濁不成花。", "岐路春三月，園林海一涯。", "蕭然正無寐，夜櫓莫咿啞。"]'),
('21309043-c1cd-4a5f-b03a-424206b0fe7e','送僧南遊','吳融','唐','唐诗','tang','','[]','戰鼙鳴未已，瓶屨抵何鄉。',48,'全唐诗/poet.tang.38000.json','["戰鼙鳴未已，瓶屨抵何鄉。", "偶別塵中易，貪歸物外忙。", "後蟬拋鄠杜，先鴈下瀟湘。", "不得從師去，殷勤謝草堂。"]'),
('c11c99f5-be8b-4633-bd1b-bd08f284b870','戲','吳融','唐','唐诗','tang','','[]','恨極同填海，情長抵導江。',48,'全唐诗/poet.tang.38000.json','["恨極同填海，情長抵導江。", "丁香從小結，蓮子徹枝雙。", "整髻花當檻，吹燈月在窗。", "秦臺非久計，早晚降霓幢。"]'),
('13cce0bf-eece-4fc2-9d95-a0d559cafa2a','雪中寄慮延讓秀才','吳融','唐','唐诗','tang','','[]','苦貧皆共雪，吾子豈同悲。',48,'全唐诗/poet.tang.38000.json','["苦貧皆共雪，吾子豈同悲。", "永日應無食，經宵必有詩。", "渚宮寒過節，華省試臨期。", "努力圖西去，休將凍餒辭。"]'),
('532dcb7b-5d14-41a9-9552-0419d49a2a1e','花村六韻','吳融','唐','唐诗','tang','','[]','地勝非離郭，花深故號村。',72,'全唐诗/poet.tang.38000.json','["地勝非離郭，花深故號村。", "已憐梁雪重，仍愧楚雲繁。", "山近當吟冷，泉高入夢喧。", "依稀小有洞，邂逅武陵源。", "月好頻移座，風輕莫閉門。", "流鶯更多思，百囀待黃昏。"]'),
('a49aa269-ecf3-40fb-97f1-1218103da124','賦雪十韻','吳融','唐','唐诗','tang','','[]','雨凍輕輕下，風乹淅淅吹。',120,'全唐诗/poet.tang.38000.json','["雨凍輕輕下，風乹淅淅吹。", "喜勝花發處，驚似客來時。", "河靜膠行棹，巖空響折枝。", "終無鷓鴣識，先有鶺鴒知。", "馬勢晨爭急，鵰聲晚更飢。", "替霜嚴柏署，藏月上龍墀。", "百尺樓堪倚，千錢酒要追。", "朝歸紫閣早，漏出建章遲。", "臘候何曾爽，春工是所資。", "遙知故溪柳，排比萬條絲。"]'),
('f50f695f-84ce-4b51-b0a9-3e2682494ce1','溪邊','吳融','唐','唐诗','tang','','[]','溪邊花滿枝，百鳥帶香飛。',24,'全唐诗/poet.tang.38000.json','["溪邊花滿枝，百鳥帶香飛。", "下有一白鷺，日斜翹石磯。"]'),
('58089e89-6a2c-4e3d-aa71-bbca468454a5','長安逢故人','吳融','唐','唐诗','tang','','[]','歲暮長安客，相逢酒一杯。',48,'全唐诗/poet.tang.38000.json','["歲暮長安客，相逢酒一杯。", "眼前閑事靜，心裏故山來。", "池影含新草，林芳動早梅。", "如何不歸去，霜鬢共風埃。"]'),
('855cf2f9-8db2-4020-b954-b6a5df58f59d','雨夜','吳融','唐','唐诗','tang','','[]','旅夕那禁雨，梅天已思秋。',48,'全唐诗/poet.tang.38000.json','["旅夕那禁雨，梅天已思秋。", "未明孤枕倦，相弔一燈愁。", "有戀慚滄海，無機奈白頭。", "何人得濃睡，溪上釣魚舟。"]'),
('4b4af768-a047-4477-9263-67644f607c20','旅中送遷客','吳融','唐','唐诗','tang','','[]','天南不可去，君去弔靈均。',36,'全唐诗/poet.tang.38000.json','["天南不可去，君去弔靈均。", "落日青山路，秋風白髮人。", "言危無繼者，道在有明神。"]'),
('58af8754-da51-4174-a12a-01fdb62d1438','寄尚顏師','吳融','唐','唐诗','tang','','[]','僧中難得靜，靜得是吾師。',48,'全唐诗/poet.tang.38000.json','["僧中難得靜，靜得是吾師。", "到闕不求紫，歸山秪愛詩。", "臨風翹雪足，向日剃霜髭。", "自歎眠漳久，雙林動所思。"]'),
('80eb4323-ac37-4940-8d29-415cb1152446','微雨','吳融','唐','唐诗','tang','','[]','天青織未徧，風急舞難成。',48,'全唐诗/poet.tang.38000.json','["天青織未徧，風急舞難成。", "粉重低飛蝶，黃沈不語鶯。", "自隨春靄亂，還放夕陽明。", "惆悵池塘上，荷珠點點傾。"]'),
('301f325c-d7bd-45e3-9fdb-45660088e2fc','送廣利大師東歸','吳融','唐','唐诗','tang','','[]','紫殿久霑恩，東歸過海門。',48,'全唐诗/poet.tang.38000.json','["紫殿久霑恩，東歸過海門。", "浮榮知是夢，輕別肯銷魂。", "明發先晨鳥，寒棲入暝猨。", "蕺山如重到，應老舊雲根。"]'),
('fd3e4c7a-3f0e-4da8-9c30-240dd4aee049','關東獻兵部劉員外','吳融','唐','唐诗','tang','','[]','昨夜星辰動，仙郎近漢關。',48,'全唐诗/poet.tang.38000.json','["昨夜星辰動，仙郎近漢關。", "玳筵吟雪罷，錦帳押春還。", "已到青雲上，應棲絳圃間。", "臨卭有詞賦，一爲奏天顏。"]'),
('bab6d24e-e3fa-4230-a33a-9829e08adbe5','途次淮口','吳融','唐','唐诗','tang','','[]','寒流萬派碧，南渡見煙光。',48,'全唐诗/poet.tang.38000.json','["寒流萬派碧，南渡見煙光。", "人向隋宮近，山盤楚塞長。", "有村皆綠暗，無徑不紅芳。", "已帶傷春病，如何更異鄉。"]'),
('5369ca74-bd04-4284-8309-468515269eab','詠柳','吳融','唐','唐诗','tang','','[]','自與鶯爲地，不教花作媒。',48,'全唐诗/poet.tang.38000.json','["自與鶯爲地，不教花作媒。", "細應和雨斷，輕秪愛風裁。", "好拂錦步障，莫遮銅雀臺。", "灞陵千萬樹，日暮別離回。"]'),
('431c53bb-cdd7-4dcb-a0de-b6fe758cc9f6','武牢關遇雨','吳融','唐','唐诗','tang','','[]','澤春關路迥，暮雨細霏霏。',48,'全唐诗/poet.tang.38000.json','["澤春關路迥，暮雨細霏霏。", "帶霧昏河浪，和塵重客衣。", "望中迷去騎，愁裏亂斜暉。", "惆悵家山遠，溟濛溼翠微。"]'),
('d0f65d64-837c-4159-b5ed-174064cfd0ce','春寒','吳融','唐','唐诗','tang','','[]','固教梅忍落，休與杏藏嬌。',48,'全唐诗/poet.tang.38000.json','["固教梅忍落，休與杏藏嬌。", "已過冬疑剩，將來暖未饒。", "玉堦殘雪在，羅薦暗魂銷。", "莫問王孫事，煙蕪正寂寥。"]'),
('824ddb5f-4277-439d-ab9a-88ee83e2cc18','早發潼關','吳融','唐','唐诗','tang','','[]','天邊月初落，馬上夢猶殘。',48,'全唐诗/poet.tang.38000.json','["天邊月初落，馬上夢猶殘。", "關樹蒼蒼曉，玉階澹澹寒。", "宦遊終自苦，身世靜堪觀。", "爭似山中隱，和雲枕碧湍。"]'),
('2c67a7e7-78b5-41b4-a306-46035781d325','送策上人','吳融','唐','唐诗','tang','','[]','昨來非有意，今去亦無心。',48,'全唐诗/poet.tang.38000.json','["昨來非有意，今去亦無心。", "闕下拋新院，江南指舊林。", "瓶添新澗綠，笠卸晚峰陰。", "八字如相許，終辭尺組尋。"]'),
('1ca8aa4e-b1fc-42c4-bb64-0efef2db7fe8','和諸學士秋夕禁直偶雪','吳融','唐','唐诗','tang','','[]','大華積秋雪，禁闈生夜寒。',48,'全唐诗/poet.tang.38000.json','["大華積秋雪，禁闈生夜寒。", "硯冰憂詔急，燈燼惜更殘。", "正遂攀稽願，翻追訪戴歡。", "更爲三日約，高興未將闌。"]'),
('f86334b8-70f2-4d47-9c84-73401a29ef70','御溝十六韻','吳融','唐','唐诗','tang','','[]','一水終南下，何年派作溝。',192,'全唐诗/poet.tang.38000.json','["一水終南下，何年派作溝。", "穿城初北注，過苑却東流。", "繞岸清波溢，連宮瑞氣浮。", "去應涵鳳沼，來必滲龍湫。", "激石珠爭碎，縈堤練不收。", "照花長樂曙，泛葉建章秋。", "影炫金莖表，光搖綺陌頭。", "旁沾畫眉府，斜入教簫樓。", "有雨難澄鏡，無萍易擲鉤。", "鼓宜堯女瑟，盪必蔡姬舟。", "臯著通鳴鶴，津應接斗牛。", "迴風還瀲瀲，和月更悠悠。", "淺憶觴堪泛，深思杖可投。", "秪懷涇合慮，不帶隴分愁。", "自有朝宗樂，曾無潰穴憂。", "不勞誇大漢，清渭貫神州。"]'),
('7fc091bf-83dd-498d-87e0-d82fd2575e0f','赴闕次留獻荆南成相公三十韻','吳融','唐','唐诗','tang','','[]','分閫兼文德，持衡有武功。',288,'全唐诗/poet.tang.38000.json','["分閫兼文德，持衡有武功。", "荆南知獨去，海內更誰同。", "拔地孤峰秀，當天一鶚雄。", "雲生五色筆，月吐六鈞弓。", "骨格凌秋聳，心源見底空。", "神清飡沆瀣，氣逸飲洪濛。", "臨事成奇策，全身仗至忠。", "解鞍欺李廣，煮弩笑臧洪。", "往昔逢多難，來茲故統戎。", "卓旗雲夢澤，撲火細腰宮。", "鏟土樓臺搆，連江雉堞籠。", "似平鋪掌上，疑湧出壺中。", "豈是勞人力，寧因役鬼工。", "本遺三戶在，今匝萬家通。", "畫舸橫青雀，危檣列綵虹。", "席飛巫峽雨，袖拂宋亭風。", "塲廣盤毬子，池閑引釣筒。", "禮賢金璧賤，煦物雪霜融。", "酒滿梁塵動，棊殘漏滴終。", "儉常資澹靜，貴絕恃穹崇。", "唯要臣誠顯，那求帝渥隆。", "甘棠名異奭，大樹姓非馮。", "自念爲遷客，方諧謁上公。", "痛知遭止棘，頻歎委飄蓬。"]'),
('2b12b96e-71fd-4dc7-8784-abbce41a332a','三峰府內矮柏十韻','吳融','唐','唐诗','tang','','[]','擢秀依黃閣，移根自碧岑。',120,'全唐诗/poet.tang.38000.json','["擢秀依黃閣，移根自碧岑。", "周圍雖合抱，直上豈盈尋。", "遠砌行窺頂，當庭坐庇陰。", "短堪驚衆木，高已讓他林。", "日轉無長影，風回有細音。", "不容蘿蔦附，只耐雪霜侵。", "玉帳籠應匝，牙旗倚更禁。", "葉低宜拂席，枝褭易抽簪。", "綠澗支離久，朱門掩映深。", "何須一千丈，方有歲寒心。"]'),
('683b61fa-9f91-4636-88b3-40cd02d821fa','雪十韻','吳融','唐','唐诗','tang','','[]','灑密蔽璇穹，霏霏杳莫窮。',120,'全唐诗/poet.tang.38000.json','["灑密蔽璇穹，霏霏杳莫窮。", "遲於雨到地，疾甚絮隨風。", "四野蒼茫際，千家晃朗中。", "夜迷三繞鵲，晝斷一行鴻。", "結片飛瓊樹，栽花點蘂宮。", "壅應邊盡北，填合海無東。", "高愛危峰積，低愁暖氣融。", "月交都浩渺，日射更𤫩瓏。", "送臘辭寒律，迎春入舊叢。", "自憐曾末至，聊復賦玄功。"]'),
('89e1d1ee-7095-4b56-ba08-813c351058a4','和睦州盧中丞題茅堂十韻','吳融','唐','唐诗','tang','','[]','有士當今重，忘情自古稀。',120,'全唐诗/poet.tang.38000.json','["有士當今重，忘情自古稀。", "獨開青嶂路，閑掩白雲扉。", "石累千層險，泉分一帶微。", "棟危猨競下，簷迥鳥爭歸。", "煙冷茶鐺靜，波香蘭舸飛。", "好移鍾阜蓼，莫種首陽薇。", "樹密含輕霧，川空漾薄暉。", "芝泥看只捧，蕙帶且休圍。", "東郭鄰穿履，西林近衲衣。", "瓊瑤一百字，千古見清機。"]'),
('e9b7eb07-737a-453c-9a42-b0c09c259227','奉和御製六韻','吳融','唐','唐诗','tang','','[]','天曉密雲開，亭亭翠葆來。',72,'全唐诗/poet.tang.38000.json','["天曉密雲開，亭亭翠葆來。", "芰荷籠水殿，楊柳蔽風臺。", "恩洽三時雨，歡騰萬歲雷。", "日華偏照御，星彩迥分台。", "葦岸縈仙棹，蓮峰倒玉杯。", "獨慚歌聖德，不是侍臣才。"]'),
('40fa7b5a-31dc-4c32-87d8-c7fb5afe22f1','敗簾六韻','吳融','唐','唐诗','tang','','[]','有客編來久，彌年斷不收。',72,'全唐诗/poet.tang.38000.json','["有客編來久，彌年斷不收。", "不堪風作候，豈復燕爲讐。", "盡見三重閣，難迷百尺樓。", "伴燈微揜夢，兼扇劣遮羞。", "零落亡珠綴，殷勤謝玉鉤。", "涼宵何必捲，月自入軒流。"]'),
('4a9e5cec-a7df-41a1-9141-f560b6c95109','玉堂種竹六韻','吳融','唐','唐诗','tang','','[]','當砌植檀欒，濃陰五月寒。',72,'全唐诗/poet.tang.38000.json','["當砌植檀欒，濃陰五月寒。", "引風穿玉牖，搖露滴金盤。", "有韻和宮漏，無香雜畹蘭。", "地疑雲鏁易，日近雪封難。", "靜稱圍棋會，閑宜閣筆看。", "他年終結實，不羨樹棲鸞。"]'),
('ddb70773-9fcf-40cd-8e39-bfd102d344b6','和韓致光侍郎無題三首十四韻 一','吳融','唐','唐诗','tang','','[]','珠佩元消暑，犀簪自辟塵。',168,'全唐诗/poet.tang.38000.json','["珠佩元消暑，犀簪自辟塵。", "揜燈容燕宿，開鏡待雞晨。", "去嬾都忘舊，來多未厭新。", "每逢憂是夢，長憶故延真。", "杏小雙圓壓，山濃兩點嚬。", "瘦難勝寶帶，輕欲馭飆輪。", "箆鳳金雕翼，釵魚玉鏤鱗。", "月明無睡夜，花落斷腸春。", "解舞何須楚，能箏可在秦。", "怯探同海底，稀遇極天津。", "綠柰攀宮豔，青梅弄嶺珍。", "管纖銀字咽，梭密錦書勻。", "厭勝還隨俗，無疑不避人。", "可憐三五夕，娬媚善爲鄰。"]'),
('f9affc77-e4c0-4d8d-a4c7-8f567ab51eca','和韓致光侍郎無題三首十四韻 二','吳融','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','舞轉輕輕雪，歌霏漠漠塵。',168,'全唐诗/poet.tang.38000.json','["舞轉輕輕雪，歌霏漠漠塵。", "漫遊多卜夜，慵起不知晨。", "玉箸和妝裛，金蓮逐步新。", "鳳笙追北里，鶴馭訪南真。", "有恨都無語，非愁亦有嚬。", "戲應過蚌浦，飛合入蟾輪。", "杯樣成言鳥，梳文解臥鱗。", "逢迎大堤晚，離別洞庭春。", "似玉曾誇趙，如雲不讓秦。", "錦收花上露，珠引月中津。", "木爲連枝貴，禽因比翼珍。", "萬峰酥點薄，五色繡妝勻。", "獺髓求魚客，鮫綃托海人。", "寸腸誰與達，洞府四無鄰。"]'),
('d47fa26c-04ed-494e-865b-a3fea9c78ee4','和韓致光侍郎無題三首十四韻 三','吳融','唐','唐诗','tang','','[]','綺閣臨初日，銅臺拂暗塵。',168,'全唐诗/poet.tang.38000.json','["綺閣臨初日，銅臺拂暗塵。", "鷾鴯偏報曉，烏鶂慣驚晨。", "魚網裁書數，鵾弦上曲新。", "病多疑厄重，語切見心真。", "子母錢徵笑，西南月借嚬。", "擣衣嫌獨杵，分袂怨雙輪。", "貝葉教丹觜，金刀寄赤鱗。", "捲簾吟塞雪，飛楫渡江春。", "解織宜名蕙，能歌合姓秦。", "眼穿回鴈嶺，魂斷飲牛津。", "藥自偷來絕，香從竊去珍。", "茗煎雲沫聚，藥種玉苗勻。", "草密應迷客，花繁好避人。", "長干足風雨，遙夜與誰鄰。"]'),
('a8d85779-981b-4eb9-8607-ffc4348cf6e0','倒次元韻','吳融','唐','唐诗','tang','','[]','南陌來尋伴，東城去卜鄰。',168,'全唐诗/poet.tang.38000.json','["南陌來尋伴，東城去卜鄰。", "生憎無賴客，死憶有情人。", "似束腰支細，如描髮彩勻。", "黃鸝裁帽貴，紫燕刻釵珍。", "身近從淄右，家元接觀津。", "雨臺誰屬楚，花洞不知秦。", "淚滴空牀冷，妝濃滿鏡春。", "枕涼欹琥珀，簟潔展麒麟。", "茂苑廊千步，昭陽扇九輪。", "陽城迷處笑，京兆畫時嚬。", "魚子封牋短，蠅頭學字真。", "易判期已遠，難諱事還新。", "艇子愁衝夜，驪駒怕拂晨。", "如何斷岐路，免得見行塵。"]'),
('88ed0282-d420-437a-ae6d-cde935675129','箇人三十韻','吳融','唐','唐诗','tang','','[]','嫋嫋復盈盈，何年墜玉京。',288,'全唐诗/poet.tang.38000.json','["嫋嫋復盈盈，何年墜玉京。", "見人還道姓，羞客不稱名。", "故事諳金谷，新居近石城。", "臉橫秋水溢，眉拂遠山晴。", "粉薄塗雲母，簪寒篸水晶。", "催來兩槳送，怕起五絲縈。", "髻學盤桓綰，牀依宛轉成。", "博山凝霧重，油壁隱車輕。", "額點梅花樣，心通棘刺情。", "搔頭邀顧遇，約指到平生。", "魚網徐徐襞，螺巵淺淺傾。", "芙蓉褥已展，荳蔻水休更。", "趙女憐膠膩，丁娘愛燭明。", "炷香龍薦腦，辟魘虎輸精。", "管咽參差韻，弦嘈倰僜聲。", "花殘春寂寂，月落漏丁丁。", "柳絮聯章敏，椒花屬思清。", "剪羅成彩字，銷蠟脫珠纓。", "邂逅當投珮，難難莫拊楹。", "熨來身熱定，舐得面痕平。", "匣鏡金螭怒，簾旌繡獸獰。", "頸長堪鶴並，腰細任蜂爭。", "滴淚泉饒竭，論心石未貞。", "必雙成鳳去，豈獨化蟬鳴。"]'),
('988d4e4c-b46a-4e42-8f82-2bfcdeb4ba05','即席十韻','吳融','唐','唐诗','tang','','[]','住處方窺宋，平生未嫁盧。',120,'全唐诗/poet.tang.38000.json','["住處方窺宋，平生未嫁盧。", "暖金輕鑄骨，寒玉細凝膚。", "妬蜨長成伴，傷鸞耐得孤。", "城堪迷下蔡，臺合上姑蘇。", "弄眼難降柳，含茸欲鬬蒲。", "生涼雲母扇，直夜博山爐。", "翡翠交妝鏡，鴛鴦入畫圖。", "無心同石轉，有淚約泉枯。", "猨渴應須見，鷹飢秪待呼。", "銀河正清淺，霓節過來無。"]'),
('6536e3da-09c7-42c0-814f-2552d0ea55ea','追詠棠梨花十韻','吳融','唐','唐诗','tang','','[]','蜀地從來勝，棠梨第一花。',120,'全唐诗/poet.tang.38000.json','["蜀地從來勝，棠梨第一花。", "更應無軟弱，別自有妍華。", "不貴綃爲霧，難降綺作霞。", "移須歸紫府，駐合餌丹砂。", "密映彈琴宅，深藏賣酒家。", "夜宜紅蠟照，春稱錦筵遮。", "連廟魂棲望，飄江字繞巴。", "未饒酥點薄，兼妬雪飛斜。", "舊賞三年斷，新期萬里賒。", "長安如種得，誰定牡丹誇。"]'),
('bfd20637-e286-4bf7-a284-ab7539fec822','緜竹山四十韻','吳融','唐','唐诗','tang','','[]','緜竹東西隅，千峰勢相屬。',288,'全唐诗/poet.tang.38000.json','["緜竹東西隅，千峰勢相屬。", "崚嶒壓東巴，連延羅古蜀。", "方者露圭角，尖者鑽箭簇。", "引者蛾眉彎，斂者鳶肩縮。", "尾蟉青蛇盤，頸低玄兔伏。", "橫來突若奔，直上森如束。", "歲在作噩年，銅梁搖蠆毒。", "相國京兆公，九命來作牧。", "戎提虎僕毛，專奉狼頭纛。", "行府寄精廬，開窗對林麓。", "是時重陽後，天氣曠清肅。", "茲山昏曉開，一一在人目。", "霜空正泬寥，濃翠霏撲撲。", "披海出珊瑚，貼天堆碧玉。", "俄然陰霾作，城郭纔霢霂。", "絕頂已凝雪，晃朗開紅旭。", "初疑崑崙下，夭矯龍銜燭。", "亦似蓬萊巔，金銀臺疊蹙。", "紫霞或旁映，綺段鋪繁褥。", "晚照忽斜籠，赤城差斷續。", "又如煮吳鹽，萬萬盆初熟。", "又如濯楚練，千千匹未軸。", "又如水晶宮，蛟螭結川瀆。", "又如鐘乳洞，電雷開巖谷。"]'),
('1317c2c5-2a60-4fd7-a82e-6dd6f012392c','祝風三十二韻','吳融','唐','唐诗','tang','','[]','我有二頃田，長洲東百里。',288,'全唐诗/poet.tang.38000.json','["我有二頃田，長洲東百里。", "環塗爲之區，積葑相連纚。", "松江流其旁，春夏多苦水。", "隄防苟不時，汎濫即無已。", "粤余病眠久，而復家無峙。", "田峻不勝荒，農功皆廢弛。", "他稼已如雲，我田方欲蒔。", "四際上通波，兼之葭與葦。", "是時立秋後，煙露浩淒矣。", "雖然遣畢功，萎約都無幾。", "如何海上風，連日從空起。", "似欲驅滄溟，來沃具區裏。", "噫嘻爾風師，吳中多豪士。", "囷倉過九年，一粒惜如死。", "糴賤兼糶貴，凶年翻大喜。", "只是疲羸苦，纔飢須易子。", "余仍轗軻者，進趨年二紀。", "秋不安一食，春不閑一晷。", "腸迴爲多別，骨瘦因積毀。", "咳唾莫逢人，揶揄空覩鬼。", "中又值干戈，遑遑常轉徙。", "故隱茅山西，今來笠澤涘。", "荒者不復尋，葺者還有以。", "將正陶令巾，又蓋姜肱被。"]'),
('f93e4cf1-2aa8-48b1-9400-1d8bd8615c45','金陵懷古','吳融','唐','唐诗','tang','','[]','玉樹聲沉戰艦收，萬家冠蓋入中州。',32,'全唐诗/poet.tang.38000.json','["玉樹聲沉戰艦收，萬家冠蓋入中州。", "秪應江令偏惆悵，頭白歸來是客遊。"]'),
('4199478c-c61d-415d-910f-d1de38fb3ed9','涼思','吳融','唐','唐诗','tang','','[]','松間小檻接波平，月澹煙沉暑氣清。',32,'全唐诗/poet.tang.38000.json','["松間小檻接波平，月澹煙沉暑氣清。", "半夜水禽棲不定，綠荷風動露珠傾。"]'),
('cf6665a9-dd07-4fd8-a1d6-12dde74e5a87','鮫綃','吳融','唐','唐诗','tang','','[]','雲供片段月供光，貧女寒機枉自忙。',32,'全唐诗/poet.tang.38000.json','["雲供片段月供光，貧女寒機枉自忙。", "莫道不蠶能致此，海邊何事有扶桑。"]'),
('ad519c9b-65bb-4e76-96cb-7dba9f353e56','潮','吳融','唐','唐诗','tang','','[]','暮去朝來無定期，桑田長被此聲移。',32,'全唐诗/poet.tang.38000.json','["暮去朝來無定期，桑田長被此聲移。", "蓬萊若探人間事，一日還應兩度知。"]'),
('db650c96-dbd9-4ad8-aba3-f0255bafa6bb','忘憂花','吳融','唐','唐诗','tang','','[]','繁紅落盡始淒涼，直道忘憂也未忘。',32,'全唐诗/poet.tang.38000.json','["繁紅落盡始淒涼，直道忘憂也未忘。", "數朵殷紅似春在，春愁特此繫人腸。"]'),
('d25e2ba6-5ef3-4792-a40b-bcabe8b5fad3','憶街西所居','吳融','唐','唐诗','tang','','[]','衡門一別夢難稀，人欲歸時不得歸。',32,'全唐诗/poet.tang.38000.json','["衡門一別夢難稀，人欲歸時不得歸。", "長憶去年寒食夜，杏花零落雨霏霏。"]'),
('e78d95db-88c4-4cce-ae43-502a9cf411b9','雲','吳融','唐','唐诗','tang','','[]','南北東西似客身，遠峰高鳥自爲鄰。',32,'全唐诗/poet.tang.38000.json','["南北東西似客身，遠峰高鳥自爲鄰。", "清歌一曲猶能住，莫道無心勝得人。"]'),
('b5c91611-3e11-4c02-9b86-4c718d7daa26','華清宮四首 一','吳融','唐','唐诗','tang','','[]','中原無鹿海無波，鳳輦鸞旗出幸多。',32,'全唐诗/poet.tang.38000.json','["中原無鹿海無波，鳳輦鸞旗出幸多。", "今日故宮歸寂寞，太平功業在山河。"]'),
('16290bfa-6b38-45eb-9f07-3f3fb4138bcc','華清宮四首 二','吳融','唐','唐诗','tang','','[]','漁陽烽火照函關，玉輦怱怱下此山。',32,'全唐诗/poet.tang.38000.json','["漁陽烽火照函關，玉輦怱怱下此山。", "一曲羽衣聽不盡，至今遺恨水潺潺。"]'),
('8f74d2ec-e789-4d9d-b287-10b5c62bef3f','華清宮四首 三','吳融','唐','唐诗','tang','','[]','上皇鑾輅重巡遊，雨淚無言獨倚樓。',32,'全唐诗/poet.tang.38000.json','["上皇鑾輅重巡遊，雨淚無言獨倚樓。", "惆悵眼前多少事，落花明月滿宮秋。"]'),
('4b406617-b0e3-4520-81d3-1491d9e52265','華清宮四首 四','吳融','唐','唐诗','tang','','[]','別殿和雲鏁翠微，太真遺像夢依依。',32,'全唐诗/poet.tang.38000.json','["別殿和雲鏁翠微，太真遺像夢依依。", "玉皇揜淚頻惆悵，應歎僧繇彩筆飛。"]'),
('a3ca1487-3b1b-4758-9244-dc908801e780','陳琳墓','吳融','唐','唐诗','tang','','[]','冀州飛檄傲英雄，却把文辭事鄴宮。',32,'全唐诗/poet.tang.38000.json','["冀州飛檄傲英雄，却把文辭事鄴宮。", "縱道筆端由我得，九泉何面見袁公。"]'),
('a6d44c76-2b29-42d5-9bbb-2f59cd4b1b5b','湖州朝陽樓','吳融','唐','唐诗','tang','','[]','十二亭亭占曉光，隋家浪說有迷藏。',32,'全唐诗/poet.tang.38000.json','["十二亭亭占曉光，隋家浪說有迷藏。", "仲宣題盡平生恨，別處應難看屋梁。"]'),
('8bad5a2d-9790-415f-b9e9-38b2765d43b7','賣花翁','吳融','唐','唐诗','tang','','["\u5199\u82b1", "\u82b1", "\u6124\u6168", "\u8bbd\u523a"]','和煙和露一叢花，擔入宮城許史家。',32,'全唐诗/poet.tang.38000.json','["和煙和露一叢花，擔入宮城許史家。", "惆悵東風無處說，不教閑地著春華。"]'),
('bfb999ea-940f-4788-a12d-05fea10aac19','自諷','吳融','唐','唐诗','tang','','[]','世路升沉合自安，故人何必苦相干。',32,'全唐诗/poet.tang.38000.json','["世路升沉合自安，故人何必苦相干。", "塗窮始解東歸去，莫過嚴光七里灘。"]'),
('b54bb539-eacf-4d78-b004-ad4575ec6e68','送杜鵑花','吳融','唐','唐诗','tang','','[]','春紅始謝又秋紅，息國亡來入楚宮。',32,'全唐诗/poet.tang.38000.json','["春紅始謝又秋紅，息國亡來入楚宮。", "應是蜀冤啼不盡，更憑顏色訴西風。"]'),
('22caca27-1d3c-44f6-ac3f-6caeed9237f8','西京道中聞蛙','吳融','唐','唐诗','tang','','[]','雨餘林外夕煙沉，忽有蛙聲伴客吟。',32,'全唐诗/poet.tang.38000.json','["雨餘林外夕煙沉，忽有蛙聲伴客吟。", "莫怪聞時倍惆悵，稚圭蓬蓽在山陰。"]'),
('ea914d98-f82d-4028-b5f5-3bc2c1a2ccf9','情','吳融','唐','唐诗','tang','','[]','依依脈脈兩如何，細以輕絲渺似波。',32,'全唐诗/poet.tang.38000.json','["依依脈脈兩如何，細以輕絲渺似波。", "月不長圓花易落，一生惆悵爲伊多。"]'),
('b1b86671-8f81-43b4-b33c-6e035ae072db','送荆南從事之岳州','吳融','唐','唐诗','tang','','[]','秋拂湖光一鏡開，庾郎蘭棹好徘徊。',32,'全唐诗/poet.tang.38000.json','["秋拂湖光一鏡開，庾郎蘭棹好徘徊。", "遙知月落酒醒處，五十弦從波上來。"]'),
('b4c4b22f-0eb0-4d8e-b90c-5cc1a00cc1c1','渡淮作','吳融','唐','唐诗','tang','','[]','紅杏花時辭漢苑，黃梅雨裏上淮船。',32,'全唐诗/poet.tang.38000.json','["紅杏花時辭漢苑，黃梅雨裏上淮船。", "雨迎花送長如此，辜負東風十四年。"]'),
('3b9501af-9e1c-4ea9-871e-52983a1e4865','薛舍人見徵恩賜香幷二十八字同寄','吳融','唐','唐诗','tang','','[]','往歲知君侍武皇，今來何用紫羅囊。',32,'全唐诗/poet.tang.38000.json','["往歲知君侍武皇，今來何用紫羅囊。", "都緣有意重熏裛，更灑江毫上玉堂。"]'),
('8d75c518-575c-49cb-9a00-7f3da85f0267','王母廟','吳融','唐','唐诗','tang','','[]','鸞龍一夜降崑丘，遺廟千年枕碧流。',32,'全唐诗/poet.tang.38000.json','["鸞龍一夜降崑丘，遺廟千年枕碧流。", "賺得武皇心力盡，忍看煙草茂陵秋。"]'),
('8a57e32b-96a5-4641-873c-2370d86bb7d3','塗中阻風','吳融','唐','唐诗','tang','','[]','洛陽寒食苦多風，掃蕩春華一半空。',32,'全唐诗/poet.tang.38000.json','["洛陽寒食苦多風，掃蕩春華一半空。", "莫道芳蹊盡成實，野花猶有未開叢。"]'),
('af025fce-852f-4477-bc67-e45cef5eb586','楚事','吳融','唐','唐诗','tang','','[]','悲秋應亦抵傷春，屈宋當年並楚臣。',32,'全唐诗/poet.tang.38000.json','["悲秋應亦抵傷春，屈宋當年並楚臣。", "何事從來好時節，只將惆悵付詞人。"]'),
('3b3edd49-5fac-449f-8060-07ae88624309','和僧詠牡丹','吳融','唐','唐诗','tang','','[]','萬緣銷盡本無心，何事看花恨却深。',32,'全唐诗/poet.tang.38000.json','["萬緣銷盡本無心，何事看花恨却深。", "都是支郎足情調，墜香殘蘂亦成吟。"]'),
('0178729a-7e9a-4238-9db4-70bea1455d61','豫讓','吳融','唐','唐诗','tang','','[]','韓魏同謀反覆深，晉陽三板免成沉。',32,'全唐诗/poet.tang.38000.json','["韓魏同謀反覆深，晉陽三板免成沉。", "趙衰當面何須恨，不把干將訪負心。"]'),
('26522520-569d-4c06-aa0f-f4d25a752a7a','和寄座主尚書','吳融','唐','唐诗','tang','','[]','偶逢戎旅戰爭日，豈是明時放逐臣。',32,'全唐诗/poet.tang.38000.json','["偶逢戎旅戰爭日，豈是明時放逐臣。", "不用裁詩苦惆悵，風雷看起臥龍身。"]'),
('4af3d293-ce4a-429d-8379-2817324713ea','江行','吳融','唐','唐诗','tang','','[]','霞低水遠碧翻紅，一棹無邊落照中。',32,'全唐诗/poet.tang.38000.json','["霞低水遠碧翻紅，一棹無邊落照中。", "說示北人應不愛，錦遮泥健馬追風。"]'),
('c6fa7080-e886-4483-8b35-2ad8065c26e6','旅館梅花','吳融','唐','唐诗','tang','','[]','清香無以敵寒梅，可愛他鄉獨看來。',32,'全唐诗/poet.tang.38000.json','["清香無以敵寒梅，可愛他鄉獨看來。", "爲憶故溪千萬樹，幾年辜負雪中開。"]'),
