('35814ca2-e6f2-46fe-a6f8-1c9f58da10b7','草','吳融','唐','唐诗','tang','','[]','染亦不可成，畫亦不可得。',24,'全唐诗/poet.tang.38000.json','["染亦不可成，畫亦不可得。", "萇弘未死時，應無此顏色。"]'),
('d665aee6-1b82-4352-ac73-ff5f923cf875','和楊侍郎','吳融','唐','唐诗','tang','','[]','目極家山遠，身拘禁苑深。',24,'全唐诗/poet.tang.38000.json','["目極家山遠，身拘禁苑深。", "煙霄慙暮齒，麋鹿媿初心。"]'),
('5dc59696-dfed-4718-80c2-1330d1688fe0','山居喜友人相訪','吳融','唐','唐诗','tang','','[]','秋雨空山夜，非君不此來。',24,'全唐诗/poet.tang.38000.json','["秋雨空山夜，非君不此來。", "高於剡溪雪，一棹到門回。"]'),
('5324cda3-d2f4-4903-a0cc-caa371b779a5','遠山','吳融','唐','唐诗','tang','','[]','隱隱隔千里，巍巍知幾重。',24,'全唐诗/poet.tang.38000.json','["隱隱隔千里，巍巍知幾重。", "平時未能去，夢斷一聲鐘。"]'),
('b9b80bd8-7452-4707-804d-37052e15f35d','江樹','吳融','唐','唐诗','tang','','[]','終日衝奔浪，何年墜亂風。',24,'全唐诗/poet.tang.38000.json','["終日衝奔浪，何年墜亂風。", "謝公堪入詠，目極在雲中。"]'),
('b1ad73ed-0422-41aa-a546-d474fe77ad76','薔薇','吳融','唐','唐诗','tang','','[]','萬卉春風度，繁花夏景長。',24,'全唐诗/poet.tang.38000.json','["萬卉春風度，繁花夏景長。", "館娃人盡醉，西子始新妝。"]'),
('67315f65-c655-4657-a130-79083e9a1710','梅雨','吳融','唐','唐诗','tang','','[]','渾開又密望中迷，乳燕歸遲粉竹低。',64,'全唐诗/poet.tang.38000.json','["渾開又密望中迷，乳燕歸遲粉竹低。", "撲地暗來飛野馬，舞風斜去散醯雞。", "初從滴瀝妨琴榭，漸到潺湲繞藥畦。", "少傍海邊飄泊處，中庭自有兩犁泥。"]'),
('1de71c0e-db4c-490e-9a46-60d16c6e3d06','登途懷友人','吳融','唐','唐诗','tang','','[]','日落野原秀，雨餘雲物閑。',48,'全唐诗/poet.tang.38000.json','["日落野原秀，雨餘雲物閑。", "清時正愁絕，高處正躋攀。", "京洛遙天外，江河戰鼓間。", "孤懷欲誰寄，應望塞鴻還。"]'),
('c92652ee-7b02-4711-b529-cd236ffcf699','聞蟬','吳融','唐','唐诗','tang','','[]','夏在先催過，秋賒已被迎。',48,'全唐诗/poet.tang.38000.json','["夏在先催過，秋賒已被迎。", "自應人不會，莫道物無情。", "木葉縱未落，鬢絲還易生。", "西風正相亂，休上夕陽城。"]'),
('840a4e36-23e9-4d3c-8ef8-2e931fbd0b65','秋色','吳融','唐','唐诗','tang','','[]','染不成乾畫未銷，霏霏拂拂又迢迢。',32,'全唐诗/poet.tang.38000.json','["染不成乾畫未銷，霏霏拂拂又迢迢。", "曾從建業城邊路，蔓草寒煙鏁六朝。"]'),
('256c3267-b5bd-4ee5-afdf-e5c635f0156b','自諷','吳融','唐','唐诗','tang','','[]','本是滄洲把釣人，無端三署接清塵。',32,'全唐诗/poet.tang.38000.json','["本是滄洲把釣人，無端三署接清塵。", "從來不解長流涕，也渡湘灕作逐臣。"]'),
('a8f52307-eaa9-4187-a33a-08ad6448a3ee','宿青雲驛','吳融','唐','唐诗','tang','','[]','蒼黃負譴走商顏，保得微躬出武關。',32,'全唐诗/poet.tang.38000.json','["蒼黃負譴走商顏，保得微躬出武關。", "今夜青雲驛前月，伴吟應到落西山。"]'),
('6fa956bc-e4e4-4f6e-a05a-4ff9791a7071','秋聞子規','吳融','唐','唐诗','tang','','[]','年年春恨化冤魂，血染枝紅壓疊繁。',32,'全唐诗/poet.tang.38000.json','["年年春恨化冤魂，血染枝紅壓疊繁。", "正是西風花落盡，不知何處認啼痕。"]'),
('2f7f1795-8d5b-4155-86f3-c69edf9f1c44','荆南席上聞歌','吳融','唐','唐诗','tang','','[]','迎愁歛黛一聲分，弔屈江邊日暮聞。',32,'全唐诗/poet.tang.38000.json','["迎愁歛黛一聲分，弔屈江邊日暮聞。", "何事遏雲翻不定，自緣蹤跡愛行雲。"]'),
('16f1bd48-e70c-44f1-a5a3-db0560d6fdfe','武關','吳融','唐','唐诗','tang','','[]','時來時去若循環，雙闔平雲謾鏁山。',64,'全唐诗/poet.tang.38000.json','["時來時去若循環，雙闔平雲謾鏁山。", "祗道地教秦設險，不知天與漢爲關。", "貪生莫作千年計，到了都成一夢閑。", "爭得便如岩下水，從他興廢自潺潺。"]'),
('13853a21-9a33-4abe-8dda-7ba0b2c3b1b8','月夕追事','吳融','唐','唐诗','tang','','[]','曾聽豪家碧玉歌，雲牀冰簟落秋河。',64,'全唐诗/poet.tang.38000.json','["曾聽豪家碧玉歌，雲牀冰簟落秋河。", "月臨高閣簾無影，風過迴廊幕有波。", "屈指盡隨雲雨散，滿頭贏得雪霜多。", "此時空見清涼影，來伴蛩聲咽砌莎。"]'),
('fe7f6888-5e55-45cf-83c0-c3c7bc0ff94b','上陽宮辭','吳融','唐','唐诗','tang','','[]','苑路青青半是苔，翠華西去未知回。',64,'全唐诗/poet.tang.38000.json','["苑路青青半是苔，翠華西去未知回。", "景陽春漏無人報，太液秋波有雁來。", "單影可堪明月照，紅顏無奈落花催。", "誰能賦得長門事，不惜千金奉酒桮。"]'),
('f609f2a2-22fe-4be2-9c32-5aadaa8bc2ef','送于員外歸隱藍田','吳融','唐','唐诗','tang','','[]','曾吟工部兩峰寒，今日星郎得挂冠。',64,'全唐诗/poet.tang.38000.json','["曾吟工部兩峰寒，今日星郎得挂冠。", "吾道不行歸始是，世情如此住應難。", "圍棋已訪生雲石，把釣先尋急雨灘。", "若遇秦時雪髯客，紫芝兼可備朝餐。"]'),
('3dc4dedc-1ff3-4895-8624-187266377cc0','廢宅','吳融','唐','唐诗','tang','','[]','風飄碧瓦雨摧垣，却有隣人與鏁門。',64,'全唐诗/poet.tang.38000.json','["風飄碧瓦雨摧垣，却有隣人與鏁門。", "幾樹好花閑白晝，滿庭荒草易黃昏。", "放魚池涸蛙爭聚，棲燕梁空雀自喧。", "不獨淒涼眼前事，咸陽一火便成原。"]'),
('17b69912-19ef-4f95-8b46-ea2fd9eb3cb2','湖州晚望','吳融','唐','唐诗','tang','','[]','鼓角迎秋晚韻長，斷虹疎雨間微陽。',64,'全唐诗/poet.tang.38000.json','["鼓角迎秋晚韻長，斷虹疎雨間微陽。", "兩條溪水分頭碧，四面人家入骨涼。", "獨鳥歸時雲鬬迥，殘蟬急處日爭忙。", "他年若得壺中術，一簇汀洲盡貯將。"]'),
('fad6799c-322c-4f85-973c-fbde93d57321','宋玉宅','吳融','唐','唐诗','tang','','[]','草白煙寒半野陂，臨江舊宅指遺基。',64,'全唐诗/poet.tang.38000.json','["草白煙寒半野陂，臨江舊宅指遺基。", "已懷湘浦招魂事，更憶高唐說夢時。", "穿徑早曾聞客住，登牆豈復見人窺。", "今朝送別還經此，吟斷當年幾許悲。"]'),
('0a53ceb2-0556-4393-ac13-39a21a520e26','春晚書懷','吳融','唐','唐诗','tang','','[]','落盡紅芳春意闌，綠蕪空鏁辟疆園。',64,'全唐诗/poet.tang.38000.json','["落盡紅芳春意闌，綠蕪空鏁辟疆園。", "嫦娥斷影霜輪冷，帝子無蹤淚竹繁。", "未達東鄰還絕想，不勞南浦更銷魂。", "晚來雖共殘鶯約，爭奈風淒又雨昏。"]'),
('de06c890-766d-4632-8c7f-30ae7d09b845','寄楊侍郎','吳融','唐','唐诗','tang','','[]','雲情鶴態莫誇慵，正上仙樓十二重。',64,'全唐诗/poet.tang.38000.json','["雲情鶴態莫誇慵，正上仙樓十二重。", "吟逸易沈鳷鵲月，夢長先斷景陽鐘。", "奇文已刻金書券，秘語看鐫玉檢封。", "何事春來待歸隱，探知溪畔有風松。"]'),
('743aa9cf-9b50-45e1-8deb-8403fa41c33e','杏花','吳融','唐','唐诗','tang','','[]','粉薄紅輕揜歛羞，花中占斷得風流。',64,'全唐诗/poet.tang.38000.json','["粉薄紅輕揜歛羞，花中占斷得風流。", "軟非因醉都無力，凝不成歌亦自愁。", "獨照影時臨水畔，最含情處出牆頭。", "裴回盡日難成別，更待黃昏對酒樓。"]'),
('38ecba14-83f8-4047-98a1-9ea39ee58763','憲丞裴公上洛退居有寄二首 一','吳融','唐','唐诗','tang','','[]','鴻在冥冥已自由，紫芝峰下更高秋。',64,'全唐诗/poet.tang.38000.json','["鴻在冥冥已自由，紫芝峰下更高秋。", "拋來簪紱都如夢，泥著杯香不爲愁。", "晚樹拂簷風脫翠，夜灘當戶月和流。", "自嗟不得從公去，共上仙家十二樓。"]'),
('3a6bfe8f-4623-4652-9000-dcb35fe63649','憲丞裴公上洛退居有寄二首 二','吳融','唐','唐诗','tang','','[]','瘦如仙鶴爽風篁，外却塵囂興緒長。',64,'全唐诗/poet.tang.38000.json','["瘦如仙鶴爽風篁，外却塵囂興緒長。", "偶坐幾回沈皓月，閑吟是處到殘陽。", "門前立使修書嬾，花下留賓壓酒忙。", "目斷瓊林攀不得，一重丹水抵三湘。"]'),
('eba4826d-a5da-4303-8623-1066ae4bd9a5','叢祠','吳融','唐','唐诗','tang','','[]','叢祠一炬照秦川，雨散雲飛二十年。',64,'全唐诗/poet.tang.38000.json','["叢祠一炬照秦川，雨散雲飛二十年。", "長路未歸萍逐水，舊居難問草平煙。", "金鞍正伴桐鄉客，粉壁猶懷桂苑仙。", "何必向來曾識面，拂塵看字也淒然。"]'),
('aea6ea10-4541-40bd-a3d9-ff9e4338daf7','分水嶺','吳融','唐','唐诗','tang','','[]','兩派潺湲不暫停，嶺頭長瀉別離情。',64,'全唐诗/poet.tang.38000.json','["兩派潺湲不暫停，嶺頭長瀉別離情。", "南隨去馬通巴棧，北逐歸人達渭城。", "澄處好窺雙黛影，咽時堪寄斷腸聲。", "紫溪舊隱還如此，清夜梁山月更明。"]'),
('f72a01d0-c57c-4d99-aa23-4c378f94b93a','赴職西川過便橋書懷寄同年','吳融','唐','唐诗','tang','','[]','平門橋下水東馳，萬里從軍一望時。',64,'全唐诗/poet.tang.38000.json','["平門橋下水東馳，萬里從軍一望時。", "鄉思旋生芳草見，客愁何限夕陽知。", "秦陵無樹煙猶鏁，漢苑空牆浪欲吹。", "不是傷春愛回首，杏壇恩重馬遲遲。"]'),
('811ed19b-b95a-44fb-974b-8b8f67c957f9','太保中書令軍前新樓','吳融','唐','唐诗','tang','','[]','十二闌干壓錦城，半空人語落灘聲。',64,'全唐诗/poet.tang.38000.json','["十二闌干壓錦城，半空人語落灘聲。", "風流近接平津閣，氣色高含細柳營。", "盡日捲簾江草綠，有時欹枕雪峰晴。", "不知捧詔朝天後，誰此登臨看月明。"]'),
('6e7a1a13-7702-448b-a558-cef0e86df5dd','玉女廟','吳融','唐','唐诗','tang','','[]','九清何日降仙霓，掩暎荒祠路欲迷。',64,'全唐诗/poet.tang.38000.json','["九清何日降仙霓，掩暎荒祠路欲迷。", "愁黛不開山淺淺，離心長在草萋萋。", "簷橫淥派王餘擲，窗褭紅枝杜宇啼。", "若得洗頭盆置此，靚妝無復碧蓮西。"]'),
('145163c7-0397-48e6-84fe-b6a6c12a2eda','坤維軍前寄江南弟兄','吳融','唐','唐诗','tang','','[]','二年征戰劒山秋，家在松江白浪頭。',64,'全唐诗/poet.tang.38000.json','["二年征戰劒山秋，家在松江白浪頭。", "關月幾時乾客淚，戍煙終日起鄉愁。", "未知遼堞何當下，轉覺燕臺不易酬。", "獨羨一聲南去雁，滿天風雨到汀洲。"]'),
('295ad042-cebb-494f-88c0-da4e7f23a846','滻水席上獻座主侍郎','吳融','唐','唐诗','tang','','[]','暖泉宮裏告虔回，略避紅塵小宴開。',64,'全唐诗/poet.tang.38000.json','["暖泉宮裏告虔回，略避紅塵小宴開。", "落絮已隨流水去，啼鶯還傍夕陽來。", "草能緣岸侵羅薦，花不容枝蘸玉杯。", "莫訝諸生中獨醉，感恩傷別正難裁。"]'),
('2be50bb6-2714-4474-8256-d0f50b6c4147','送知古上人','吳融','唐','唐诗','tang','','[]','昔年離別浙河東，多難相逢舊楚宮。',64,'全唐诗/poet.tang.38000.json','["昔年離別浙河東，多難相逢舊楚宮。", "振錫纔尋三徑草，登船忽挂一帆風。", "幾程村飯添盂白，何處山花照衲紅？", "不似投荒憔悴客，滄浪無際問漁翁。"]'),
('f55086ed-c307-43be-9a99-4616c35d88a9','和座主尚書登布善寺樓','吳融','唐','唐诗','tang','','[]','往事何時不繫腸，更堪凝睇白雲鄉。',64,'全唐诗/poet.tang.38000.json','["往事何時不繫腸，更堪凝睇白雲鄉。", "楚王城壘空秋色，羊祜江山祗暝光。", "林下遠分南去馬，渡頭偏認北歸航。", "誰知此日憑軒處，一筆工夫勝七襄。"]'),
('1ef3566c-a526-412a-8716-12cd9fc0e5b5','金橋感事','吳融','唐','唐诗','tang','','["\u6292\u60c5"]','太行和雪疊晴空，二月春郊尚朔風。',64,'全唐诗/poet.tang.38000.json','["太行和雪疊晴空，二月春郊尚朔風。", "飲馬早聞臨渭北，射鵰今欲過山東。", "百年徒有伊川歎，五利寧無魏絳功。", "日暮長亭正愁絕，哀笳一曲戍煙中。"]'),
('f8f5cf40-96f7-46d8-ab57-0afe7b38d113','蕭縣道中','吳融','唐','唐诗','tang','','[]','戍火三籠滯晚程，枯桑繫馬上寒城。',64,'全唐诗/poet.tang.38000.json','["戍火三籠滯晚程，枯桑繫馬上寒城。", "滿川落照無人過，卷地飛蓬有燒明。", "楚客早聞歌鳳德，劉琨休更舞雞聲。", "草堂舊隱終歸去，寄語巖猨莫曉驚。"]'),
('e6e48b56-b629-4f7c-9349-b31fdcc7c5f8','題兖州泗河中石牀','吳融','唐','唐诗','tang','','[]','一片苔牀水漱痕，何人清賞動乾坤。',66,'全唐诗/poet.tang.38000.json','["一片苔牀水漱痕，何人清賞動乾坤。", "謫仙醉後雲爲態，野客吟時月作魂。", "光景不回波自遠，風流難問石無[言]。", "邇來多少登臨客，千載誰將勝事論。"]'),
('d37ffcf9-5285-4d74-883e-8ac79bab45ce','禁直偶書','吳融','唐','唐诗','tang','','[]','玉皇新復五城居，仙館詞臣在碧虛。',64,'全唐诗/poet.tang.38000.json','["玉皇新復五城居，仙館詞臣在碧虛。", "錦砌漸看翻芍藥，鏁窗還詠隔蟾蜍。", "敢期林上靈烏語，貪草雲間彩鳳書。", "爭奈滄洲頻入夢，白波無際落紅蕖。"]'),
('1b23b7d0-b611-4e3c-b7af-74d129e91ee2','送弟東歸','吳融','唐','唐诗','tang','','[]','偶持麟筆侍金閨，夢想三年在故溪。',64,'全唐诗/poet.tang.38000.json','["偶持麟筆侍金閨，夢想三年在故溪。", "祖竹定欺簷雪折，穉杉應拂棟雲齊。", "謾勞筋力趨丹鳳，可有文詞詠碧雞。", "此別更無閑事囑，北山高處謝猨啼。"]'),
('83e643a1-daea-42fa-98ea-5fbfb6efb046','和座主尚書春日郊居','吳融','唐','唐诗','tang','','[]','海燕初歸朔雁回，靜眠深揜百花臺。',64,'全唐诗/poet.tang.38000.json','["海燕初歸朔雁回，靜眠深揜百花臺。", "春蔬已爲高僧掇，臘醞還因熟客開。", "簷外暖絲兼絮墮，檻前輕浪帶鷗來。", "謝公難避蒼生意，自古風流必上台。"]'),
('179a5d17-46f2-4e9d-b436-91de2246258c','僧舍白牡丹二首 一','吳融','唐','唐诗','tang','','[]','膩若裁雲薄綴霜，春殘獨自殿羣芳。',64,'全唐诗/poet.tang.38000.json','["膩若裁雲薄綴霜，春殘獨自殿羣芳。", "梅妝向日霏霏暖，紈扇搖風閃閃光。", "月魄照來空見影，露華凝後更多香。", "天生潔白宜清淨，何必殷紅暎洞房。"]'),
('2b9bca44-2754-47f0-a988-cd1f15396f63','僧舍白牡丹二首 二','吳融','唐','唐诗','tang','','[]','侯家萬朵簇霞丹，若並霜林素豔難。',64,'全唐诗/poet.tang.38000.json','["侯家萬朵簇霞丹，若並霜林素豔難。", "合影只應天際月，分香多是畹中蘭。", "雖饒百卉爭先發，還在三春向後殘。", "想得惠林憑此檻，肯將榮落意來看。"]'),
('35d5e7d4-1dd4-4e0b-baac-7e1a50f5bf20','八月十五夜禁直寄同僚','吳融','唐','唐诗','tang','','[]','中秋月滿盡相尋，獨入非煙宿禁林。',64,'全唐诗/poet.tang.38000.json','["中秋月滿盡相尋，獨入非煙宿禁林。", "曾恨人間千里隔，更堪天上九門深。", "明涵太液魚龍定，靜鏁圓靈象緯沈。", "目斷枚臯何處在，闌干十二憶登臨。"]'),
('319502e8-c7de-4bfb-ba4b-3d6a45f13e0a','上巳日花下閑看','吳融','唐','唐诗','tang','','[]','十里香塵撲馬飛，碧蓮峰下踏青時。',64,'全唐诗/poet.tang.38000.json','["十里香塵撲馬飛，碧蓮峰下踏青時。", "雲鬟照水和花重，羅袖擡風惹絮遲。", "可便無心邀娬媚，還應有淚憶袁熙。", "如煙如夢爭尋得，溪柳回頭萬萬絲。"]'),
('a51d913c-3354-40d0-a470-7a7f9d082ba0','禪院弈棋偶題','吳融','唐','唐诗','tang','','[]','裛塵絲雨送微涼，偶出樊籠入道場。',64,'全唐诗/poet.tang.38000.json','["裛塵絲雨送微涼，偶出樊籠入道場。", "半偈已能消萬事，一枰兼得了殘陽。", "尋知世界都如夢，自喜身心甚不忙。", "更約西風搖落後，醉來終日臥禪房。"]'),
('52e28c9a-c24a-4abc-ab94-2e7ab8774a1f','和張舍人','吳融','唐','唐诗','tang','','[]','玉女盆邊雪未銷，正多春事莫無憀。',64,'全唐诗/poet.tang.38000.json','["玉女盆邊雪未銷，正多春事莫無憀。", "杏花向日紅勻臉，雲帶環山白繫腰。", "鶯囀樹頭欹枕聽，凍開泉眼杖藜挑。", "陵遷谷變如須問，控鶴山人字子喬。"]'),
('afc9758b-5b1f-4c18-b661-bac9db4b81be','送友赴闕','吳融','唐','唐诗','tang','','[]','故人歸去指翔鸞，樂帶離聲可有歡。',64,'全唐诗/poet.tang.38000.json','["故人歸去指翔鸞，樂帶離聲可有歡。", "驛路兩行秋吹急，渭波千疊夕陽寒。", "空郊已歎周禾熟，舊苑應尋漢火殘。", "遙羨從公無一事，探花先醉曲江干。"]'),
('8ac1c0cb-3e3c-462b-ba4b-2a80fd7d1464','過鄧城縣作','吳融','唐','唐诗','tang','','[]','不用登臨足感傷，古來今往盡茫茫。',64,'全唐诗/poet.tang.38000.json','["不用登臨足感傷，古來今往盡茫茫。", "未知堯桀誰臧否，可便彭殤有短長。", "楚壘萬重多故事，漢波千疊更殘陽。", "到頭一切皆身外，只覺關身是醉鄉。"]'),
('05e80444-fbeb-4146-b858-86958752fd1e','文德初聞車駕東遊','吳融','唐','唐诗','tang','','[]','龍斾叢叢下劒門，還將瑞氣入中原。',64,'全唐诗/poet.tang.38000.json','["龍斾叢叢下劒門，還將瑞氣入中原。", "鰲頭一蕩山雖沒，烏足重安日不昏。", "晉客已知周禮在，秦人仍喜漢官存。", "自憐閑坐漁磯石，萬級雲臺落夢魂。"]'),
('2e730162-0a4d-44e0-b17f-581ef798d05e','子規','吳融','唐','唐诗','tang','','["\u6292\u60c5", "\u675c\u9e43"]','舉國繁華委逝川，羽毛飄蕩一年年。',64,'全唐诗/poet.tang.38000.json','["舉國繁華委逝川，羽毛飄蕩一年年。", "他山叫處花成血，舊苑春來草似煙。", "雨暗不離濃綠樹，月斜長弔欲明天。", "湘江日暮聲淒切，愁殺行人歸去船。"]'),
('f7150de2-4c5b-410a-a658-5a3ce099a431','簡州歸降賀京兆公','吳融','唐','唐诗','tang','','[]','分棟山前曙色開，三千鐵騎簡州回。',64,'全唐诗/poet.tang.38000.json','["分棟山前曙色開，三千鐵騎簡州回。", "雲間墮箭飛書去，風裏擎竿露布來。", "古謂伐謀爲上策，今看靜勝自中台。", "功名一似淮西事，只是元臣不姓裴。"]'),
('aa3e0444-cb4e-4983-af17-6c2ecce0928d','登漢州城樓','吳融','唐','唐诗','tang','','[]','雨餘秋色拂孤城，遠目凝時萬象清。',64,'全唐诗/poet.tang.38000.json','["雨餘秋色拂孤城，遠目凝時萬象清。", "疊翠北來千嶂盡，漫流東去一江平。", "從軍固有荆州樂，懷古能無峴首情。", "欲下闌干一迴首，烏歸帆沒戍煙明。"]'),
('a7554ae0-8ee7-45a3-a0d3-5ab5ee07e304','岐下寓居見槐花落因寄從事','吳融','唐','唐诗','tang','','[]','纔開便落不勝黃，覆著庭莎襯夕陽。',64,'全唐诗/poet.tang.38000.json','["纔開便落不勝黃，覆著庭莎襯夕陽。", "只共蟬催雙鬢老，可知人已十年忙。", "曉窗須爲吟秋興，夜枕應教夢帝鄉。", "蜀國馬卿看從獵，肯將閑事入淒涼。"]'),
('7a85c285-1148-48e0-863f-624d5ba4277f','和人有感','吳融','唐','唐诗','tang','','[]','莫愁家住石城西，月墜星沈客到迷。',64,'全唐诗/poet.tang.38000.json','["莫愁家住石城西，月墜星沈客到迷。", "一院無人春寂寂，九原何處草萋萋。", "香魂未散煙籠水，舞袖休翻柳拂堤。", "蘭棹一移風雨急，流鶯千萬莫長啼。"]'),
('af20d937-6fe6-4a07-89f4-9231e55e72fe','春歸次金陵','吳融','唐','唐诗','tang','','[]','春陰漠漠覆江城，南國歸橈趂晚程。',64,'全唐诗/poet.tang.38000.json','["春陰漠漠覆江城，南國歸橈趂晚程。", "水上驛流初過雨，樹籠堤處不離鶯。", "跡疎冠蓋兼無夢，地近鄉園自有情。", "便被東風動離思，楊花千里雪中行。"]'),
('a44227a3-01e2-4ae6-81da-ef9957829fa2','途中見杏花','吳融','唐','唐诗','tang','','["\u6292\u60c5", "\u82b1", "\u5199\u82b1"]','一枝紅豔出牆頭，牆外行人正獨愁。',64,'全唐诗/poet.tang.38000.json','["一枝紅豔出牆頭，牆外行人正獨愁。", "長得看來猶有恨，可堪逢處更難留。", "林空色暝鶯先到，春淺香寒蝶未遊。", "更憶帝鄉千萬樹，澹煙籠日暗神州。"]'),
('45e9a714-559b-4b9c-8f15-7e0bb6200ef7','秋日經別墅','吳融','唐','唐诗','tang','','[]','別墅蕭條海上村，偶期蘭菊與琴尊。',64,'全唐诗/poet.tang.38000.json','["別墅蕭條海上村，偶期蘭菊與琴尊。", "簷橫碧嶂秋光近，樹帶閑潮晚色昏。", "幸有白雲眠楚客，不勞芳草思王孫。", "北山移去前文在，無復教人歎曉猨。"]'),
('cde3ddab-b6aa-4cce-99de-e600b9e82746','紅葉','吳融','唐','唐诗','tang','','[]','露染霜乾片片輕，斜陽照處轉烘明。',64,'全唐诗/poet.tang.38000.json','["露染霜乾片片輕，斜陽照處轉烘明。", "和煙飄落九秋色，隨浪汎將千里情。", "幾夜月中藏鳥影，誰家庭際伴蛩聲。", "一時衰颯無多恨，看着清風綵剪成。"]'),
('ff60d5f6-007b-4134-9a6b-84a0a9e2fdc0','離霅溪感事獻鄭員外','吳融','唐','唐诗','tang','','[]','足恨饒悲不自由，萍無根蒂水長流。',64,'全唐诗/poet.tang.38000.json','["足恨饒悲不自由，萍無根蒂水長流。", "庾公明月吟連曙，謝守青山看入秋。", "一飯意專堪便死，千金諾在轉難酬。", "雲沈鳥去回頭否，平子才多好賦愁。"]'),
('9c4282b1-f53e-43ed-8972-fb8dbe67e7d8','岐州安西門','吳融','唐','唐诗','tang','','[]','安西門外徹安西，一百年前斷鼓鼙。',64,'全唐诗/poet.tang.38000.json','["安西門外徹安西，一百年前斷鼓鼙。", "犬解人歌曾入唱，馬稱龍子幾來嘶。", "自從遼水煙塵起，更到塗山道路迷。", "今日登臨須下淚，行人無個草萋萋。"]'),
('2df80a71-e7b1-4be7-87be-a8d0daa9797b','關西驛亭即事','吳融','唐','唐诗','tang','','[]','晚霞零落雨初收，關上危闌獨悵留。',64,'全唐诗/poet.tang.38000.json','["晚霞零落雨初收，關上危闌獨悵留。", "千里好春聊極目，五陵無事莫回頭。", "山猶帶雪霏霏恨，柳未禁寒冉冉愁。", "直是無情也腸斷，鳥歸帆沒水空流。"]'),
('6710d655-c2ca-4316-9888-50a036b1a1eb','望嵩山','吳融','唐','唐诗','tang','','[]','三十六峰危似冠，晴樓百尺獨登看。',64,'全唐诗/poet.tang.38000.json','["三十六峰危似冠，晴樓百尺獨登看。", "高凌鳥外青冥窄，翠落人間白晝寒。", "不覺衡陽遮雁過，如何鍾阜鬬龍盤。", "始知萬歲聲長在，只待東巡動玉鸞。"]'),
('90a1e0e1-aabf-4ba0-8e96-15df37579aca','題湖城縣西道中槐樹','吳融','唐','唐诗','tang','','[]','零落攲斜此路中，盛時曾識太平風。',64,'全唐诗/poet.tang.38000.json','["零落攲斜此路中，盛時曾識太平風。", "曉迷天仗歸春苑，暮送鸞旗指洛宮。", "一自煙塵生薊北，更無消息幸關東。", "而今只有孤根在，鳥啄蟲穿沒亂蓬。"]'),
('24152f34-8cc6-4582-94c4-36d77e053b2b','東歸次瀛上','吳融','唐','唐诗','tang','','[]','煖煙輕淡草霏霏，一片晴山襯夕暉。',64,'全唐诗/poet.tang.38000.json','["煖煙輕淡草霏霏，一片晴山襯夕暉。", "水露淺沙無客泛，樹連疎苑有鶯飛。", "自從身與滄浪別，長被春教寂寞歸。", "回首青門不知處，向人楊柳莫依依。"]'),
('e349c048-6b35-4a24-9ec7-c71f9db72a34','偶書','吳融','唐','唐诗','tang','','[]','青牛關畔寄孤村，山當屏風石當門。',64,'全唐诗/poet.tang.38000.json','["青牛關畔寄孤村，山當屏風石當門。", "芳樹綠陰連蔽芾，長河飛浪接崑崙。", "苔田綠後蛙爭聚，麥壠黃時雀更喧。", "只此無心便無事，避人何必武陵源。"]'),
('f1b2d36c-3df3-4185-a0ec-4d5cd886846e','得京中親友書訝久無音耗以詩代謝','吳融','唐','唐诗','tang','','[]','退閑何事不忘機，況限溪雲靜掩扉。',64,'全唐诗/poet.tang.38000.json','["退閑何事不忘機，況限溪雲靜掩扉。", "馬頰浪高魚去少，雞鳴關險雁來稀。", "無才敢更期連茹，有意兼思學採薇。", "珍重故人知我者，九霄休復寄音徽。"]'),
('c4016e76-a02e-4f8b-93bb-aa84c42fd1c5','即事','吳融','唐','唐诗','tang','','[]','抵鵲山前雲掩扉，更甘終老脫朝衣。',64,'全唐诗/poet.tang.38000.json','["抵鵲山前雲掩扉，更甘終老脫朝衣。", "曉窺青鏡千峰入，暮倚長松獨鶴歸。", "雲裏引來泉脉細，雨中移得藥苗肥。", "何須一筯鱸魚膾，始挂孤帆問釣磯。"]'),
('1144758b-1f67-4cb9-bad8-d3eddb0e7ff3','病中宜茯苓寄李諫議','吳融','唐','唐诗','tang','','[]','千年茯菟帶龍鱗，太華峰頭得最珍。',64,'全唐诗/poet.tang.38000.json','["千年茯菟帶龍鱗，太華峰頭得最珍。", "金鼎曉煎雲漾粉，玉甌寒貯露含津。", "南宮已借徵詩客，內署今還託諫臣。", "飛檄愈風知妙手，也須分藥救漳濱。"]'),
('761ea005-9b29-43fa-a0d8-e2adf7c631f0','槎','吳融','唐','唐诗','tang','','[]','浪痕龍跡老敧危，流落何時別故枝。',64,'全唐诗/poet.tang.38000.json','["浪痕龍跡老敧危，流落何時別故枝。", "歲月空教苔蘚積，芳菲長倩薜蘿知。", "有文在朽人難識，無蠹藏心鳥莫窺。", "家近滄浪從汎去，碧天消息不參差。"]'),
('05d329e9-444b-4718-b3a9-72120f52e991','汴上觀','吳融','唐','唐诗','tang','','[]','九曲河冰半段來，嚴霜結出勁風裁。',64,'全唐诗/poet.tang.38000.json','["九曲河冰半段來，嚴霜結出勁風裁。", "非時已認蟬飄翼，到海須憂蚌失胎。", "千里風清聞戛玉，幾人東下憶奔雷。", "殷勤莫礙星槎路，從看天津弄杼回。"]'),
('fe955445-1f9e-46ba-b564-0bc82599010d','閑居有作','吳融','唐','唐诗','tang','','[]','依依芳樹拂簷平，繞竹清流浸骨清。',64,'全唐诗/poet.tang.38000.json','["依依芳樹拂簷平，繞竹清流浸骨清。", "愛弄綠苔魚自躍，慣偷紅果鳥無聲。", "踏青堤上煙多綠，拾翠江邊月更明。", "只此超然長往是，幾人能遂鑄金成。"]'),
('d6fcf9cc-796f-4b64-a4da-3016036037b0','離岐下題西湖','吳融','唐','唐诗','tang','','["\u897f\u6e56"]','送夏迎秋幾醉來，不堪行色被蟬催。',64,'全唐诗/poet.tang.38000.json','["送夏迎秋幾醉來，不堪行色被蟬催。", "身隨渭水看歸遠，夢挂秦雲約自迴。", "雨細若爲拋釣艇，月明誰復上歌臺。", "千波萬浪西風急，更爲紅蕖把一桮。"]'),
('5c314358-db4b-42a5-bb0d-455582751107','岐陽蒙相國對宅因抒懷投獻','吳融','唐','唐诗','tang','','[]','風有危亭月有臺，平津閣畔好裴回。',64,'全唐诗/poet.tang.38000.json','["風有危亭月有臺，平津閣畔好裴回。", "雖非宋玉誅茅至，且學王家種竹來。", "已得靜居從馬歇，不堪行色被蟬催。", "故園蘭菊三千里，旅夢方應校嬾迴。"]'),
('881b755e-5d6b-4e12-a99a-c9e1f675fb38','晚泊松江','吳融','唐','唐诗','tang','','[]','落日停橈古渡邊，古今蹤跡一蒼然。',64,'全唐诗/poet.tang.38000.json','["落日停橈古渡邊，古今蹤跡一蒼然。", "平沙盡處雲藏樹，遠吹收來水定天。", "正困東西千里路，可憐瀟灑五湖船。", "如何不及前賢事，却謝鱸魚在洛川。"]'),
('651f432d-3ce8-49ae-9fe0-cf68df0778d1','過澠池書事','吳融','唐','唐诗','tang','','[]','澠池城郭半遺基，無限春愁挂落暉。',64,'全唐诗/poet.tang.38000.json','["澠池城郭半遺基，無限春愁挂落暉。", "柳渡風輕花浪綠，麥田煙暖錦雞飛。", "相如忠烈千秋斷，二主英雄一夢歸。", "莫道新亭人對泣，異鄉殊代也霑衣。"]'),
('e1fb1d49-c8b7-4c83-9fb2-9e0095d1ee71','富春','吳融','唐','唐诗','tang','','[]','水送山迎入富春，一川如畫晚晴新。',64,'全唐诗/poet.tang.38000.json','["水送山迎入富春，一川如畫晚晴新。", "雲低遠渡帆來重，潮落寒沙鳥下頻。", "未必柳間無謝客，也應花裏有秦人。", "嚴光萬古清風在，不敢停橈更問津。"]'),
('7ada8699-d003-418a-8d52-f9e5fc1f6051','高侍御話及皮博士池中白蓮因成一章寄博士兼奉呈','吳融','唐','唐诗','tang','','[]','白玉花開綠錦池，風流御史報人知。',64,'全唐诗/poet.tang.38000.json','["白玉花開綠錦池，風流御史報人知。", "看來應是雲中墮，偷去須從月下移。", "已被亂蟬催晼晚，更禁涼雨動䙰褷。", "習家秋色堪圖畫，只欠山公倒接䍦。"]'),
('9845de4b-778d-45b1-b7b7-c1ffdde83f9a','憶猿','吳融','唐','唐诗','tang','','[]','翠微雲歛日沈空，叫徹青冥怨不窮。',64,'全唐诗/poet.tang.38000.json','["翠微雲歛日沈空，叫徹青冥怨不窮。", "連臂影垂溪色裏，斷腸聲盡月明中。", "靜含煙峽淒淒雨，高弄霜天嫋嫋風。", "猶有北山歸意在，少驚佳樹近房櫳。"]'),
('411de517-cc82-4b5e-9ab2-5a19ec687e44','紅樹','吳融','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','一聲南雁已先紅，神女霜飛葉葉同。',64,'全唐诗/poet.tang.38000.json','["一聲南雁已先紅，神女霜飛葉葉同。", "自是孤根非暖地，莫驚他木耐秋風。", "暖煙散去陰全薄，明月臨來影半空。", "長憶洞庭千萬樹，照山橫浦夕陽中。"]'),
('43e88407-a03e-4d5c-b1ca-1d6996ca3969','新雁','吳融','唐','唐诗','tang','','[]','湘浦波春始北歸，玉關搖落又南飛。',64,'全唐诗/poet.tang.38000.json','["湘浦波春始北歸，玉關搖落又南飛。", "數聲飄去和秋色，一字橫來背晚暉。", "紫閣高翻雲羃羃，灞川低渡雨微微。", "莫從思婦臺邊過，未得征人萬里衣。"]'),
('eb5aa93f-8fb0-40eb-9c58-04925ef42c85','海上秋懷','吳融','唐','唐诗','tang','','[]','辭無珪組隱無才，門向潮頭過處開。',64,'全唐诗/poet.tang.38000.json','["辭無珪組隱無才，門向潮頭過處開。", "幾度黃昏逢罔象，有時紅旭見蓬萊。", "磧連荒戍頻頻火，天絕纖雲往往雷。", "昨夜秋風已搖落，那堪更上望鄉臺。"]'),
('e50eecbd-56d2-40ed-8c4d-fb47ff027f1e','憶山泉','吳融','唐','唐诗','tang','','[]','穿雲落石細湔湔，盡日疑聞弄管弦。',64,'全唐诗/poet.tang.38000.json','["穿雲落石細湔湔，盡日疑聞弄管弦。", "千仞灑來寒碎玉，一泓深去碧涵天。", "煙迷葉亂尋難見，月好風清聽不眠。", "春雨正多歸未得，只應流恨更潺湲。"]'),
('b302b0d9-94a6-45ab-9d68-1350fa03b3da','東歸望華山','吳融','唐','唐诗','tang','','[]','碧蓮重疊在青冥，落日垂鞭緩客程。',64,'全唐诗/poet.tang.38000.json','["碧蓮重疊在青冥，落日垂鞭緩客程。", "不奈春煙籠暗澹，可堪秋雨洗分明。", "南邊已放三千馬，北面猶標百二城。", "只怕仙人撫高掌，年年相見是空行。"]'),
('44189244-22ff-4edb-b651-5d089dc0234c','遊華州飛泉亭','吳融','唐','唐诗','tang','','[]','走馬街南百畝池，碧蓮花影倒參差。',64,'全唐诗/poet.tang.38000.json','["走馬街南百畝池，碧蓮花影倒參差。", "偶同人去紅塵外，正值僧歸落照時。", "萬事已爲春棄置，百憂須賴酒醫治。", "殷勤待取前峰月，更倚闌干弄釣絲。"]'),
('7524a652-842f-4083-80f6-17a580bbfa18','池上雙鳧二首 一','吳融','唐','唐诗','tang','','[]','碧池悠漾小鳧雛，兩兩依依秪自娛。',64,'全唐诗/poet.tang.38000.json','["碧池悠漾小鳧雛，兩兩依依秪自娛。", "釣艇忽移還散去，寒鴟有意即相呼。", "可憐翡翠歸雲髻，莫羨鴛鴦入畫圖。", "幸是羽毛無取處，一生安穩老菰蒲。"]'),
('cdeb8466-ed1f-4785-8168-23d964d60fd0','池上雙鳧二首 二','吳融','唐','唐诗','tang','','[]','雙鳧狎得傍池臺，戲藻銜蒲遠又回。',64,'全唐诗/poet.tang.38000.json','["雙鳧狎得傍池臺，戲藻銜蒲遠又回。", "敢爲稻粱凌險去，幸無鷹隼觸波來。", "萬絲春雨眠時亂，一片濃萍浴處開。", "不在籠欄夜仍好，月汀星沼剩裴回。"]'),
('a6819c5a-cece-4e07-a998-9513c2c2851d','葉落','吳融','唐','唐诗','tang','','[]','紅影飄來翠影微，一辭林表不知歸。',64,'全唐诗/poet.tang.38000.json','["紅影飄來翠影微，一辭林表不知歸。", "伴愁無色煙猶在，替恨成啼露未晞。", "若逐水流應萬里，莫因風起便孤飛。", "楚郊千樹秋聲急，日暮紛紛惹客衣。"]'),
('83b8102d-d1f4-405f-9775-f45730ec96f2','和皮博士赴上京觀中修靈齋贈威儀尊師兼見寄','吳融','唐','唐诗','tang','','[]','霓結雙旌羽綴裙，七星壇上拜元君。',64,'全唐诗/poet.tang.38000.json','["霓結雙旌羽綴裙，七星壇上拜元君。", "精誠有爲天應感，章奏無私鬼怕聞。", "鶴馭已從煙際下，鳳膏還向月中焚。", "白雲鄉路看看到，好駐流年翊聖文。"]'),
('5fd56c8a-8487-4f05-92f9-64f4154e1c3a','春雨','吳融','唐','唐诗','tang','','[]','霏霏漠漠暗和春，羃翠凝紅色更新。',64,'全唐诗/poet.tang.38000.json','["霏霏漠漠暗和春，羃翠凝紅色更新。", "寒入膩裘濃曉睡，細隨油壁靜香塵。", "連雲似織休迷雁，帶柳如啼好贈人。", "別有空堦寂寥事，綠苔狼籍落花頻。"]'),
('fb5532f5-1b8e-4d2f-b12a-d4643e45d304','秋池','吳融','唐','唐诗','tang','','[]','冷涵秋水碧溶溶，一片澄明見底空。',64,'全唐诗/poet.tang.38000.json','["冷涵秋水碧溶溶，一片澄明見底空。", "有日晴來雲襯白，幾時吹落葉浮紅。", "香啼蓼穗娟娟露，乾動蓮莖淅淅風。", "凌曉無端照衰髮，便悲霜雪鏡光中。"]'),
('52a5e7ce-e78e-4a34-801c-25bef82f469b','首陽山','吳融','唐','唐诗','tang','','["\u9ec4\u6cb3"]','首陽山枕黃河水，上有兩人曾餓死。',64,'全唐诗/poet.tang.38000.json','["首陽山枕黃河水，上有兩人曾餓死。", "不同天下人爲非，兄弟相看自爲是。", "遂令萬古識君心，爲臣貴義不貴身。", "精靈長在白雲裏，應笑隨時飽死人。"]'),
('8eb6be1f-ca76-4092-89ab-d47677e6abd7','太湖石歌','吳融','唐','唐诗','tang','','["\u592a\u6e56", "\u6d1e\u5ead\u6e56"]','洞庭山下湖波碧，波中萬古生幽石。',200,'全唐诗/poet.tang.38000.json','["洞庭山下湖波碧，波中萬古生幽石。", "鐵索千尋取得來，奇形怪狀誰能識。", "初疑朝家正人立，又如戰士方狙擊。", "又如防風死後骨，又如於菟活時額。", "又如成人楓，又如害癭柏。", "雨過上停泓，風來中有隙。", "想得沈潛水府時，興雲出雨蟠蛟螭。", "今來硉矹林庭上，長恐忽然生白浪。", "用時應不稱媧皇，將去也堪隨博望。", "噫嘻爾石好憑依，幸有方池幷釣磯。", "小山叢桂且爲伴，鍾阜白雲長自歸。", "何必豪家甲第裏，玉闌干畔爭光輝。", "一朝荆棘忽流落，何異綺羅雲雨飛。"]'),
('f1e923ff-5671-438f-8697-08ad1d691fe3','贈方干處士歌','吳融','唐','唐诗','tang','','[]','把筆盡爲詩，何人敵夫子。',130,'全唐诗/poet.tang.38000.json','["把筆盡爲詩，何人敵夫子。", "句滿天下口，名聒天下耳。", "不識朝，不識市。", "曠逍遙，閑徙倚。", "一桮酒，無萬事。", "一葉舟，無千里。", "衣裳白雲，坐臥流水。", "霜落風高忽相憶，惠然見過留一夕。", "一夕聽吟十數篇，水榭林蘿爲岑寂。", "拂旦舍我亦不辭，攜筇徑去隨所適。", "隨所適，無處覓。", "雲半片，鶴一隻。"]'),
('b0ecee39-0568-4b54-ab75-249bdc3fab1e','李周彈箏歌','吳融','唐','唐诗','tang','','[]','古人云：絲不如竹，竹不如肉。',286,'全唐诗/poet.tang.38000.json','["古人云：絲不如竹，竹不如肉。", "乃知此語未必然，李周彈箏聽不足。", "聞君七歲八歲時，五音六律皆生知。", "就中十三弦最妙，應宮出入年方少。", "青騘慣走長楸日，幾度承恩蒙急召。", "一字雁行斜御筵，鏘金戛羽凌非煙。", "始似五更殘月裏，淒淒切切清露蟬。", "又如石罅堆葉下，泠泠瀝瀝蒼崖泉。", "鴻門玉斗初向地，織女金梭飛上天。", "有時上苑繁花發，有時太液秋波闊。", "當頭獨坐摐一聲，滿座好風生拂拂。", "天顏開，聖心悅。", "紫金白珠霑賜物，出來無暇更還家。", "且上青樓醉明月，年將六十藝轉精。", "自寫梨園新曲聲，近來一事還惆悵。", "故里春荒煙草平，供奉供奉且聽語。", "自昔興衰看樂府，秪如伊州與梁州。", "盡是太平時歌舞，旦夕君王繼此聲，不要停弦淚如雨。"]'),
('f92f296d-2f5b-483f-ae59-5be06c526258','贈{巩/言}光上人草書歌','吳融','唐','唐诗','tang','','[]','篆書樸，隸書俗，草聖貴在無羈束。',208,'全唐诗/poet.tang.38000.json','["篆書樸，隸書俗，草聖貴在無羈束。", "江南有僧名{巩/言}光，紫毫一管能顚狂。", "人家好壁試揮拂，瞬目已流三五行。", "摘如鉤，挑如撥。", "斜如掌，迴如斡。", "又如夏禹鏁淮神，波底出來手正拔。", "又如朱亥鎚晉鄙，袖中擡起腕欲脫。", "有時軟縈盈，一穗秋雲曳空闊。", "有時瘦巉岩，百尺枯松露槎枿。", "忽然飛動更驚人，一聲霹靂龍虵活。", "稽山賀老昔所傳，又聞能者惟張顚。", "上人致功應不下，其奈飄飄滄海邊。", "可中一入天子國，絡素裁縑灑毫墨。", "不繫知之與不知，須言一字千金值。"]'),
('b9c4387c-bb94-4278-870a-d904b952483d','贈李長史歌','吳融','唐','唐诗','tang','','[]','危欄壓溪溪澹碧，翠褭紅飄鶯寂寂。',272,'全唐诗/poet.tang.38000.json','["危欄壓溪溪澹碧，翠褭紅飄鶯寂寂。", "此日長亭愴別離，座中忽遇吹蘆客。", "雙攘輕袖當高軒，含商吐羽凌非煙。", "初疑一百尺瀑布，八九月落香爐巔。", "又似鮫人爲客罷，迸淚成珠玉盤瀉。", "碧珊瑚碎震澤中，金鋃鐺撼龜山下。", "鏗訇揭調初驚人，幽咽細聲還感神。", "紫鳳將雛叫山月，玄兔喪子啼江春。", "咨嗟長史出人藝，如何值此艱難際。", "可中長似承平基，肯將此爲閑人吹。", "不是東城射雉處，即應南苑鬬雞時。", "白櫻桃熟每先賞，紅芍藥開長有詩。", "賣珠曾被武皇問，薰香不怕賈公知。", "今來流落一何苦，江南江北九寒暑。", "翠華猶在橐泉中，一曲梁州淚如雨。", "長史長史聽我語，從來藝絕多失所。", "羅君贈君兩首詩，半是悲君半自悲。"]'),
('03b8b065-de20-46ca-a56f-bad0d1e1a5f5','贈廣利大師歌','吳融','唐','唐诗','tang','','[]','化人之心固甚難，自化之心更不易。',204,'全唐诗/poet.tang.38000.json','["化人之心固甚難，自化之心更不易。", "化人可以程限之，自化元須有其志。", "在心爲志者何人，今日得之於廣利。", "三十年前識師初，正見把筆學草書。", "崩雲落日千萬狀，隨手變化生空虛。", "海北天南幾回別，每見書蹤轉奇絕。", "近來兼解作歌詩，言語明快有氣骨。", "堅如百鍊鋼，挺特不可屈。", "又如千里馬，脫韁飛滅沒。", "好是不雕刻，縱橫衝口發。", "昨來示我十餘篇，詠殺江南風與月。", "乃知性是天，習是人。", "莫輕河邊羖䍽，飛作天上麒麟。", "但日新，又日新。", "李太白，非通神。"]'),
('e9b068a0-73d9-437b-9a18-3bd314ba138e','古離別','吳融','唐','唐诗','tang','','[]','紫鸞黃鵠雖別離，一舉千里何難追。',96,'全唐诗/poet.tang.38000.json','["紫鸞黃鵠雖別離，一舉千里何難追。", "猶聞啼風與叫月，流連斷續令人悲。", "賦情更有深繾綣，碧甃千尋尚爲淺。", "蟾蜍正向清夜流，蛺蝶須教墮絲罥。", "莫道斷絲不可續，丹穴鳳凰膠不遠。", "莫道流水不迴波，海上兩潮長自返。"]'),
('38100dc8-bc59-44f5-9e22-bb12be88d05d','風雨吟','吳融','唐','唐诗','tang','','[]','風騷騷，雨涔涔，長洲苑外荒居深。',335,'全唐诗/poet.tang.38000.json','["風騷騷，雨涔涔，長洲苑外荒居深。", "門外流水流澶漫，河邊古木鳴蕭森。", "敻無禽影，寂無人音。", "端然拖愁坐，萬感叢於心。", "姑蘇碧瓦十萬戶，中有樓臺與歌舞。", "尋常倚月復眠花，莫說斜風兼細雨。", "應不知天地造化是何物，亦不知榮辱是何主。", "吾囷長滿是太平，吾樂不極是天生。", "豈憂天下有大憝，四郊刁斗常錚錚。", "官軍擾人甚於賊，將臣怕死唯守城。", "又豈復憂朝廷苦弛慢，中官轉縱橫。", "李膺勾黨即罹患，竇武忠謀又未行。", "又豈憂文臣盡遭束高閣，文教從今日蕭索。", "若更無人稍近前，把筆到頭同一惡。", "可嘆吳城城中人，無人與我交一言。", "蓬蒿滿徑塵一榻，獨此閔閔何其煩。", "雖然小或可謀大，[嫠]婦之憂史尚存。", "況我長懷丈夫志，今來流落滄溟涘。", "有時驚事再咨嗟，因風因雨更憔悴。", "只有閑橫膝上琴，怨傷怨恨聊相寄。", "伯牙海上感滄溟，何似今朝風雨思。"]'),
('a143dca3-283d-4a1f-9d7c-e095562a31db','江行','吳融','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','來時風，去時雨，蕭蕭颯颯春江浦。',32,'全唐诗/poet.tang.38000.json','["來時風，去時雨，蕭蕭颯颯春江浦。", "欹欹側側海門帆，軋軋啞啞洞庭櫓。"]'),
('d9b431fa-d330-41da-8ddf-b012b801d894','壁畫折竹雜言','吳融','唐','唐诗','tang','','[]','枯纏藤，重欹雪，渭曲逢，湘江別。',32,'全唐诗/poet.tang.38000.json','["枯纏藤，重欹雪，渭曲逢，湘江別。", "不是從來無本根，畫工取勢教摧折。"]'),
('9f715bcb-1a10-40b8-a20c-f07634e33273','古錦裾六韻','吳融','唐','唐诗','tang','','[]','濯水經何日，隨風故有人。',72,'全唐诗/poet.tang.38000.json','["濯水經何日，隨風故有人。", "綠衣猶偪畫，丹頂尚迷真。", "暗澹雲沈古，青蒼蘚剝新。", "暎襟知惹淚，侵韉想縈塵。", "掣曳無由睹，流傳久自珍。", "武威應認得，牽挽幾當春。"]'),
('a495149f-2c80-452a-a557-283fb578a1fa','賦得欲曉看妝面','吳融','唐','唐诗','tang','','[]','朧朧欲曙色，隱隱辨殘妝。',72,'全唐诗/poet.tang.38000.json','["朧朧欲曙色，隱隱辨殘妝。", "月始雲中出，花猶霧裏藏。", "眉邊全失翠，額畔半留黃。", "轉入金屏影，隈侵角枕光。", "有蟬隳鬢樣，無燕著𨥁行。", "十二峯前夢，如何不斷腸。"]'),
('ecb9b524-ba9d-4f24-b1e9-433ec6964eee','府試雨夜帝里聞猿聲','吳融','唐','唐诗','tang','','[]','雨滴秦中夜，猿聞峽外聲。',72,'全唐诗/poet.tang.38000.json','["雨滴秦中夜，猿聞峽外聲。", "已吟何遜恨，還賦屈平情。", "暗逐哀鴻淚，遙含禁漏清。", "直疑遊萬里，不覺在重城。", "霎霎侵燈亂，啾啾入夢驚。", "明朝臨曉鏡，別有鬢絲生。"]'),
('bc59ed4d-5cb0-4371-af2d-8970f6630501','題畫柏','吳融','唐','唐诗','tang','','[]','不得月中桂，轉思陵上柏。',168,'全唐诗/poet.tang.38000.json','["不得月中桂，轉思陵上柏。", "閑取畫圖看，煩紆果冰釋。", "桂生在青冥，萬古煙霧隔。", "下蔭玄兔窟，上暎嫦娥魄。", "圓缺且不常，高低圖難測。", "若非假羽翰，折攀何由得。", "天遠眼虛穿，夜闌頭自白。", "未知陵上柏，一定不移易。", "有意兼松茂，無情從麝食。", "不在是非間，與人爲憤激。", "他年上縑素，今日懸屋壁。", "靈怪不可知，風雨疑來逼。", "明朝歸故園，唯此同所適。", "回首寄團枝，無勞惠消息。"]'),
('8ca650b3-a08b-4599-97be-2aec53e586b5','平望蚊子二十六韻','吳融','唐','唐诗','tang','','[]','天下有蚊子，候夜噆人膚。',288,'全唐诗/poet.tang.38000.json','["天下有蚊子，候夜噆人膚。", "平望有蚊子，白晝來相屠。", "不避風與雨，羣飛出菰蒲。", "擾擾蔽天黑，雷然隨舳艫。", "利嘴入人肉，微形紅且濡。", "振蓬亦不懼，至死貪膏腴。", "舟人敢停棹，陸者亦疾趨。", "南北百餘里，畏之如虎貙。", "噫嘻天地間，萬物各有殊。", "陽者陽爲伍，陰者陰爲徒。", "蚊蚋是陰物，夜從喧牆隅。", "如何正曦赫，吞噬當通衢。", "人筋爲爾斷，人力爲爾枯。", "衣巾穢且甚，盤饌腥有餘。", "豈是陽德衰，不能使消除。", "豈是有主者，此鄉宜毒荼。", "吾聞蛇能螫，避之則無虞。", "吾聞蠆有毒，見之可疾驅。", "唯是此蚊子，逢人皆病諸。", "江南夏景好，水木多蕭疎。", "此中震澤路，風月彌清虛。", "前後幾來往，襟懷曾未舒。", "朝既蒙襞積，夜仍跧蘧蒢。", "雖然好吟嘯，其奈難踟蹰。"]'),
('ec22cba9-2ae4-432a-8ee5-be0b3102d3ab','桃花','吳融','唐','唐诗','tang','','[]','滿樹和嬌爛漫紅，萬枝丹彩灼春融。',32,'全唐诗/poet.tang.38000.json','["滿樹和嬌爛漫紅，萬枝丹彩灼春融。", "何當結作千年實，將示人間造化工。"]'),
('6d975670-5361-4dfa-8dea-a7c9192229b9','木筆花','吳融','唐','唐诗','tang','','[]','嫩如新竹管初齊，粉膩紅輕樣可攜。',32,'全唐诗/poet.tang.38000.json','["嫩如新竹管初齊，粉膩紅輕樣可攜。", "誰與詩人偎檻看，好於牋墨併分題。"]'),
('8cd539f8-81df-4b70-ae80-d5178dba4c76','淛東筵上有寄','吳融','唐','唐诗','tang','','[]','襄王席上一神仙，眼色相當語不傳。',64,'全唐诗/poet.tang.38000.json','["襄王席上一神仙，眼色相當語不傳。", "見了又休真似夢，坐來雖近遠於天。", "隴禽有意猶能說，江月無心也解圓。", "更被東風勸惆悵，落花時節定翩翩。"]'),
('0f911f79-05f7-455b-89d8-84be9d19a0a9','富水驛東楹有人題詩','吳融','唐','唐诗','tang','','[]','繡纓霞翼兩鴛鴦，金島銀川是故鄉。',64,'全唐诗/poet.tang.38000.json','["繡纓霞翼兩鴛鴦，金島銀川是故鄉。", "只合雙飛便雙死，豈悲相失與相忘。", "煙花夜泊紅蕖膩，蘭渚春遊碧草芳。", "何事遽驚雲雨別，秦山楚水兩乖張。"]'),
('8e2b7d0f-57b1-416f-bcd4-525ba34fd7d1','上巳日','吳融','唐','唐诗','tang','','[]','本學多情劉武威，尋花傍水看春暉。',32,'全唐诗/poet.tang.38000.json','["本學多情劉武威，尋花傍水看春暉。", "無端遇著傷心事，贏得淒涼索漠歸。"]'),
('b4f49f27-3a23-416f-8e2b-24a1dbdf0445','隋堤','吳融','唐','唐诗','tang','','[]','搔首隋堤落日斜，已無餘柳可藏鴉。',64,'全唐诗/poet.tang.38000.json','["搔首隋堤落日斜，已無餘柳可藏鴉。", "岸傍昔道牽龍艦，河底今來走犢車。", "曾笑陳家歌玉樹，却隨後主看瓊花。", "四方正是無虞日，誰信黎陽有古家。"]'),
('d7e99c8f-cda0-4dc3-a195-4b0c015a2e3f','寄杜先生詩','孫偓','唐','唐诗','tang','','[]','蜀國信難遇，楚鄉心更愁。',36,'全唐诗/poet.tang.38000.json','["蜀國信難遇，楚鄉心更愁。", "我行同范蠡，師舉效浮丘。", "他日相逢處，多應在十洲。"]'),
('17a7cdce-d717-479f-aae5-f1cb79fb2236','贈南嶽僧全玭','孫偓','唐','唐诗','tang','','["\u8861\u5c71"]','窠居過後更何人，傳得如來法印真。',32,'全唐诗/poet.tang.38000.json','["窠居過後更何人，傳得如來法印真。", "昨日祝融峰下見，草衣便是雪山□。"]'),
('c2e28eaf-9ae7-4e63-842a-339ac012bb77','荅門生王渙李德鄰趙光胤王拯長句','孫偓','唐','唐诗','tang','','[]','謬持文柄得時賢，粉署清華次第遷。',64,'全唐诗/poet.tang.38000.json','["謬持文柄得時賢，粉署清華次第遷。", "昔歲策名皆健筆，今朝稱職並同年。", "各懷器業寧推讓，俱上青霄肯後先。", "何事老夫猶賦詠，欲將酬和永留傳。"]'),
('be8f904b-9a2c-4607-9b72-0c4977713b7c','句','孫偓','唐','唐诗','tang','','[]','好是步虛明月夜，瑞爐蜚下醮壇前。',16,'全唐诗/poet.tang.38000.json','["好是步虛明月夜，瑞爐蜚下醮壇前。"]'),
('51079f37-b3f8-4287-9494-3bfda3a83e4c','禁林聞曉鶯','陸扆','唐','唐诗','tang','','[]','曙色分層漢，鶯聲繞上林。',72,'全唐诗/poet.tang.38000.json','["曙色分層漢，鶯聲繞上林。", "報花開瑞錦，催柳綻黃金。", "斷續隨風遠，間關送月沈。", "語當溫樹近，飛覺禁園深。", "繡戶驚殘夢，瑤池囀好音。", "願將棲息意，從此沃天心。"]'),
('1b2c6661-3cd4-488e-b671-b75ef2f40418','句','陸扆','唐','唐诗','tang','','[]','今秋已約天台月。',8,'全唐诗/poet.tang.38000.json','["今秋已約天台月。"]'),
('d1469ba6-9f93-46b8-82bd-af8816362dcb','華州牓寄諸門生','薛昭緯','唐','唐诗','tang','','[]','時君過聽委平衡，粉署華燈到曉明。',54,'全唐诗/poet.tang.38000.json','["時君過聽委平衡，粉署華燈到曉明。", "開卷固難窺浩汗，執衡空欲慕公平。", "機雲筆舌臨文健，沈宋章篇發詠清。", "自笑觀光輝。"]'),
('4e5c503f-406c-4bf1-a9b7-e02c65a08818','謝銀工','薛昭緯','唐','唐诗','tang','','[]','一楪氈根數十皴，盤中猶更有紅鱗。',32,'全唐诗/poet.tang.38000.json','["一楪氈根數十皴，盤中猶更有紅鱗。", "早知文字多辛苦，悔不當初學冶銀。"]'),
('44208aa2-fc56-4fac-a8b2-eb1a52bce8d1','閑居即事','陸翱','唐','唐诗','tang','','[]','衰柳迷隋苑，衡門啼暮鴉。',48,'全唐诗/poet.tang.38000.json','["衰柳迷隋苑，衡門啼暮鴉。", "茅廚煙不動，書牖日空斜。", "悔下東山石，貧於南阮家。", "沈憂損神慮，萱草自開花。"]'),
('34f8963b-77e0-4296-97b1-2f81576ca377','趙氏北樓','陸翱','唐','唐诗','tang','','[]','慇懃趙公子，良夜竟相留。',48,'全唐诗/poet.tang.38000.json','["慇懃趙公子，良夜竟相留。", "朗月生東海，仙娥在北樓。", "酒闌珠露滴，歌逈石城秋。", "本爲愁人設，愁人到曉愁。"]'),
('a30231d3-d12f-4ca4-809c-31fe9b38cc5f','題馬嵬驛','狄歸昌','唐','唐诗','tang','','[]','馬嵬煙柳正依依，重見鑾輿幸蜀歸。',32,'全唐诗/poet.tang.38000.json','["馬嵬煙柳正依依，重見鑾輿幸蜀歸。", "泉下阿蠻應有語，這回休更怨楊妃。"]'),
('b669fb21-e6e3-472a-aaa5-75cae8e0b60b','蜀中登第荅李搏六韻','裴廷裕','唐','唐诗','tang','','[]','何勞問我成都事，亦報君知便納降。',96,'全唐诗/poet.tang.38000.json','["何勞問我成都事，亦報君知便納降。", "蜀柳籠堤煙矗矗，海棠當戶燕雙雙。", "富春不並窮師子，濯錦全勝旱曲江。", "高捲絳紗揚氏宅，半垂紅袖薛濤牕。", "浣花泛鷁詩千首，靜衆尋梅酒百缸。", "若說弦歌與風景，主人兼是碧油幢。"]'),
('c0abe9d3-f8be-4d57-b247-fdc70924165d','偶題','裴廷裕','唐','唐诗','tang','','[]','微雨微風寒食節，半開半合木蘭花。',32,'全唐诗/poet.tang.38000.json','["微雨微風寒食節，半開半合木蘭花。", "看花倚柱終朝立，却似淒淒不在家。"]'),
('ab1a09fd-044a-4a36-9d55-be31dc097352','閑宵望月','李沇','唐','唐诗','tang','','[]','卷箔舒紅茵，當軒翫明月。',72,'全唐诗/poet.tang.38000.json','["卷箔舒紅茵，當軒翫明月。", "懿哉深夜中，靜聽歌初發。", "苔含殿華濕，竹影蟾光潔。", "轉扇來清風，援琴飛白雪。", "行愁景候變，坐恐流芳歇。", "桂影有餘光，蘭燈任將滅。"]'),
('8810649a-95e0-4870-a086-4bc6d5fc3865','醮詞','李沇','唐','唐诗','tang','','[]','犬咬天關閉，彩童呼僊吏。',108,'全唐诗/poet.tang.38000.json','["犬咬天關閉，彩童呼僊吏。", "一封紅篆書，爲奏塵寰事。", "八極鼇柱傾，四溟龍鬣沸。", "長庚冷有芒，文曲澹無氣。", "烏輪不再中，黃沙瘞腥鬼。", "請帝命真官，臨雲啓金匱。", "方與清華宮，重正紫極位。", "曠古雨露恩，安得惜沾施。", "生人血欲盡，攙搶無飽意。"]'),
('b339a0db-62c8-4e5d-b380-e3e5228c9347','巫山高','李沇','唐','唐诗','tang','','[]','抉天心，開地脉，俘動凌霄拂藍碧。',96,'全唐诗/poet.tang.38000.json','["抉天心，開地脉，俘動凌霄拂藍碧。", "襄王端眸望不極，似睹瑤姬長歎息。", "巫妝不治獨西望，暗泣紅蕉抱雲帳。", "君王妬妾夢荆宮，虛把金泥印仙掌。", "江濤迅激如相助，十二獰龍怒行雨。", "崑崙謾有通天路，九峰正在天低處。"]'),
('abe0f4f3-884b-4043-a852-7b47911078e2','夢仙謠','李沇','唐','唐诗','tang','','[]','海宮蹙浪收殘月，挈壺掌事傳更歇。',96,'全唐诗/poet.tang.38000.json','["海宮蹙浪收殘月，挈壺掌事傳更歇。", "銀蟾半墜恨流咽，六鰲披月撼蓬闕。", "九炁真翁騎白犀，臨池靜聽雌蛟啼。", "桂花浥露曙香冷，八窗玉朗驚晨雞。", "裁紗翦羅貼丹鳳，膩霞遠閉瑤山夢。", "露乾欲醉芙蕖塘，迴首驅雲朝正陽。"]'),
('5e7730a6-4bfe-445d-a161-c2a9d6e1515a','秋霖歌','李沇','唐','唐诗','tang','','[]','西方龍兒口猶乳，初解驅雲學行雨。',64,'全唐诗/poet.tang.38000.json','["西方龍兒口猶乳，初解驅雲學行雨。", "縱恣羣陰駕老虬，勺水蹄涔盡奔注。", "葉破苔黃未休滴，膩光透長狂莎色。", "恨無長劒一千仞，劃斷頑雲看晴碧。"]'),
('ee762a37-026e-4a87-b3cf-b1a303316052','方響歌','李沇','唐','唐诗','tang','','[]','敲金扣石聲相凌，遙空冷靜天正澄。',128,'全唐诗/poet.tang.38000.json','["敲金扣石聲相凌，遙空冷靜天正澄。", "寶缾下井轆轤急，小娃弄索傷清冰。", "穿絲透管音未歇，迴風繞指驚泉咽。", "季倫怒擊珊瑚摧，靈芸整鬢步搖折。", "十六葉中侵素光，寒玲震月雜珮璫。", "雲和不覺罷餘怨，蓮峰一夜啼琴姜。", "急節寫商商恨促，秦愁越調逡巡足。", "夢入仙樓戛殘曲，飛霜稜稜上秋玉。"]'),
('6ab07977-848f-4834-a3a2-9ee1d3a97447','荅王渙','裴贄','唐','唐诗','tang','','[]','謬持文柄得時賢，粉署清華次第遷。',64,'全唐诗/poet.tang.38000.json','["謬持文柄得時賢，粉署清華次第遷。", "昔歲策名皆健筆，今朝稱職並同年。", "各懷器業寧推讓，俱上青霄肯後先。", "何事老夫猶賦詠，欲將酬和永留傳。"]'),
('95f7bab0-ee45-4175-b1a2-bcbcc9587d88','薄命妾','盧汝弼','唐','唐诗','tang','','[]','君恩已斷盡成空，追想嬌歡恨莫窮。',64,'全唐诗/poet.tang.38000.json','["君恩已斷盡成空，追想嬌歡恨莫窮。", "長爲蕣花光曉日，誰知團扇送秋風。", "黃金買賦心徒切，清路飛塵信莫通。", "閑凭玉欄思舊事，幾回春暮泣殘紅。"]'),
('ae14cbbe-4641-4d08-aa99-bc02c48284e0','秋夕寓居精舍書事','盧汝弼','唐','唐诗','tang','','[]','葉滿苔堦杵滿城，此中多恨恨難平。',64,'全唐诗/poet.tang.38000.json','["葉滿苔堦杵滿城，此中多恨恨難平。", "疎簷看織蠨蛸網，暗隙愁聽蟋蟀聲。", "醉臥欲拋羈客思，夢歸偏動故鄉情。", "覺來獨步長廊下，半夜西風吹月明。"]'),
('66a93f31-272a-4a2a-acc3-e3e586542d9e','聞雁','盧汝弼','唐','唐诗','tang','','[]','秋風蕭瑟靜埃氛，邊雁迎風響咽羣。',64,'全唐诗/poet.tang.38000.json','["秋風蕭瑟靜埃氛，邊雁迎風響咽羣。", "瀚海應嫌霜下早，湘川偏愛草初薰。", "蘆洲宿處依沙岸，榆塞飛時度晚雲。", "何處最添羈客恨，竹窗殘月酒醒聞。"]'),
('9dee1d3b-d968-43ce-8913-51b25cc2fe9c','鴛鴦','盧汝弼','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','雙浮雙浴傍苔磯，蓼浦蘭臯繡帳幃。',64,'全唐诗/poet.tang.38000.json','["雙浮雙浴傍苔磯，蓼浦蘭臯繡帳幃。", "長羨鷺鷥能潔白，不隨鸂鶒鬬毛衣。", "霞侵綠渚香衾暖，樓倚青雲殿瓦飛。", "應笑隨陽沙漠雁，洞庭煙暖又思歸。"]'),
('75aa294d-ec72-4ba9-a8e7-cfced83d3833','和李秀才邊庭四時怨 一','盧汝弼','唐','唐诗','tang','','[]','春風昨夜到榆關，故國煙花想已殘。',32,'全唐诗/poet.tang.38000.json','["春風昨夜到榆關，故國煙花想已殘。", "少婦不知歸不得，朝朝應上望夫山。"]'),
('0d3cea35-013e-4bb6-bcde-944e9bd4b7bb','和李秀才邊庭四時怨 二','盧汝弼','唐','唐诗','tang','','[]','盧龍塞外草初肥，雁乳平蕪曉不飛。',32,'全唐诗/poet.tang.38000.json','["盧龍塞外草初肥，雁乳平蕪曉不飛。", "鄉國近來音信斷，至今猶自著寒衣。"]'),
('fd92f7fc-9acf-4083-94de-28858dc59b6c','和李秀才邊庭四時怨 三','盧汝弼','唐','唐诗','tang','','[]','八月霜飛柳半黃，蓬根吹斷雁南翔。',32,'全唐诗/poet.tang.38000.json','["八月霜飛柳半黃，蓬根吹斷雁南翔。", "隴頭流水關山月，泣上龍堆望故鄉。"]'),
('77561049-4d06-4e15-b0db-12faa3717e20','和李秀才邊庭四時怨 四','盧汝弼','唐','唐诗','tang','','["\u751f\u6d3b", "\u8fb9\u585e"]','朔風吹雪透刀瘢，飲馬長城窟更寒。',32,'全唐诗/poet.tang.38000.json','["朔風吹雪透刀瘢，飲馬長城窟更寒。", "半夜火來知有敵，一時齊保賀蘭山。"]'),
('06bebd1b-f5db-48a8-95ed-cf8147ca0c30','山居即事二首 一','陸希聲','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','君山蒼翠接青冥，東走洮湖上洞庭。',64,'全唐诗/poet.tang.38000.json','["君山蒼翠接青冥，東走洮湖上洞庭。", "茅屋向陽梳白髮，竹窓深夜誦丹經。", "湧泉回泬魚龍氣，怪石驚騰鳥獸形。", "爲問前時金馬客，此焉還作少微星。"]'),
('5cf9d20d-b287-4b47-9779-f201b993f5e6','山居即事二首 二','陸希聲','唐','唐诗','tang','','[]','不是幽棲矯性靈，從來無意在羶腥。',64,'全唐诗/poet.tang.38000.json','["不是幽棲矯性靈，從來無意在羶腥。", "滿川風物供高枕，四合雲山借畫屏。", "五鹿歸來驚嶽嶽，孤鴻飛去入冥冥。", "君陽遁叟何爲樂，一炷清香兩卷經。"]'),
('800dcdad-ce26-4afa-aca7-4aa715a84780','陽羨雜詠十九首 苦竹逕','陸希聲','唐','唐诗','tang','','[]','山前無數碧琅玕，一逕清森五月寒。',32,'全唐诗/poet.tang.38000.json','["山前無數碧琅玕，一逕清森五月寒。", "世上何人憐苦節，應須細問子猷看。"]'),
('f30743af-3dd9-464d-92cc-4952f5a2e383','陽羨雜詠十九首 梅花塢','陸希聲','唐','唐诗','tang','','[]','凍蘂凝香色豔新，小山深塢伴幽人。',32,'全唐诗/poet.tang.38000.json','["凍蘂凝香色豔新，小山深塢伴幽人。", "知君有意凌寒色，羞共千花一樣春。"]'),
('6192f742-8d10-4de6-a325-3e53989f23ea','陽羨雜詠十九首 石兕臺','陸希聲','唐','唐诗','tang','','[]','大河波浪激潼關，青兕胡爲伏此山。',32,'全唐诗/poet.tang.38000.json','["大河波浪激潼關，青兕胡爲伏此山。", "遙想楚王雲夢澤，蜺旌羽蓋定空還。"]'),
('14054525-6b59-464a-a56e-998ecbfdb7bd','陽羨雜詠十九首 講易臺','陸希聲','唐','唐诗','tang','','[]','年逾知命志尤堅，獨向青山更絕編。',32,'全唐诗/poet.tang.38000.json','["年逾知命志尤堅，獨向青山更絕編。", "天下有山山有水，養蒙肥遯正翛然。"]'),
('c45ab6e9-6cb3-4857-87b4-c48311f8ea3d','陽羨雜詠十九首 觀魚亭','陸希聲','唐','唐诗','tang','','[]','惠施徒自學多方，謾說觀魚理未長。',32,'全唐诗/poet.tang.38000.json','["惠施徒自學多方，謾說觀魚理未長。", "不得莊生濠上旨，江湖何以見相忘。"]'),
('2220dba0-98e7-49d1-9d03-0912fd030a58','陽羨雜詠十九首 綠雲亭','陸希聲','唐','唐诗','tang','','[]','六月清涼綠樹陰，小亭高臥滌煩襟。',32,'全唐诗/poet.tang.38000.json','["六月清涼綠樹陰，小亭高臥滌煩襟。", "羲皇向上何人到，永日時時弄素琴。"]'),
('ce4483a8-143d-482d-88b8-40b3247c9ad6','陽羨雜詠十九首 清輝堂','陸希聲','唐','唐诗','tang','','[]','野人心地本無機，爲愛茅簷倚翠微。',32,'全唐诗/poet.tang.38000.json','["野人心地本無機，爲愛茅簷倚翠微。", "盡日尊前誰是客，秋山含水有清輝。"]'),
('5c998f57-01cf-4aa1-bc2f-eaa34135cde5','陽羨雜詠十九首 觀妙庵','陸希聲','唐','唐诗','tang','','[]','妙理難觀旨甚深，欲知無欲是無心。',32,'全唐诗/poet.tang.38000.json','["妙理難觀旨甚深，欲知無欲是無心。", "茅庵不異人間世，河上真人自可尋。"]'),
('36aa1b8b-216c-4585-b643-8c7ba73aaf15','陽羨雜詠十九首 西陽亭','陸希聲','唐','唐诗','tang','','[]','隔林殘日照孤亭，玄[晏]先生酒未醒。',34,'全唐诗/poet.tang.38000.json','["隔林殘日照孤亭，玄[晏]先生酒未醒。", "入夜莫愁迷下路，昔人猶在逐流螢。"]'),
('44c3232f-d3e4-4b94-b8e5-512c5c8b999b','陽羨雜詠十九首 弄雲亭','陸希聲','唐','唐诗','tang','','[]','自知無業致吾君，只向春山弄白雲。',32,'全唐诗/poet.tang.38000.json','["自知無業致吾君，只向春山弄白雲。", "已共此山私斷當，不須轉轍重移文。"]'),
('ad6c32b3-a437-4571-912a-4fdda5bdf8fd','陽羨雜詠十九首 伏龜堂','陸希聲','唐','唐诗','tang','','[]','盤崖蹙縮似靈龜，鬼谷先生隱遁時。',32,'全唐诗/poet.tang.38000.json','["盤崖蹙縮似靈龜，鬼谷先生隱遁時。", "不獨卷懷經世志，白雲流水是心期。"]'),
('fcb67ad9-7fc7-41a8-a309-bf750154b940','陽羨雜詠十九首 桃花谷','陸希聲','唐','唐诗','tang','','[]','君陽山下足春風，滿谷仙桃照水紅。',32,'全唐诗/poet.tang.38000.json','["君陽山下足春風，滿谷仙桃照水紅。", "何必武陵源上去，澗邊好過落花中。"]'),
('24a890c4-ba5a-4015-9f0a-ee9d090cf577','陽羨雜詠十九首 含桃圃','陸希聲','唐','唐诗','tang','','[]','小圃初晴風露光，含桃花發滿山香。',32,'全唐诗/poet.tang.38000.json','["小圃初晴風露光，含桃花發滿山香。", "看花對酒心無事，倍覺春來白日長。"]'),
('9341ff8a-0a80-4ada-b691-cf807756f540','陽羨雜詠十九首 茗坡','陸希聲','唐','唐诗','tang','','[]','二月山家穀雨天，半坡芳茗露華鮮。',32,'全唐诗/poet.tang.38000.json','["二月山家穀雨天，半坡芳茗露華鮮。", "春醒酒病兼消渴，惜取新芽旋摘煎。"]'),
('6df65f7d-a903-47ef-b862-6fe3c40e6ebc','陽羨雜詠十九首 松嶺','陸希聲','唐','唐诗','tang','','[]','嶺上青松手自栽，已能蒼翠映莓苔。',32,'全唐诗/poet.tang.38000.json','["嶺上青松手自栽，已能蒼翠映莓苔。", "歲寒本是君家事，好送清風月下來。"]'),
('ae3a3d33-932e-4691-a17a-cacfe9c6dbc7','陽羨雜詠十九首 桃溪','陸希聲','唐','唐诗','tang','','[]','芳草霏霏遍地齊，桃花脉脉自成谿。',32,'全唐诗/poet.tang.38000.json','["芳草霏霏遍地齊，桃花脉脉自成谿。", "也知百舌多言語，任向春風盡意啼。"]'),
('02dcd9ba-5798-428a-bfa1-0014f397bba4','陽羨雜詠十九首 李徑','陸希聲','唐','唐诗','tang','','[]','一徑穠芳萬蘂攢，風吹雨打未摧殘。',32,'全唐诗/poet.tang.38000.json','["一徑穠芳萬蘂攢，風吹雨打未摧殘。", "憐君盡向高枝發，應爲行人要整冠。"]'),
('c9d20f81-2971-483f-a8a0-976229f31a78','陽羨雜詠十九首 鴻盤','陸希聲','唐','唐诗','tang','','[]','落落飛鴻漸始盤，青雲起處剩須看。',32,'全唐诗/poet.tang.38000.json','["落落飛鴻漸始盤，青雲起處剩須看。", "如今天路多矰繳，縱使銜蘆去也難。"]'),
('7ddc6155-8760-4ca6-b1f0-7d8a8427202c','陽羨雜詠十九首 偃月嶺','陸希聲','唐','唐诗','tang','','[]','山嶺依稀偃月形，數層倚石疊空青。',32,'全唐诗/poet.tang.38000.json','["山嶺依稀偃月形，數層倚石疊空青。", "幾迴雪夜寒光積，直似金光照戶庭。"]'),
('c4e6d77e-c59c-4936-ab38-0438aa343531','寄{巩/言}光上人','陸希聲','唐','唐诗','tang','','[]','筆下龍蛇似有神，天池雷雨變逡巡。',32,'全唐诗/poet.tang.38000.json','["筆下龍蛇似有神，天池雷雨變逡巡。", "寄言昔日不龜手，應念江頭洴澼人。"]'),
('d9530bc5-739e-463e-9443-e6d2f962b859','喜杜荀鶴及第','李昭象','唐','唐诗','tang','','[]','深巖貧復病，榜到見君名。',48,'全唐诗/poet.tang.38000.json','["深巖貧復病，榜到見君名。", "貧病渾如失，山川頓覺清。", "一春新酒興，四海舊詩聲。", "日使能吟者，西來步步輕。"]'),
('c273f671-d8df-4616-82ab-fd76a4e56412','赴舉出山留寄山居鄭參軍','李昭象','唐','唐诗','tang','','[]','還如費冠卿，向此振高名。',48,'全唐诗/poet.tang.38000.json','["還如費冠卿，向此振高名。", "肯羨魚鬚美，長誇鶴氅輕。", "理琴寒指倦，試藥黑髭生。", "時泰難雲臥，隨看急詔行。"]'),
('5ad567df-9680-46a8-86f8-f15ee202e990','題顧正字谿居','李昭象','唐','唐诗','tang','','[]','高敞吟軒近釣灣，塵中來似出人間。',64,'全唐诗/poet.tang.38000.json','["高敞吟軒近釣灣，塵中來似出人間。", "若教明月休生桂，應得危時共掩關。", "春酒夜棊難放客，短籬疎竹不遮山。", "莫誇恬淡勝榮祿，雁引行高未許閑。"]'),
('8c3a8555-4d37-4f36-ae6d-a043f6e71302','寄獻山中顧公員外','李昭象','唐','唐诗','tang','','[]','抽却朝簪著釣蓑，近來聲迹轉巍峩。',64,'全唐诗/poet.tang.38000.json','["抽却朝簪著釣蓑，近來聲迹轉巍峩。", "祥麟避網雖山野，丹鳳銜書即薜蘿。", "乍隱文章情更逸，久閑經濟術翻多。", "深慙未副吹噓力，竟困風埃爭奈何。"]'),
('0ed9d896-ba61-4976-bd43-d78f2b60c2e1','山中寄崔諫議','李昭象','唐','唐诗','tang','','[]','半生猨鳥共山居，吟月吟風兩鬢疎。',64,'全唐诗/poet.tang.38000.json','["半生猨鳥共山居，吟月吟風兩鬢疎。", "新句未嘗忘教化，上才爭忍不吹噓。", "全家欲去干戈後，大國中興禮樂初。", "從此升騰休說命，秪希公道數封書。"]'),
('4b182de3-f12c-43dd-808f-2bc42a3d7d0a','學仙詞寄顧雲','李昭象','唐','唐诗','tang','','[]','記得初傳九轉方，碧雲峰下祝虛皇。',64,'全唐诗/poet.tang.38000.json','["記得初傳九轉方，碧雲峰下祝虛皇。", "丹砂未熟心徒切，白日難留鬢欲蒼。", "無路洞天尋穆滿，有時人世美劉郎。", "仙人恩重何由報，焚盡星壇午夜香。"]'),
('1687cdb4-4e08-4573-8b9e-a20e5d811564','寄尉遲侍御','李昭象','唐','唐诗','tang','','["\u4e5d\u534e\u5c71"]','我眠青嶂弄澄潭，君戴貂蟬白玉篸。',32,'全唐诗/poet.tang.38000.json','["我眠青嶂弄澄潭，君戴貂蟬白玉篸。", "應向謝公樓上望，九華山色在西南。"]'),
('e4d9dd37-c469-4587-be44-f3b7d15fa9cd','招西洞道者','李昭象','唐','唐诗','tang','','[]','危峰抹黛夾晴川，樹簇紅英草碧煙。',32,'全唐诗/poet.tang.38000.json','["危峰抹黛夾晴川，樹簇紅英草碧煙。", "樵客雲僧兩無事，此中堪去覓靈仙。"]'),
('a47958f5-3dba-4ef8-abca-4c0eafbfb390','句','李昭象','唐','唐诗','tang','','[]','投文得仕而今少，佩印還家古所榮。',16,'全唐诗/poet.tang.38000.json','["投文得仕而今少，佩印還家古所榮。"]'),
('71f45efb-b1f0-4ca9-af27-f5eaefb6b872','夏雨','王駕','唐','唐诗','tang','','[]','非惟消旱暑，且喜救生民。',48,'全唐诗/poet.tang.38000.json','["非惟消旱暑，且喜救生民。", "天地如蒸濕，園林似却春。", "洗風清枕簟，換夜失埃塵。", "又作豐年望，田夫笑向人。"]'),
('10a0693c-971f-4f3d-959d-01dcf02f00f8','古意','王駕','唐','唐诗','tang','','["\u601d\u5ff5", "\u5987\u5973"]','夫戍蕭關妾在吳，西風吹妾妾憂夫。',32,'全唐诗/poet.tang.38000.json','["夫戍蕭關妾在吳，西風吹妾妾憂夫。", "一行書信千行淚，寒到君邊衣到無。"]'),
('e3e0e059-b731-486e-9932-4e410ca59707','社日','王駕','唐','唐诗','tang','','[]','鵝湖山下稻粱肥，豚柵雞棲半掩扉。',32,'全唐诗/poet.tang.38000.json','["鵝湖山下稻粱肥，豚柵雞棲半掩扉。", "桑柘影斜春社散，家家扶得醉人歸。"]'),
('ef12d1aa-b50f-4bf6-a5e1-b1c3a92aecab','雨晴','王駕','唐','唐诗','tang','','[]','雨前初見花間蘂，雨後兼無葉裏花。',32,'全唐诗/poet.tang.38000.json','["雨前初見花間蘂，雨後兼無葉裏花。", "蛺蝶飛來過墻去，却疑春色在鄰家。"]'),
('8711393b-5b9e-490f-9f61-6d30e5b101b2','亂後曲江','王駕','唐','唐诗','tang','','[]','憶昔爭遊曲水濱，未春長有探春人。',32,'全唐诗/poet.tang.38000.json','["憶昔爭遊曲水濱，未春長有探春人。", "遊春人盡空池在，直至春深不似春。"]'),
('7a75d708-2ce5-4b0f-8108-a1c67e394bf5','過故友居','王駕','唐','唐诗','tang','','[]','鄰笛寒吹日落初，舊居今已別人居。',32,'全唐诗/poet.tang.38000.json','["鄰笛寒吹日落初，舊居今已別人居。", "亂來兒姪皆分散，惆悵僧房認得書。"]'),
('f0cd0195-afa4-4392-b8f1-a67da7843bc9','上裴侍郎','王渙','唐','唐诗','tang','','[]','青衿七十牓三年，建禮含香次第遷。',64,'全唐诗/poet.tang.38000.json','["青衿七十牓三年，建禮含香次第遷。", "珠彩下連星錯落，桂花曾對月嬋娟。", "玉經磨琢多成器，劍拔沈埋更倚天。", "應念銜恩最深者，春來爲壽拜尊前。"]'),
('8a5c5ce7-5788-4286-8b7d-d7db10c8a7b3','悼亡','王渙','唐','唐诗','tang','','[]','春來得病夏來加，深掩粧窗臥碧紗。',64,'全唐诗/poet.tang.38000.json','["春來得病夏來加，深掩粧窗臥碧紗。", "爲怯暗藏秦女扇，怕驚愁度阿香車。", "腰肢暗想風欺柳，粉態難忘露洗花。", "今日青門葬君處，亂蟬衰草夕陽斜。"]'),
('1529dd5b-e0dc-4dd0-9712-b220d6247679','惆悵詩十二首 一','王渙','唐','唐诗','tang','','[]','八蠶薄絮鴛鴦綺，半夜佳期並枕眠。',32,'全唐诗/poet.tang.38000.json','["八蠶薄絮鴛鴦綺，半夜佳期並枕眠。", "鐘動紅娘喚歸去，對人勻淚拾金鈿。"]'),
('67a3b70f-73a9-464c-9b49-2a47f65418f5','惆悵詩十二首 二','王渙','唐','唐诗','tang','','[]','李夫人病已經秋，漢武看來不舉頭。',32,'全唐诗/poet.tang.38000.json','["李夫人病已經秋，漢武看來不舉頭。", "得所濃華銷歇盡，楚魂湘血一生休。"]'),
('513394b7-8453-4433-b57a-fadc5741b1a4','惆悵詩十二首 三','王渙','唐','唐诗','tang','','[]','謝家池館花籠月，蕭寺房廊竹颭風。',32,'全唐诗/poet.tang.38000.json','["謝家池館花籠月，蕭寺房廊竹颭風。", "夜半酒醒憑檻立，所思多在別離中。"]'),
('e2bbbd83-77c2-4da0-910b-4d0e7501f968','惆悵詩十二首 四','王渙','唐','唐诗','tang','','[]','隋師戰艦欲亡陳，國破應難保此身。',32,'全唐诗/poet.tang.38000.json','["隋師戰艦欲亡陳，國破應難保此身。", "訣別徐郎淚如雨，鏡鸞分後屬何人。"]'),
('57752e11-7bd5-4a19-9ac7-ff9dbc9315e2','惆悵詩十二首 五','王渙','唐','唐诗','tang','','[]','七夕瓊筵隨事陳，兼花連蔕共傷神。',32,'全唐诗/poet.tang.38000.json','["七夕瓊筵隨事陳，兼花連蔕共傷神。", "蜀王殿裏三更月，不見驪山私語人。"]'),
('61089543-ac89-40b9-9937-941e2dea2d3f','惆悵詩十二首 六','王渙','唐','唐诗','tang','','[]','夜寒春病不勝懷，玉瘦花啼萬事乖。',32,'全唐诗/poet.tang.38000.json','["夜寒春病不勝懷，玉瘦花啼萬事乖。", "薄倖檀郎斷芳信，驚嗟猶夢合歡鞋。"]'),
('f92fe766-715c-4c2f-a670-26733f93ae86','惆悵詩十二首 七','王渙','唐','唐诗','tang','','[]','嗚咽離聲管吹秋，妾身今日爲君休。',32,'全唐诗/poet.tang.38000.json','["嗚咽離聲管吹秋，妾身今日爲君休。", "齊奴不說平生事，忍看花枝謝玉樓。"]'),
('19f59a00-3f8e-40fa-8da9-82006389ae09','惆悵詩十二首 八','王渙','唐','唐诗','tang','','[]','青絲一綹墮雲鬟，金翦刀鳴不忍看。',32,'全唐诗/poet.tang.38000.json','["青絲一綹墮雲鬟，金翦刀鳴不忍看。", "持謝君王寄幽怨，可能從此住人間。"]'),
('a78c4ea2-8b9a-45a1-bf78-0d359d7f05ba','惆悵詩十二首 九','王渙','唐','唐诗','tang','','[]','陳宮興廢事難期，三閣空餘綠草基。',32,'全唐诗/poet.tang.38000.json','["陳宮興廢事難期，三閣空餘綠草基。", "狎客淪亡麗華死，他年江令獨來時。"]'),
('2a96ed3a-d4cb-4a50-bc67-e1caada90086','惆悵詩十二首 十','王渙','唐','唐诗','tang','','[]','晨肇重來路已迷，碧桃花謝武陵溪。',32,'全唐诗/poet.tang.38000.json','["晨肇重來路已迷，碧桃花謝武陵溪。", "仙山目斷無尋處，流水潺湲日漸西。"]'),
('ec9adba0-d22c-4eec-ab55-fdf3db6c6522','惆悵詩十二首 十一','王渙','唐','唐诗','tang','','[]','少卿降北子卿還，朔野離觴慘別顏。',32,'全唐诗/poet.tang.38000.json','["少卿降北子卿還，朔野離觴慘別顏。", "却到茂陵唯一慟，節毛零落鬢毛斑。"]'),
('76c71596-50f6-4177-9271-78ac738e5156','惆悵詩十二首 十二','王渙','唐','唐诗','tang','','[]','夢裏分明入漢宮，覺來燈背錦屏空。',32,'全唐诗/poet.tang.38000.json','["夢裏分明入漢宮，覺來燈背錦屏空。", "紫臺月落關山曉，腸斷君恩信畫工。"]'),
('6600c2b0-ba46-44c2-a192-c7f572af908f','江上雨','戴司顏','唐','唐诗','tang','','[]','非不欲前去，此情非自由。',48,'全唐诗/poet.tang.38000.json','["非不欲前去，此情非自由。", "星辰照何處，風雨送涼秋。", "寒鎖空江夢，聲隨黃葉愁。", "蕭蕭猶未已，早晚去蘋洲。"]'),
('a4c4aa1a-063e-41fa-a7da-5caf06bcb263','塞上','戴司顏','唐','唐诗','tang','','[]','空蹟晝蒼茫，沙腥古戰場。',48,'全唐诗/poet.tang.38000.json','["空蹟晝蒼茫，沙腥古戰場。", "逢春多霰雪，生計在牛羊。", "冷角吹鄉淚，乾榆落夢牀。", "從來山水客，誰謂到漁陽。"]'),
('8e453ccc-033a-460c-bc34-6297096d2a3e','句','戴司顏','唐','唐诗','tang','','[]','遠來朝鳳闕，歸去戀元侯。',12,'全唐诗/poet.tang.38000.json','["遠來朝鳳闕，歸去戀元侯。"]'),
('a6225148-9783-4fae-a11a-638a836c3345','投謝錢武肅','吳仁璧','唐','唐诗','tang','','[]','東門上相好知音，數盡臺前郭隗金。',64,'全唐诗/poet.tang.38000.json','["東門上相好知音，數盡臺前郭隗金。", "累重雖然容食椹，力微無計報焚林。", "弊貂不稱芙蓉幕，衰朽仍慚玳瑁簪。", "十里溪光一山月，可堪從此負歸心。"]'),
('e7300777-f722-492e-9120-8b302e16f40e','客路','吳仁璧','唐','唐诗','tang','','[]','人寰急景如波委，客路浮雲似蓋輕。',32,'全唐诗/poet.tang.38000.json','["人寰急景如波委，客路浮雲似蓋輕。", "回首故山天外碧，十年無計却歸耕。"]'),
('ce95ef0c-d519-4048-a95d-6331cbc069e1','南徐題友人郊居','吳仁璧','唐','唐诗','tang','','[]','門前樵徑連江寺，岸下漁磯繫海槎。',32,'全唐诗/poet.tang.38000.json','["門前樵徑連江寺，岸下漁磯繫海槎。", "待到秋深好時節，與君長醉隱侯家。"]'),
('def00dc7-7fef-4d6f-8608-fadfd4833412','讀度人經寄鄭仁表','吳仁璧','唐','唐诗','tang','','[]','身雖一旦塵中老，名擬三清會裏題。',32,'全唐诗/poet.tang.38000.json','["身雖一旦塵中老，名擬三清會裏題。", "二午九齋餘日在，請君相伴醉如泥。"]'),
('4f0a9186-8536-4c5b-9fc6-ad83a41eea17','秋日聽僧彈琴','吳仁璧','唐','唐诗','tang','','[]','金徽玉軫韻泠然，言下浮生指下泉。',32,'全唐诗/poet.tang.38000.json','["金徽玉軫韻泠然，言下浮生指下泉。", "恰稱秋風西北起，一時吹入碧湘煙。"]'),
('64db94a8-e2ac-4d22-bb87-89cdf4d9c655','賈誼','吳仁璧','唐','唐诗','tang','','[]','扶持一疏滿遺編，漢陛前頭正少年。',32,'全唐诗/poet.tang.38000.json','["扶持一疏滿遺編，漢陛前頭正少年。", "誰道恃才輕絳灌，却將惆悵弔湘川。"]'),
('72547543-820f-4314-ae4a-63bca51c0e94','春雪','吳仁璧','唐','唐诗','tang','','[]','雪霽凝光入坐寒，天明猶自臥袁安。',32,'全唐诗/poet.tang.38000.json','["雪霽凝光入坐寒，天明猶自臥袁安。", "貂裘穿後鶴氅敝，自此風流不足看。"]'),
('c18f51bc-a96d-4c5f-81cb-698da227a65a','衰柳','吳仁璧','唐','唐诗','tang','','[]','金風漸利露珠團，廣陌長堤黛色殘。',32,'全唐诗/poet.tang.38000.json','["金風漸利露珠團，廣陌長堤黛色殘。", "水殿狂遊隋煬帝，一千餘里可堪看。"]'),
('13b24e45-1bc4-4181-bec5-5f9b899e1665','鳳仙花','吳仁璧','唐','唐诗','tang','','[]','香紅嫩綠正開時，冷蝶飢蜂兩不知。',32,'全唐诗/poet.tang.38000.json','["香紅嫩綠正開時，冷蝶飢蜂兩不知。", "此際最宜何處看，朝陽初上碧梧枝。"]'),
('06069c87-167e-4ed7-9ea7-dd39018557e6','金錢花','吳仁璧','唐','唐诗','tang','','[]','淺絳濃香幾朵勻，日鎔金鑄萬家新。',32,'全唐诗/poet.tang.38000.json','["淺絳濃香幾朵勻，日鎔金鑄萬家新。", "堪疑劉寵遺芳在，不許山陰父老貧。"]'),
('780f813e-5083-4589-91a4-fba8b1093425','錢塘鶴','吳仁璧','唐','唐诗','tang','','[]','人間路靄青天半，鼇岫雲生碧海涯。',32,'全唐诗/poet.tang.38000.json','["人間路靄青天半，鼇岫雲生碧海涯。", "雖抱雕籠密扃鑰，可能長在叔倫家。"]'),
('08cccaa5-b327-45e6-8ffa-e1c23cb57a2a','句','吳仁璧','唐','唐诗','tang','','[]','爲惜苔錢妨換砌，因憐山色旋開尊。',64,'全唐诗/poet.tang.38000.json','["爲惜苔錢妨換砌，因憐山色旋開尊。", "高閣煙霞禪客睡，滿城塵土世人忙。", "五龍金角向星斗，三洞玉音愁鬼神。", "蒲草薄裁連蒂白，臙脂濃染半葩紅。"]'),
('368046e7-dbdf-49ce-a257-5cab88ef84e7','奉試麥壟多秀色','汪極','唐','唐诗','tang','','[]','南陌生岐穗，農家樂事多。',48,'全唐诗/poet.tang.38000.json','["南陌生岐穗，農家樂事多。", "塍畦交茂綠，苗實際清和。", "日布玲瓏影，風翻浩蕩波。", "來牟知帝力，含哺有衢歌。"]'),
('1c8ff73f-54be-4139-bd74-11429936dc7b','下第戲狀元崔昭緯','張曙','唐','唐诗','tang','','[]','千里江山陪驥尾，五更風水失龍鱗。',32,'全唐诗/poet.tang.38000.json','["千里江山陪驥尾，五更風水失龍鱗。", "昨夜浣花溪上雨，綠楊芳草爲何人。"]'),
('de9bb8fc-e694-459b-aa97-2a4f892e1e87','贈天台王處士','林嵩','唐','唐诗','tang','','[]','深隱天台不記秋，琴臺長別一何愁。',64,'全唐诗/poet.tang.38000.json','["深隱天台不記秋，琴臺長別一何愁。", "茶煙巖外雲初起，新月潭心釣未收。", "映宇異花叢發好，穿松孤鶴一聲幽。", "赤城不掩高宗夢，寧久懸冠枕瀑流。"]'),
('8eaf97fd-82bb-4651-9dde-9a5a6f78182c','春宮怨','杜荀鶴','唐','唐诗','tang','','["\u5bab\u6028", "\u6625\u5929", "\u5199\u666f", "\u5973\u5b50", "\u5510\u8bd7\u4e09\u767e\u9996", "\u4e94\u8a00\u5f8b\u8bd7"]','早被嬋娟誤，欲妝臨鏡慵。',48,'全唐诗/poet.tang.38000.json','["早被嬋娟誤，欲妝臨鏡慵。", "承恩不在貌，教妾若爲容。", "風暖鳥聲碎，日高花影重。", "年年越溪女，相憶採芙蓉。"]'),
('2b605213-400a-4fae-8b02-d5f020fff1f9','訪道者不遇','杜荀鶴','唐','唐诗','tang','','[]','寂寂白雲門，尋真不遇真。',48,'全唐诗/poet.tang.38000.json','["寂寂白雲門，尋真不遇真。", "祗應松上鶴，便是洞中人。", "藥圃花香異，沙泉鹿跡新。", "題詩留姓字，他日此相親。"]'),
('3f48efb6-6e46-4294-8a8c-0dfabe1c926b','送人遊吳','杜荀鶴','唐','唐诗','tang','','["\u9001\u522b", "\u751f\u6d3b", "\u5e26\u6709\u5730\u540d", "\u5199\u666f", "\u5730\u540d"]','君到姑蘇見，人家盡枕河。',48,'全唐诗/poet.tang.38000.json','["君到姑蘇見，人家盡枕河。", "古宮閑地少，水港小橋多。", "夜市賣菱藕，春船載綺羅。", "遙知未眠月，鄉思在漁歌。"]'),
('ec25b07d-83a2-4fc7-9b44-a2d021f3c61d','送陳昈歸麻川','杜荀鶴','唐','唐诗','tang','','[]','麻川清見底，似入武陵溪。',48,'全唐诗/poet.tang.38000.json','["麻川清見底，似入武陵溪。", "兩岸山相向，三春鳥亂啼。", "酒旗和柳動，僧屋與雲齊。", "即此吾鄉路，懷君夢不迷。"]'),
('d3c0ea30-598d-4d92-ab6e-9c45bff99661','出山','杜荀鶴','唐','唐诗','tang','','[]','病眼看春牓，文場公道開。',48,'全唐诗/poet.tang.38000.json','["病眼看春牓，文場公道開。", "朋人登第盡，白髮出山來。", "處世曾無過，惟天合是媒。", "長安不覺遠，期遂一名迴。"]'),
('3977c028-671d-4e5b-b03c-42c156de4ee1','浙中逢詩友','杜荀鶴','唐','唐诗','tang','','[]','到處有同人，多爲賦與文。',48,'全唐诗/poet.tang.38000.json','["到處有同人，多爲賦與文。", "詩中難得友，湖畔喜逢君。", "凍把城根雪，風開嶽面雲。", "苦吟吟不足，爭忍話離羣。"]'),
('eb18e4f7-84a7-4ab9-a170-e53f8f769697','送友遊吳越','杜荀鶴','唐','唐诗','tang','','["\u9001\u522b", "\u5c71\u5ddd", "\u5199\u666f", "\u7530\u56ed"]','去越從吳過，吳疆與越連。',48,'全唐诗/poet.tang.38000.json','["去越從吳過，吳疆與越連。", "有園多種橘，無水不生蓮。", "夜市橋邊火，春風寺外船。", "此中偏重客，君去必經年。"]'),
('e0c19ec0-06b5-457e-9325-405c59c76dfb','出常山界使回有寄','杜荀鶴','唐','唐诗','tang','','[]','自小即南北，未如今日離。',48,'全唐诗/poet.tang.38000.json','["自小即南北，未如今日離。", "封疆初盡處，人使却回時。", "開口有所忌，此心無以爲。", "行行復垂淚，不稱是男兒。"]'),
('8cf6b268-1434-4b9f-b12e-68c5836e72ab','經廢宅','杜荀鶴','唐','唐诗','tang','','[]','人生當貴盛，修德可延之。',48,'全唐诗/poet.tang.38000.json','["人生當貴盛，修德可延之。", "不慮有今日，爭教無破時。", "蘚斑題字壁，花發帶巢枝。", "何況蒿原上，荒墳與折碑。"]'),
('8b8aac21-df6b-451f-96d3-3303f1971874','登天台寺','杜荀鶴','唐','唐诗','tang','','[]','一到天台寺，高低景旋生。',48,'全唐诗/poet.tang.38000.json','["一到天台寺，高低景旋生。", "共僧巖上坐，見客海邊行。", "野色人耕破，山根浪打鳴。", "忙時向閑處，不覺有閑情。"]'),
('0fc179c0-ecd1-4fa6-9ebd-f39b40c315b5','途中春','杜荀鶴','唐','唐诗','tang','','[]','馬上覽春色，丈夫慙淚垂。',48,'全唐诗/poet.tang.38000.json','["馬上覽春色，丈夫慙淚垂。", "一生看却老，五字未逢知。", "酒力不能久，愁根無可醫。", "明年到今日，公道與誰期。"]'),
('0614bcec-5657-44c7-b153-220240a21948','入關歷陽道中却寄舍弟','杜荀鶴','唐','唐诗','tang','','[]','求名日苦辛，日望日榮親。',48,'全唐诗/poet.tang.38000.json','["求名日苦辛，日望日榮親。", "落葉山中路，秋霖馬上人。", "晨昏知汝道，詩酒衛吾身。", "自笑拋麋鹿，長安擬醉春。"]'),
('ecc59628-86cd-4a41-9d6b-31398e405830','贈歐陽明府','杜荀鶴','唐','唐诗','tang','','[]','賢宰宰斯邑，政聞閭里間。',48,'全唐诗/poet.tang.38000.json','["賢宰宰斯邑，政聞閭里間。", "都緣民訟少，長覺吏徒閑。", "帆落樽前浦，鐘鳴枕上山。", "回舟却惆悵，數宿釣魚灣。"]'),
('ab7d5d6e-a749-4393-a7b3-403e09c2bce5','贈臨上人','杜荀鶴','唐','唐诗','tang','','[]','不計禪兼律，終須入悟門。',48,'全唐诗/poet.tang.38000.json','["不計禪兼律，終須入悟門。", "解空非有自，所得是無言。", "眼豁浮生夢，心澄大道源。", "今來習師者，多鏁教中猿。"]'),
('664c1d81-714c-4d8f-9481-1f69c86dbda7','題戰島僧居','杜荀鶴','唐','唐诗','tang','','[]','師愛無塵地，江心島上居。',48,'全唐诗/poet.tang.38000.json','["師愛無塵地，江心島上居。", "接船求化慣，登陸赴齋疎。", "載士春栽樹，拋生日餧魚。", "入雲蕭帝寺，畢竟欲何如。"]'),
('661af006-05d8-4fa1-92ef-aff15bfb2f9f','別衡州牧','杜荀鶴','唐','唐诗','tang','','[]','朝別使君門，暮投江上村。',48,'全唐诗/poet.tang.38000.json','["朝別使君門，暮投江上村。", "從來無舊分，臨去望何恩。", "行計自不定，此心誰與論。", "秋猿叫寒月，祗欲斷人魂。"]'),
('6a44861d-2a13-4fa1-9fa7-80d051301fb3','送人遊江南','杜荀鶴','唐','唐诗','tang','','[]','滿酌勸君酒，勸君君莫辭。',48,'全唐诗/poet.tang.38000.json','["滿酌勸君酒，勸君君莫辭。", "能禁幾度別，即到白頭時。", "晚岫無雲蔽，春帆有燕隨。", "男兒兩行淚，不欲等閑垂。"]'),
('8cbb68bc-894d-44cc-a54b-8d0ca9a776ae','遊茅山','杜荀鶴','唐','唐诗','tang','','[]','步步入山門，仙家鳥徑分。',48,'全唐诗/poet.tang.38000.json','["步步入山門，仙家鳥徑分。", "漁樵不到處，麋鹿自成羣。", "石面迸出水，松頭穿破雲。", "道人星月下，相次禮茅君。"]'),
('0d0b986f-9d42-437b-8997-32f45f171678','讀友人詩卷','杜荀鶴','唐','唐诗','tang','','[]','冰齒味瑤軸，祗應神鬼知。',48,'全唐诗/poet.tang.38000.json','["冰齒味瑤軸，祗應神鬼知。", "坐當羣靜後，吟到月沈時。", "雪峽猿聲健，風檉鶴立危。", "篇篇一字字，誰復更言詩。"]'),
('755686a4-c246-4f4a-8aa3-1ed6ed237c73','寄從叔','杜荀鶴','唐','唐诗','tang','','[]','三族不當路，長年猶布衣。',48,'全唐诗/poet.tang.38000.json','["三族不當路，長年猶布衣。", "苦吟天與性，直道世將非。", "雁夜愁癡坐，漁鄉老憶歸。", "爲儒皆可立，自是拙時機。"]'),
('9bf3e4fc-67b5-47e6-8f04-91f10b60f541','寄李溥','杜荀鶴','唐','唐诗','tang','','[]','如我如君者，不妨身晚成。',48,'全唐诗/poet.tang.38000.json','["如我如君者，不妨身晚成。", "但從時輩笑，自得古人情。", "共莫更初志，俱期立後名。", "男兒且如此，何用歎平生。"]'),
('bad644ef-316c-4093-8218-58ace0bc7cda','郊居即事投李給事','杜荀鶴','唐','唐诗','tang','','[]','無祿奉晨昏，閑居幾度春。',48,'全唐诗/poet.tang.38000.json','["無祿奉晨昏，閑居幾度春。", "江湖苦吟士，天地最窮人。", "書劒同三友，蓬蒿外四鄰。", "相知不相薦，何以自謀身。"]'),
('c3209a29-b661-4495-adeb-204b0b088579','寄詩友','杜荀鶴','唐','唐诗','tang','','[]','別來春又春，相憶喜相親。',48,'全唐诗/poet.tang.38000.json','["別來春又春，相憶喜相親。", "與我爲同志，如君能幾人。", "何時吟得力，漸老事關身。", "惟有前溪水，年年濯客塵。"]'),
('1dd3d04b-5231-405c-8df1-32b785c03913','題田翁家','杜荀鶴','唐','唐诗','tang','','[]','田翁真快活，婚嫁不離村。',48,'全唐诗/poet.tang.38000.json','["田翁真快活，婚嫁不離村。", "州縣供輸罷，追隨鼓笛喧。", "盤飧同老少，家計共田園。", "自說身無事，應官有子孫。"]'),
('63adc562-56c5-4942-ac1b-4371970a5f50','長安冬日','杜荀鶴','唐','唐诗','tang','','[]','近臘饒風雪，閑房凍坐時。',48,'全唐诗/poet.tang.38000.json','["近臘饒風雪，閑房凍坐時。", "書生教到此，天意轉難知。", "吟苦猿三叫，形枯柏一枝。", "還應公道在，未忍與山期。"]'),
('2a793755-5fbd-447b-91cd-3197e2bcb419','霽後登唐興寺水閣','杜荀鶴','唐','唐诗','tang','','[]','一雨三秋色，蕭條古寺間。',48,'全唐诗/poet.tang.38000.json','["一雨三秋色，蕭條古寺間。", "無端登水閣，有處似家山。", "白日生新事，何時得暫閑。", "將知老僧意，未必戀松關。"]'),
('a072d2b4-4e1c-4397-a587-00baf9d0869d','山中寄友人','杜荀鶴','唐','唐诗','tang','','[]','深山多隙地，無力及耕桑。',48,'全唐诗/poet.tang.38000.json','["深山多隙地，無力及耕桑。", "不是營生拙，都緣覓句忙。", "破窗風翳燭，穿屋月侵牀。", "吾友應相笑，辛勤道未光。"]'),
('1c32accd-b526-401b-9b76-9f9760b7be31','自述','杜荀鶴','唐','唐诗','tang','','[]','四海欲行遍，不知終遇誰。',48,'全唐诗/poet.tang.38000.json','["四海欲行遍，不知終遇誰。", "用心常合道，出語或傷時。", "擬作閑人老，慙無識者嗤。", "如今已無計，祗得苦于詩。"]'),
('d37fc5bd-0158-4e52-a7bb-274688287f02','題江山寺','杜荀鶴','唐','唐诗','tang','','[]','江上山頭寺，景留吟客船。',48,'全唐诗/poet.tang.38000.json','["江上山頭寺，景留吟客船。", "遍遊銷一日，重到是何年。", "沙鳥多翹足，巖僧半露肩。", "爲詩多語澀，喜此得終篇。"]'),
('1871aca0-705a-4455-bbbf-3a19886913c8','秋日旅舍臥病呈所知','杜荀鶴','唐','唐诗','tang','','[]','秋色上庭枝，愁懷切向誰。',48,'全唐诗/poet.tang.38000.json','["秋色上庭枝，愁懷切向誰。", "青雲無勢日，華髮有狂時。", "枕上聞風雨，江南繫別離。", "如何吟到此，此道不聞知。"]'),
('010ec73b-a49e-4ab8-b373-74d281f178ea','秋宿山館','杜荀鶴','唐','唐诗','tang','','[]','山館坐待曉，夜長吟役神。',48,'全唐诗/poet.tang.38000.json','["山館坐待曉，夜長吟役神。", "斜風吹敗葉，寒燭照愁人。", "蘊蓄天然性，澆訛世惡真。", "男兒出門志，不獨爲謀身。"]'),
('8261aa49-fb44-4912-ba0f-de93d45a11ae','贈老僧','杜荀鶴','唐','唐诗','tang','','[]','衆僧尊夏臘，靈嶽遍曾登。',48,'全唐诗/poet.tang.38000.json','["衆僧尊夏臘，靈嶽遍曾登。", "度水手中杖，行山溪畔藤。", "心空默是印，眉白雪爲稜。", "自得巡方道，棲禪老未能。"]'),
('adfe260e-7b9d-4049-9286-d8dca992910e','別舍弟','杜荀鶴','唐','唐诗','tang','','[]','欲住住不得，出門天氣秋。',48,'全唐诗/poet.tang.38000.json','["欲住住不得，出門天氣秋。", "惟知偷拭淚，不忍更回頭。", "此日祗愁老，況身方遠遊。", "孤寒將五字，何以動諸侯。"]'),
('b25d54ad-5eee-44db-bf82-29f5a798090e','雪中別詩友','杜荀鶴','唐','唐诗','tang','','[]','酒寒無小戶，請滿酌行杯。',48,'全唐诗/poet.tang.38000.json','["酒寒無小戶，請滿酌行杯。", "若待雪消去，自然春到來。", "出城人跡少，向暮鳥聲哀。", "未遇應關命，侯門處處開。"]'),
('2fb5cb3d-ff60-4ef0-91cb-61b829982f6a','題嶽麓寺','杜荀鶴','唐','唐诗','tang','','[]','一簇楚江山，江山勝此難。',48,'全唐诗/poet.tang.38000.json','["一簇楚江山，江山勝此難。", "覓人來畫取，到處得吟看。", "鶴隱松聲盡，魚沈檻影寒。", "自知心未了，閑話亦多端。"]'),
('d8d50a21-82b8-4566-bc01-33b5816f6a93','懷廬嶽書齋','杜荀鶴','唐','唐诗','tang','','[]','長憶在廬嶽，免低塵土顏。',48,'全唐诗/poet.tang.38000.json','["長憶在廬嶽，免低塵土顏。", "煮茶窗底水，採藥屋頭山。", "是境皆遊遍，誰人不羨閑。", "無何一名繫，引出白雲間。"]'),
('4bc402ed-a84a-40ec-a1a3-d75514b6c2ff','題唐興寺小松','杜荀鶴','唐','唐诗','tang','','[]','雖小天然別，難將衆木同。',48,'全唐诗/poet.tang.38000.json','["雖小天然別，難將衆木同。", "侵僧半窗月，向客滿襟風。", "枝拂行苔鶴，聲分叫砌蟲。", "如今未堪看，須是雪霜中。"]'),
('9f52c79e-0c51-45f5-b0cc-41c0dcccfea4','與友人話別','杜荀鶴','唐','唐诗','tang','','[]','客路行多少，干人無易顏。',48,'全唐诗/poet.tang.38000.json','["客路行多少，干人無易顏。", "未成終老計，難致此身閑。", "月兔走入海，日烏飛出山。", "流年留不得，半在別離間。"]'),
('a9e7d25f-39ca-40ba-8472-9d5e27449dd1','贈廬嶽隱者','杜荀鶴','唐','唐诗','tang','','[]','自見來如此，未嘗離洞門。',48,'全唐诗/poet.tang.38000.json','["自見來如此，未嘗離洞門。", "結茅遮雨雪，採藥給晨昏。", "古樹藤纏殺，春泉鹿過渾。", "悠悠無一事，不似屬乾坤。"]'),
('c486f4d3-20ac-4191-b9c6-7d0fc28919ae','懷紫閣隱者','杜荀鶴','唐','唐诗','tang','','[]','紫閣白雲端，雲中有地仙。',48,'全唐诗/poet.tang.38000.json','["紫閣白雲端，雲中有地仙。", "未歸蓬島上，猶隱國門前。", "洞口人無跡，花陰鹿自眠。", "焚香賦詩罷，星月冷遙天。"]'),
('6ffbe4bf-1ad9-4398-a614-0054df35be58','題會上人院','杜荀鶴','唐','唐诗','tang','','[]','鼓角城中寺，師居日得閑。',48,'全唐诗/poet.tang.38000.json','["鼓角城中寺，師居日得閑。", "必能行大道，何用在深山。", "破衲新添線，空門夜不關。", "心知與眼見，終取到無間。"]'),
('7cff0074-8a17-49d7-b673-c4cc8b03c550','送黃補闕南遷','杜荀鶴','唐','唐诗','tang','','[]','得罪非天意，分明謫去身。',48,'全唐诗/poet.tang.38000.json','["得罪非天意，分明謫去身。", "一心貪諫主，開口不防人。", "自古有遷客，何朝無直臣。", "喧然公論在，雖滯楚南春。"]'),
('f32673ca-e5cb-4fad-bbc5-d17809e15ebb','送賓貢登第後歸海東','杜荀鶴','唐','唐诗','tang','','[]','歸捷中華第，登船鬢未絲。',48,'全唐诗/poet.tang.38000.json','["歸捷中華第，登船鬢未絲。", "直應天上桂，別有海東枝。", "國界波窮處，鄉心日出時。", "西風送君去，莫慮到家遲。"]'),
('1f977aa5-e2a2-4932-bacb-92ff9dc6c802','近試投所知','杜荀鶴','唐','唐诗','tang','','[]','白髮隨梳落，吟懷說向誰。',48,'全唐诗/poet.tang.38000.json','["白髮隨梳落，吟懷說向誰。", "敢辭成事晚，自是出山遲。", "擬動如浮海，凡言似課詩。", "終身事知己，此外復何爲。"]'),
('4264bd54-fce8-4af6-8bd6-4a94e02e4864','送友人牧江州','杜荀鶴','唐','唐诗','tang','','[]','本國兵戈後，難官在此時。',48,'全唐诗/poet.tang.38000.json','["本國兵戈後，難官在此時。", "遠分天子命，深要使君知。", "但遂生靈願，當應雨露隨。", "江山勝他郡，閑賦庾樓詩。"]'),
('11e23596-baf3-429c-84e0-e3d7f7223e7a','辭座主侍郎','杜荀鶴','唐','唐诗','tang','','[]','一飯尚懷感，況攀高桂枝。',48,'全唐诗/poet.tang.38000.json','["一飯尚懷感，況攀高桂枝。", "此恩無報處，故國遠歸時。", "祗恐兵戈隔，再趨門館遲。", "茅堂拜親後，特地淚雙垂。"]'),
('44fa2020-c545-4187-b545-bb2c47954c6b','別從叔','杜荀鶴','唐','唐诗','tang','','[]','立馬不忍上，醉醒天氣寒。',48,'全唐诗/poet.tang.38000.json','["立馬不忍上，醉醒天氣寒。", "都緣在門易，直似別家難。", "世路既如此，客心須自寬。", "江村亦飢凍，爭及問長安。"]'),
('2244b0fa-b552-435c-8fcb-4b730aea1152','送人南遊','杜荀鶴','唐','唐诗','tang','','[]','凡遊南國者，未有不蹉跎。',48,'全唐诗/poet.tang.38000.json','["凡遊南國者，未有不蹉跎。", "到海路難盡，挂帆人更多。", "潮沙分象跡，花洞響蠻歌。", "縱有投文處，於君能幾何。"]'),
('6b6741c8-e5b3-431c-a5d7-528e376b0a15','經賈島墓','杜荀鶴','唐','唐诗','tang','','[]','謫宦自麻衣，銜冤至死時。',48,'全唐诗/poet.tang.38000.json','["謫宦自麻衣，銜冤至死時。", "山根三尺墓，人口數聯詩。", "仙桂終無分，皇天似有私。", "暗松風雨夜，空使老猿悲。"]'),
('682fa1bf-f06b-4959-af3d-986091b2b07e','秋夜晚泊','杜荀鶴','唐','唐诗','tang','','[]','一望一蒼然，蕭騷起暮天。',48,'全唐诗/poet.tang.38000.json','["一望一蒼然，蕭騷起暮天。", "遠山橫落日，歸鳥度平川。", "家是去秋別，月當今夕圓。", "漁翁似相伴，徹曉葦叢邊。"]'),
('c9ce9adf-8dec-4e72-a7ee-138bf1f474ab','送舍弟','杜荀鶴','唐','唐诗','tang','','[]','我受羈棲慣，客情方細知。',48,'全唐诗/poet.tang.38000.json','["我受羈棲慣，客情方細知。", "好看前路事，不比在家時。", "勉汝言須記，聞人善即師。", "旅中無廢業，時作一篇詩。"]'),
('cceb2ffd-85fe-433a-9a89-27cc5ff3e2c0','將歸山逢友人','杜荀鶴','唐','唐诗','tang','','[]','儒爲君子儒，儒道不妨孤。',48,'全唐诗/poet.tang.38000.json','["儒爲君子儒，儒道不妨孤。", "白髮多生矣，青山可住乎。", "徉狂寧是事，巧達又非夫。", "祗此平生願，他人肯信無。"]'),
('b148096a-7f8a-4e94-9628-c742f3d816b2','經九華費徵君墓','杜荀鶴','唐','唐诗','tang','','["\u4e5d\u534e\u5c71"]','凡弔先生者，多傷荆棘間。',48,'全唐诗/poet.tang.38000.json','["凡弔先生者，多傷荆棘間。", "不知三尺墓，高却九華山。", "天地有何外，子孫無亦閑。", "當時若徵起，未必得身還。"]'),
('13672c02-dba9-49b6-9260-4c0e68ced953','溪居叟','杜荀鶴','唐','唐诗','tang','','[]','溪翁居靜處，溪鳥入門飛。',48,'全唐诗/poet.tang.38000.json','["溪翁居靜處，溪鳥入門飛。", "早起釣魚去，夜深乘月歸。", "見君無事老，覺我有求非。", "不說風霜苦，三冬一草衣。"]'),
('68a8bc6b-aa3b-4790-9a88-977741bbb7b8','與友人對酒吟','杜荀鶴','唐','唐诗','tang','','[]','憑君滿酌酒，聽我醉中吟。',48,'全唐诗/poet.tang.38000.json','["憑君滿酌酒，聽我醉中吟。", "客路如天遠，侯門似海深。", "新墳侵古道，白髮戀黃金。", "共有人間事，須懷濟物心。"]'),
('41322a5c-165c-4abe-a151-6a787737d52e','送僧','杜荀鶴','唐','唐诗','tang','','[]','道了亦未了，言閑今且閑。',48,'全唐诗/poet.tang.38000.json','["道了亦未了，言閑今且閑。", "從來無住處，此去向何山。", "片石樹陰下，斜陽潭影間。", "請師留偈別，恐不到人寰。"]'),
('db9c0369-a780-4819-89e9-d9eab8627aaa','送九華道士遊茅山','杜荀鶴','唐','唐诗','tang','','[]','忽起地仙興，飄然出舊山。',48,'全唐诗/poet.tang.38000.json','["忽起地仙興，飄然出舊山。", "於身無切事，在世有餘閑。", "日月浮生外，乾坤大醉間。", "故園華表上，誰得見君還。"]'),
('39761c8a-19ce-4d99-9571-4627e5d7f3d7','寄舍弟','杜荀鶴','唐','唐诗','tang','','[]','世亂信難通，鄉心日萬重。',48,'全唐诗/poet.tang.38000.json','["世亂信難通，鄉心日萬重。", "弟兄皆嚮善，天地合相容。", "大野陰雲重，連城殺氣濃。", "家山白雲裏，臥得最高峰。"]'),
('a8b0b730-c92f-4906-8fc3-0342b571fc2e','下第投所知','杜荀鶴','唐','唐诗','tang','','[]','若以名場內，誰無一軸詩。',48,'全唐诗/poet.tang.38000.json','["若以名場內，誰無一軸詩。", "縱饒生白髮，豈敢怨明時。", "知己雖然切，春官未必私。", "寧教讀書眼，不有看花期。"]'),
('690b6c13-eb9a-4dbd-8407-bbebf4c61ea2','寄顧雲','杜荀鶴','唐','唐诗','tang','','[]','省得前年別，蘋洲旅館中。',48,'全唐诗/poet.tang.38000.json','["省得前年別，蘋洲旅館中。", "亂離身不定，彼此信難通。", "侯國兵雖斂，吾鄉業已空。", "秋來憶君夢，夜夜逐征鴻。"]'),
('7f54bd80-7158-4f7c-9508-dbc73aba5284','贈宣城麋明府','杜荀鶴','唐','唐诗','tang','','[]','天下爲官者，無君一軸詩。',48,'全唐诗/poet.tang.38000.json','["天下爲官者，無君一軸詩。", "數聯同我得，當代遇誰知。", "年齒吟將老，生涯說可悲。", "何當拋手板，鄰隱過危時。"]'),
('2fbda051-6db7-4c68-91b1-a4b76cf10d3e','望遠','杜荀鶴','唐','唐诗','tang','','[]','門前通大道，望遠上高臺。',48,'全唐诗/poet.tang.38000.json','["門前通大道，望遠上高臺。", "落日人行盡，窮邊信不來。", "還聞戰得勝，未見敕招回。", "却入機中坐，新愁織不開。"]'),
('a647c9e5-c418-432f-aadf-4afe1c0390c8','冬末投長沙裴侍郎','杜荀鶴','唐','唐诗','tang','','[]','欲露塵中事，其如不易言。',48,'全唐诗/poet.tang.38000.json','["欲露塵中事，其如不易言。", "家山一離別，草樹匝春暄。", "吹夢風天角，啼愁雪嶽猿。", "佇思心覺滿，何以遠門軒。"]'),
('767f4dc8-65b6-456a-84f5-9d25088f7b09','贈秋浦金明府長','杜荀鶴','唐','唐诗','tang','','[]','倚郭難爲宰，非君即有私。',48,'全唐诗/poet.tang.38000.json','["倚郭難爲宰，非君即有私。", "惟憑野老口，不立政聲碑。", "苦甚求名日，貧於未選時。", "溪山竟如此，利得且吟詩。"]'),
('869c5375-ce65-4175-a511-0bab1c08ad43','和高祕書早春對雪登樓見寄之什','杜荀鶴','唐','唐诗','tang','','[]','天有惜花意，恐花開染塵。',48,'全唐诗/poet.tang.38000.json','["天有惜花意，恐花開染塵。", "先教微雪下，始放滿城春。", "且醉登樓客，重期出郭人。", "因酬郢中律，霜鬢數莖新。"]'),
('da4a96af-baf1-4f4e-917c-a71ab915ce77','亂後山中作','杜荀鶴','唐','唐诗','tang','','[]','自從天下亂，日晚別庭闈。',48,'全唐诗/poet.tang.38000.json','["自從天下亂，日晚別庭闈。", "兄弟團圞樂，羈孤遠近歸。", "文章甘世薄，耕種喜山肥。", "直待中興後，方應出隱扉。"]'),
('220a1748-b3ec-477e-8c07-38afd845c091','旅寓書事','杜荀鶴','唐','唐诗','tang','','[]','日日驚身事，悽悽欲斷魂。',48,'全唐诗/poet.tang.38000.json','["日日驚身事，悽悽欲斷魂。", "時清不自立，髮白傍誰門。", "中路殘秋雨，空山一夜猿。", "公卿得見面，懷抱細難言。"]'),
('433d63b9-0886-43a3-a01a-caa0357caaf5','舟行晚泊江上寺','杜荀鶴','唐','唐诗','tang','','[]','久勞風水上，禪客喜相依。',48,'全唐诗/poet.tang.38000.json','["久勞風水上，禪客喜相依。", "挂衲雖無分，修心未覺非。", "日沈山虎出，鐘動寺禽歸。", "月上潮平後，談空漸入微。"]'),
('1d50246a-6dbd-4f01-95bc-5eab472a908f','長林山中聞賊退寄孟明府','杜荀鶴','唐','唐诗','tang','','[]','一縣今如此，殘民數不多。',48,'全唐诗/poet.tang.38000.json','["一縣今如此，殘民數不多。", "也知賢宰切，爭奈亂兵何。", "皆自干戈達，咸思雨露和。", "應憐住山者，頭白未登科。"]'),
('93c3dc05-659b-484c-943f-1a42b3e3dd1b','泗上客思','杜荀鶴','唐','唐诗','tang','','[]','痛飲復高歌，愁終不奈何。',48,'全唐诗/poet.tang.38000.json','["痛飲復高歌，愁終不奈何。", "家山隨日遠，身事逐年多。", "沒鴈雲橫楚，兼蟬柳夾河。", "此心閑未得，到處被詩磨。"]'),
('4efca65d-3235-44c4-bf81-cc97b0fc9f18','寄同人','杜荀鶴','唐','唐诗','tang','','[]','盡與貧爲患，唯余即不然。',48,'全唐诗/poet.tang.38000.json','["盡與貧爲患，唯余即不然。", "四方無靜處，百口度荒年。", "白髮生閑事，新詩出數聯。", "時情竟如此，不免却歸田。"]'),
('ed826213-f49f-4046-8b39-de8fe3ced6ae','下第出關投鄭拾遺','杜荀鶴','唐','唐诗','tang','','[]','丹霄桂有枝，未折未爲遲。',48,'全唐诗/poet.tang.38000.json','["丹霄桂有枝，未折未爲遲。", "況是孤寒士，兼行苦澀詩。", "杏園人醉日，關路獨歸時。", "更卜深知意，將來擬薦誰。"]'),
('dabdda7d-66b2-44aa-9677-91e6a3a99a6f','塞上','杜荀鶴','唐','唐诗','tang','','[]','草白河冰合，蕃戎出掠頻。',48,'全唐诗/poet.tang.38000.json','["草白河冰合，蕃戎出掠頻。", "戍樓三號火，探馬一條塵。", "戰士風霜老，將軍雨露新。", "封侯不由此，何以慰征人。"]'),
('2a298514-238c-4fcb-953d-10338e9fcdd4','別敬侍郎','杜荀鶴','唐','唐诗','tang','','[]','交道有寒暑，在人無古今。',48,'全唐诗/poet.tang.38000.json','["交道有寒暑，在人無古今。", "與君中夜話，盡我一生心。", "所向未得志，豈惟空解吟。", "何當重相見，舊隱白雲深。"]'),
('f214a50f-967c-4ef7-afd4-9e48ece722c2','送青陽李明府','杜荀鶴','唐','唐诗','tang','','["\u4e5d\u534e\u5c71"]','善政無慙色，吟歸似等閑。',48,'全唐诗/poet.tang.38000.json','["善政無慙色，吟歸似等閑。", "惟將六幅絹，寫得九華山。", "求理頭空白，離京債未還。", "仍聞猿與鶴，都在一船間。"]'),
('260130c0-fc85-47c4-b892-cb49a2b690ce','將遊湘湖有作','杜荀鶴','唐','唐诗','tang','','[]','一家相別意，不得不澘然。',48,'全唐诗/poet.tang.38000.json','["一家相別意，不得不澘然。", "遠作南方客，初登上水船。", "嶽鐘思冷夢，湘月少殘篇。", "便有歸來計，風波亦隔年。"]'),
('8d769297-a0ad-4ec0-992b-4b2a25cdb5ef','送姚庭珪','杜荀鶴','唐','唐诗','tang','','[]','脫衣將換酒，對酌話何之。',48,'全唐诗/poet.tang.38000.json','["脫衣將換酒，對酌話何之。", "雨後秋蕭索，天涯晚別離。", "人生無此恨，鬢色不成絲。", "未得重相見，看君馬上詩。"]'),
('014e1e17-1bd0-4ece-9655-abffca2eb5a4','投李大夫','杜荀鶴','唐','唐诗','tang','','[]','自小僻於詩，篇篇恨不奇。',48,'全唐诗/poet.tang.38000.json','["自小僻於詩，篇篇恨不奇。", "苦吟無暇日，華髮有多時。", "進取門難見，升沈命未知。", "秋風夜來急，還恐到京遲。"]'),
('abc2264b-c19d-44ee-938b-dc26326f6568','貽里中同志','杜荀鶴','唐','唐诗','tang','','[]','鄉里爲儒者，唯君見我心。',48,'全唐诗/poet.tang.38000.json','["鄉里爲儒者，唯君見我心。", "詩書常共讀，雨雪亦相尋。", "貧賤志氣在，子孫交契深。", "古人猶晚達，況未鬢霜侵。"]'),
('58c4dd07-c8f9-49b8-8bcc-0cd65f75c533','江上送韋彖先輩','杜荀鶴','唐','唐诗','tang','','[]','不易爲離抱，江天即見鴻。',48,'全唐诗/poet.tang.38000.json','["不易爲離抱，江天即見鴻。", "暮帆何處落，涼月與誰同。", "木葉新霜後，漁燈夜浪中。", "時難慎行止，吾道利于窮。"]'),
('f8929d09-035b-4ee0-bc25-8c26387d0ad3','維揚逢詩友張喬','杜荀鶴','唐','唐诗','tang','','[]','天下方多事，逢君得話詩。',48,'全唐诗/poet.tang.38000.json','["天下方多事，逢君得話詩。", "直應吾道在，未覺國風衰。", "生計吟消日，人情醉過時。", "雅篇三百首，留作後來師。"]'),
('b00d2479-4f54-4ae6-b47c-d2ed34bfdc8a','秋晨有感','杜荀鶴','唐','唐诗','tang','','[]','木葉落時節，旅人初夢驚。',48,'全唐诗/poet.tang.38000.json','["木葉落時節，旅人初夢驚。", "鐘才枕上盡，事已眼前生。", "吟髮不長黑，世交無久情。", "且將公道約，未忍便歸耕。"]'),
('57c5e421-f3d7-4856-928d-244a05e3737c','秋日山中寄李處士','杜荀鶴','唐','唐诗','tang','','["\u5fe7\u56fd\u5fe7\u6c11", "\u8bbd\u55bb"]','吾輩道何窮，寒山細雨中。',48,'全唐诗/poet.tang.38000.json','["吾輩道何窮，寒山細雨中。", "兒童書懶讀，果粟樹將空。", "言論關時務，篇章見國風。", "昇平猶可用，應不廢爲公。"]'),
('e63c833e-2bc6-43c9-90da-b882cd6f161d','晚泊金陵水亭','杜荀鶴','唐','唐诗','tang','','[]','江亭當廢國，秋景倍蕭騷。',48,'全唐诗/poet.tang.38000.json','["江亭當廢國，秋景倍蕭騷。", "夕照殘荒壘，寒潮漲古濠。", "就田看鶴劣，隔水見僧高。", "無限前朝事，醒吟易覺勞。"]'),
('a42c0077-db45-40da-bddc-500cb50fe908','錢塘別羅隱','杜荀鶴','唐','唐诗','tang','','[]','故國看看遠，前程計在誰。',48,'全唐诗/poet.tang.38000.json','["故國看看遠，前程計在誰。", "五更聽角後，一葉渡江時。", "吾道天寧喪，人情日可疑。", "西陵向西望，雙淚爲君垂。"]'),
('9c78a9c4-4281-454b-b668-9567730ad4d7','山中貽同志','杜荀鶴','唐','唐诗','tang','','[]','君貧我亦貧，爲善喜爲鄰。',48,'全唐诗/poet.tang.38000.json','["君貧我亦貧，爲善喜爲鄰。", "到老如今日，無心媿古人。", "閉門非傲世，守道是謀身。", "別有同山者，其如未可親。"]'),
('6731fd16-4db5-4e56-a1f0-0c4c0fdecdaa','秋日懷九華舊居','杜荀鶴','唐','唐诗','tang','','[]','吾道在五字，吾身寧陸沈。',48,'全唐诗/poet.tang.38000.json','["吾道在五字，吾身寧陸沈。", "涼生中夜雨，病起故山心。", "燭共寒酸影，蛩添苦楚吟。", "何當遂歸去，一徑入松林。"]'),
('140fb84a-43a1-4799-af8f-4ba8eb5d2991','江岸秋思','杜荀鶴','唐','唐诗','tang','','[]','驅馬傍江行，鄉愁步步生。',48,'全唐诗/poet.tang.38000.json','["驅馬傍江行，鄉愁步步生。", "舉鞭揮柳色，隨手失蟬聲。", "秋稼緣長道，寒雲約古城。", "家貧遇豐歲，無地可歸耕。"]'),
('e2c6dc49-caa5-4bd7-8ddc-a2b75ad21253','哭劉德仁','杜荀鶴','唐','唐诗','tang','','[]','賈島還如此，生前不見春。',48,'全唐诗/poet.tang.38000.json','["賈島還如此，生前不見春。", "豈能詩苦者，便是命羈人。", "家事因吟失，時情礙國親。", "多應銜恨骨，千古不爲塵。"]'),
('9417dc6f-70e0-4801-a605-e630080d0fcd','經青山弔李翰林','杜荀鶴','唐','唐诗','tang','','[]','何爲先生死，先生道日新。',48,'全唐诗/poet.tang.38000.json','["何爲先生死，先生道日新。", "青山明月夜，千古一詩人。", "天地空銷骨，聲名不傍身。", "誰移耒陽冢，來此作吟鄰。"]'),
('174566e0-5b17-455e-a222-a242e916176f','下第東歸別友人','杜荀鶴','唐','唐诗','tang','','[]','不得同君住，當春別帝鄉。',48,'全唐诗/poet.tang.38000.json','["不得同君住，當春別帝鄉。", "年華落第老，岐路出關長。", "芳草緣流水，殘花向夕陽。", "懷親暫歸去，非是釣滄浪。"]'),
('eee00d39-c4d2-4313-8700-9744834105e7','秋宿詩僧雲英房因贈','杜荀鶴','唐','唐诗','tang','','[]','賈島憐無可，都緣數句詩。',48,'全唐诗/poet.tang.38000.json','["賈島憐無可，都緣數句詩。", "君雖是後輩，我謂過當時。", "溪浪和星動，松陰帶鶴移。", "同吟到明坐，此道淡誰知。"]'),
('71690dfa-cc0e-450a-87ee-2e9857761e1d','送人宰吳縣','杜荀鶴','唐','唐诗','tang','','[]','海漲兵荒後，爲官合動情。',48,'全唐诗/poet.tang.38000.json','["海漲兵荒後，爲官合動情。", "字人無異術，至論不如清。", "草履隨船賣，綾梭隔水鳴。", "唯持古人意，千里贈君行。"]');
